-- Poems batch 243
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('5b1a431b-7229-4c8d-8975-801d075d600d','玄關一竅頌','周無所住','宋','宋诗','song-poetry','','[]','一竅纔通萬竅通，絲毫不動露真空。',32,'全唐诗/poet.song.220000.json','["一竅纔通萬竅通，絲毫不動露真空。", "箇中便是真宗祖，認著依前又不中。"]'),
('ccde4c15-5eb5-4fa7-b229-3c12a90fd011','真土頌','周無所住','宋','宋诗','song-poetry','','[]','真土從來名强立，學人不曉謾傍求。',32,'全唐诗/poet.song.220000.json','["真土從來名强立，學人不曉謾傍求。", "若知真土爲中道，何必騎牛更覓牛。"]'),
('e2a982e7-4e1e-43f4-9da0-58fa6e3bae7c','陽晶頌','周無所住','宋','宋诗','song-poetry','','[]','全清絕點號陽晶，纔有纖瑕便屬陰。',32,'全唐诗/poet.song.220000.json','["全清絕點號陽晶，纔有纖瑕便屬陰。", "多少神仙皆不說，誰人肯向此留心。"]'),
('5759d7a9-3844-464b-b3c5-e357a6318094','玄牝頌','周無所住','宋','宋诗','song-poetry','','[]','萬物芸芸，各歸其根。',20,'全唐诗/poet.song.220000.json','["萬物芸芸，各歸其根。", "識得根源，玄牝虛傳。"]'),
('2ba14f91-8034-4840-826c-beac97af378d','龍虎頌','周無所住','宋','宋诗','song-poetry','','[]','龍虎猖狂，心念炎烈。',20,'全唐诗/poet.song.220000.json','["龍虎猖狂，心念炎烈。", "慧劍纔揮，二獸俱滅。"]'),
('12f49121-5d6d-4317-a53d-b34dccea9773','鉛汞頌','周無所住','宋','宋诗','song-poetry','','[]','欲識鉛汞，情性二物。',20,'全唐诗/poet.song.220000.json','["欲識鉛汞，情性二物。", "二物和合，還丹了畢。"]'),
('3f406081-4c19-468f-8ee0-0982fd396ec4','真爐鼎頌','周無所住','宋','宋诗','song-poetry','','[]','頭上頂天，脚下踏地。',20,'全唐诗/poet.song.220000.json','["頭上頂天，脚下踏地。", "中有一物，煆成寶器。"]'),
('2ea29a8e-510f-4c1f-844b-a9e4dbe8131e','真藥物頌','周無所住','宋','宋诗','song-poetry','','[]','天地之先，無根靈草。',20,'全唐诗/poet.song.220000.json','["天地之先，無根靈草。", "一意制度，産成至寶。"]'),
('aeb9aad1-143d-4a5a-9742-649422a0ff95','斤兩頌','周無所住','宋','宋诗','song-poetry','','[]','不圓不缺行中道，著意忘懷便落偏。',32,'全唐诗/poet.song.220000.json','["不圓不缺行中道，著意忘懷便落偏。", "更言二八一斤數，開眼明明被孰瞞。"]'),
('a8a4bce7-7e87-4444-a559-a751d48f78c8','抽添頌  其一','周無所住','宋','宋诗','song-poetry','','[]','若問抽添法，縱擒怕覺遲。',24,'全唐诗/poet.song.220000.json','["若問抽添法，縱擒怕覺遲。", "調停無損益，方始證無爲。"]'),
('579aabc4-72dc-4a98-8115-a0bc0be9ebd6','抽添頌  其二','周無所住','宋','宋诗','song-poetry','','[]','識得真心無不徧，自己不明被物轉。',32,'全唐诗/poet.song.220000.json','["識得真心無不徧，自己不明被物轉。", "可憐無限守株人，退鉛進汞錯方便。"]'),
('8ba198a7-1231-4834-85ef-a33acb3a9074','火候頌','周無所住','宋','宋诗','song-poetry','','[]','真火本無候，時人休强猜。',24,'全唐诗/poet.song.220000.json','["真火本無候，時人休强猜。", "要知端的意，無去亦無來。"]'),
('0ac62210-6387-4b4a-a9fe-087d1f3ebb01','法度頌','周無所住','宋','宋诗','song-poetry','','[]','清浄藥材，密意爲丸。',20,'全唐诗/poet.song.220000.json','["清浄藥材，密意爲丸。", "十二時中，無念火煎。"]'),
('0cc36dd6-8a23-40ef-a687-c8f8c44282fc','口訣頌','周無所住','宋','宋诗','song-poetry','','[]','意到心誠，湛然若凝。',20,'全唐诗/poet.song.220000.json','["意到心誠，湛然若凝。", "晝夜無間，效驗自應。"]'),
('cebed887-a6a9-4621-9c21-c7ced030e529','沐浴頌','周無所住','宋','宋诗','song-poetry','','[]','沐浴無他術，休尋卯酉中。',24,'全唐诗/poet.song.220000.json','["沐浴無他術，休尋卯酉中。", "困眠饑喫飯，無日不春風。"]'),
('a9836fd2-2a0b-477b-b51b-d11041b3bc3d','工夫頌','周無所住','宋','宋诗','song-poetry','','[]','百刻工夫一刻推，一刻還同十二時。',32,'全唐诗/poet.song.220000.json','["百刻工夫一刻推，一刻還同十二時。", "十二時中歸一念，念中無念始真奇。"]'),
('3446c072-c63a-472c-a7e7-544b87cca3a1','溫養頌','周無所住','宋','宋诗','song-poetry','','[]','恬淡無思慮，虛無任自然。',24,'全唐诗/poet.song.220000.json','["恬淡無思慮，虛無任自然。", "胎圓神自化，我命不由天。"]'),
('29537a41-3be0-4f54-a305-1853d004d9a2','句  其一','趙希棼','宋','宋诗','song-poetry','','[]','野屋往來少，春雲晴雨多。',12,'全唐诗/poet.song.220000.json','["野屋往來少，春雲晴雨多。"]'),
('ce8da1ba-3f2d-4719-9c11-ca2a989861b7','句  其二','趙希棼','宋','宋诗','song-poetry','','[]','風雨送迎地，別離多少人。',12,'全唐诗/poet.song.220000.json','["風雨送迎地，別離多少人。"]'),
('dfbcc269-94a5-480a-96b9-937850dfa624','觀石魚','趙汝廩','宋','宋诗','song-poetry','','[]','預喜金穰驗石鱗，□能免俗且怡神。',64,'全唐诗/poet.song.220000.json','["預喜金穰驗石鱗，□能免俗且怡神。", "曉行鯨背占前夢，瑞絕龜陵知幾春。", "拂石已無題字處，觀魚皆是願豐人。", "片雲不爲催詩黑，欲雨知予志在民。"]'),
('8772db59-91e7-4cf8-ad7e-7c167f95f6da','慶江檢詳太夫人  其一','潛放','宋','宋诗','song-poetry','','[]','盛事于今蘇老泉，郡侯端的是坡仙。',32,'全唐诗/poet.song.220000.json','["盛事于今蘇老泉，郡侯端的是坡仙。", "棣華咫尺龍顔近，競詫皆出孟母賢。"]'),
('391d1be4-07bb-4c7e-9aa3-8e8b2c139e7c','慶江檢詳太夫人  其二','潛放','宋','宋诗','song-poetry','','[]','見說團欒醉壽觥，椒盤長近歲崢嶸。',32,'全唐诗/poet.song.220000.json','["見說團欒醉壽觥，椒盤長近歲崢嶸。", "今年臘裏欣逢閏，直待春回却舉行。"]'),
('de9e9a32-cad6-4319-81c8-d4e6cd8fea1e','慶江檢詳太夫人  其三','潛放','宋','宋诗','song-poetry','','[]','笑著斑襴學乳兒，民情物意總相宜。',32,'全唐诗/poet.song.220000.json','["笑著斑襴學乳兒，民情物意總相宜。", "嬉嬉同在春風裏，父樣尊嚴母樣慈。"]'),
('ca0fa4ec-cb8b-4494-8a02-d5d08d62acb2','慶江檢詳太夫人  其四','潛放','宋','宋诗','song-poetry','','[]','誰謂廬陵是富州，反成窮匱省支收。',32,'全唐诗/poet.song.220000.json','["誰謂廬陵是富州，反成窮匱省支收。", "壽筵只作家常辦，不學豪奢逞異羞。"]'),
('3322f350-5e26-4db2-b5cc-298a1f83fe87','慶江檢詳太夫人  其五','潛放','宋','宋诗','song-poetry','','[]','只把雙珠學道功，可占椿算與萱同。',32,'全唐诗/poet.song.220000.json','["只把雙珠學道功，可占椿算與萱同。", "平反陰德知多少，盡在慈祥豈弟中。"]'),
('4bcfdaad-d377-463c-92ab-407a53904f2a','慶江檢詳太夫人  其六','潛放','宋','宋诗','song-poetry','','[]','記得迎承過葛川，穉金未肅嫩涼天。',32,'全唐诗/poet.song.220000.json','["記得迎承過葛川，穉金未肅嫩涼天。", "當時若徑趨金闕，安得廬陵有此緣。"]'),
('436d818b-e7fc-4085-af80-ea58a37a97e9','慶江檢詳太夫人  其七','潛放','宋','宋诗','song-poetry','','[]','吉文江口到臨川，半是康衢半是舡。',32,'全唐诗/poet.song.220000.json','["吉文江口到臨川，半是康衢半是舡。", "泛綠依紅春正好，魚軒來往綵衣邊。"]'),
('0864f2a3-db28-4295-a92a-8b5c2deb0b32','慶江檢詳太夫人  其八','潛放','宋','宋诗','song-poetry','','[]','君王宣室正興思，尺一催歸四輩馳。',32,'全唐诗/poet.song.220000.json','["君王宣室正興思，尺一催歸四輩馳。", "壽宴明年當此日，蟠桃宣勸在瑶池。"]'),
('20ddc49e-eb8a-47c2-b9e5-606011821b41','九仙瀑布泉','柳德驥','宋','宋诗','song-poetry','','[]','白雲深處是仙鄉，石澗飛流瀑布長。',64,'全唐诗/poet.song.220000.json','["白雲深處是仙鄉，石澗飛流瀑布長。", "天插一泉聲潄玉，地高六月夜凝霜。", "烟霞極目浮孤嶼，蘿薜牽衣出上方。", "明發陰晴誰借問，虛名終愧夢黄粱。"]'),
('e7f28bae-87bf-4d8e-adf1-d040fdf7cdb2','湯嶺溫泉','柳德驥','宋','宋诗','song-poetry','','[]','化工何事起炎涼，偏使山中泉作湯。',64,'全唐诗/poet.song.220000.json','["化工何事起炎涼，偏使山中泉作湯。", "地氣爞爞燒石乳，水香鬰鬰噴硫磺。", "暄波常湧無冬夏，熱溜長澌歷雪霜。", "聞道驪山有溫谷，豈惟神女爲秦皇。"]'),
('6bf02b5c-4b4c-4f59-bd98-313078200961','端午泉','柳德驥','宋','宋诗','song-poetry','','[]','有個靈泉在翠微，我來問訊水方肥。',64,'全唐诗/poet.song.220000.json','["有個靈泉在翠微，我來問訊水方肥。", "盈虛嘿順陰陽氣，消長先知天地機。", "金井祥開波有縠，銀床冷迫石生衣。", "浮名不值一杯水，滿酌甖瓶拂袖歸。"]'),
('64208bf5-d0c8-4b6f-bf20-20a5487b77e6','登立魚山','艾丑','宋','宋诗','song-poetry','','[]','杳杳靈岩洞府深，有人巖下振潮音。',32,'全唐诗/poet.song.220000.json','["杳杳靈岩洞府深，有人巖下振潮音。", "龍天聳聽生歡喜，留得神魚立到今。"]'),
('0c160401-1420-4217-9879-f307a01b1c6f','自題像','周信庵','宋','宋诗','song-poetry','','[]','信庵年生七十二，經過庚子乙亥春。',64,'全唐诗/poet.song.220000.json','["信庵年生七十二，經過庚子乙亥春。", "自權自力承家業，榮辱無驚樂太真。", "吾歸去，別鄉親，平生朴直坦夷人。", "今朝倚杖逍遥處，風月無邊碧草新。"]'),
('4cf80ed3-8cf8-4ea2-adec-5c3abee85fe5','飲城樓','李振祖','宋','宋诗','song-poetry','','[]','山外晴雲數點鴉，寸心芳草共天涯。',32,'全唐诗/poet.song.220000.json','["山外晴雲數點鴉，寸心芳草共天涯。", "夕陽城上遊人少，十二欄干楊柳花。"]'),
('774d243c-6d7f-4e6e-92a2-232ec8bc3ebc','懷高履常','倪槐坡','宋','宋诗','song-poetry','','[]','何處存吾道，行藏一草堂。',48,'全唐诗/poet.song.220000.json','["何處存吾道，行藏一草堂。", "貴雖人所欲，貧亦士之常。", "竹靜鶴同住，山深蘭自香。", "從渠笑疏懶，此興自深長。"]'),
('f56a7805-beb0-49b5-ae74-4a394d8f8542','掃苔','倪槐坡','宋','宋诗','song-poetry','','[]','紙屏竹榻亦生涯，掩上柴扉不用推。',64,'全唐诗/poet.song.220000.json','["紙屏竹榻亦生涯，掩上柴扉不用推。", "人似春雲離復合，愁如潮水去還來。", "壺頭新釀今朝熟，籬脚寒梅昨夜開。", "嶽頂高僧□有約，想携竹箒掃蒼苔。"]'),
('28f32ac8-845b-45b0-9123-bb3c5c67f26b','臨終偈','釋行元','宋','宋诗','song-poetry','','[]','來亦無所從，去亦無所至。',24,'全唐诗/poet.song.220000.json','["來亦無所從，去亦無所至。", "來去既一如，春風滿天地。"]'),
('47cb8b8b-55c6-4c5c-a985-12402e9bac53','句  其一','釋從垣','宋','宋诗','song-poetry','','[]','泉石天象轉，花月地痕虛。',12,'全唐诗/poet.song.220000.json','["泉石天象轉，花月地痕虛。"]'),
('cd8fbfd2-5640-4d8a-84c3-2db41f89d66d','句  其二','釋從垣','宋','宋诗','song-poetry','','[]','□踏浪□知浪險，蝶翻花宅惜花空。',16,'全唐诗/poet.song.220000.json','["□踏浪□知浪險，蝶翻花宅惜花空。"]'),
('8d08c46c-804c-4fed-a522-3a43f4a9b305','句  其三','釋從垣','宋','宋诗','song-poetry','','[]','習字带秋收柿葉，學詩和月嚥梅花。',16,'全唐诗/poet.song.220000.json','["習字带秋收柿葉，學詩和月嚥梅花。"]'),
('6f32bcd8-0545-47dc-a184-efbc950ceb7b','句  其四','釋從垣','宋','宋诗','song-poetry','','[]','□盡榆錢猶案價，晚風門外落桐花。',16,'全唐诗/poet.song.220000.json','["□盡榆錢猶案價，晚風門外落桐花。"]'),
('f824238a-6375-459b-b7f4-03bdc73df16f','句  其五','釋從垣','宋','宋诗','song-poetry','','[]','吟詩已得池塘夢，學易獨明天地心。',16,'全唐诗/poet.song.220000.json','["吟詩已得池塘夢，學易獨明天地心。"]'),
('56034503-354e-4dcb-87c1-cd4128c994a8','句  其六','釋從垣','宋','宋诗','song-poetry','','[]','杜宇一聲蒼樹遠，黄鸝三囀落花深。',16,'全唐诗/poet.song.220000.json','["杜宇一聲蒼樹遠，黄鸝三囀落花深。"]'),
('451f4a1c-d9c5-4f3f-a250-169dfccc5a6c','雁蕩歸興','應節嚴','宋','宋诗','song-poetry','','[]','倚雲絕巘極躋攀，力倦何能跨鶴還。',64,'全唐诗/poet.song.220000.json','["倚雲絕巘極躋攀，力倦何能跨鶴還。", "回首乘鸞千尺上，舉頭踞虎萬尋間。", "石壇勝地留仙住，玉府浮雲伴客閒。", "秀水名山觀不盡，放吟騷客興何慳。"]'),
('4523d3db-2edf-48e4-ab61-02598671ed57','句','高達','宋','宋诗','song-poetry','','[]','至今青霄人，猶是門下客。',12,'全唐诗/poet.song.220000.json','["至今青霄人，猶是門下客。"]'),
('e05d1451-3525-4d83-a9fd-ccc593da47a2','再游浯溪','張仲','宋','宋诗','song-poetry','','[]','一年兩檄過浯溪，□上𢈪亭□□□。',32,'全唐诗/poet.song.220000.json','["一年兩檄過浯溪，□上𢈪亭□□□。", "笑□興亡千古□，□□崖石與天齊。"]'),
('49e6b5cc-b72f-4920-b08e-3226b4cf6fc6','遊虎丘','鄭覺民','宋','宋诗','song-poetry','','[]','丘壑癖所耽，從遊虎踞巖。',48,'全唐诗/poet.song.220000.json','["丘壑癖所耽，從遊虎踞巖。", "山形藏古寺，泉脈湧幽潭。", "遠望悲陳迹，清禪任閉菴。", "繇來賢達士，捷徑鄙終南。"]'),
('44eb8539-2328-44b2-b935-e5e614552c17','釣雪歌','歐陽守道','宋','宋诗','song-poetry','','[]','上天同雲兮雨雪其霏，之子于釣兮在水之湄。',40,'全唐诗/poet.song.220000.json','["上天同雲兮雨雪其霏，之子于釣兮在水之湄。", "魚潛於淵兮不可求思，泌之洋洋兮可以樂饑。"]'),
('c495c993-6302-481f-b1a8-7e87bac1d8fa','索胡學聖詩','歐陽守道','宋','宋诗','song-poetry','','[]','爲候君詩十日留，無詩何以別交遊。',64,'全唐诗/poet.song.220000.json','["爲候君詩十日留，無詩何以別交遊。", "自緣白雪難於和，莫把明珠暗處投。", "往施固慙三不報，此鳴儻許兩相酬。", "今番但挈空囊去，湘水湘山段段愁。"]'),
('db52ddb4-5f16-47a3-8e2c-1ea063eb0997','爲琛上人題','歐陽守道','宋','宋诗','song-poetry','','[]','今日有心還有累，當來無窄亦無寬。',64,'全唐诗/poet.song.220000.json','["今日有心還有累，當來無窄亦無寬。", "難將世事眉雙皺，盡付塵緣指一彈。", "煩惱不從生處有，應酬都向夢中看。", "不知向去寬多少，萬里秋空孤月寒。"]'),
('28fa74a1-ed8f-400b-9aae-17a14cc6c683','題興善院凈師月巖圖','歐陽守道','宋','宋诗','song-poetry','','[]','君不見長安市，擾擾行人如聚蟻。',231,'全唐诗/poet.song.220000.json','["君不見長安市，擾擾行人如聚蟻。", "不惟賈客與廛民，往往冠紳大夫士。", "投身閙處思山林，欲歸未歸長苦心。", "夜深燈火如白晝，嘔啞絃管喧繁音。", "孤客欲眠眠不得，四更五更人暫息。", "忽然車轂鳴枕中，百官朝早傳呼亟。", "我時起坐一喟然，推窗孤月方流天。", "嗟哉市朝不知夜，挹此清景何由緣。", "歸求重覓麋鹿伴，塵勞餘業猶羈絆。", "高僧過我出畫圖，月照巖心僧仰看。", "有巖有月儘佳哉，僧叉不俗何方來。", "此巖豈是南海觀，不然五臺峨眉鴈蕩與天台。", "巖空月圓僧靜坐，不用話頭勞勘破。", "人言腰錢騎鶴上揚州，何如巖中月下從僧遊。"]'),
('684e552e-5135-4ea1-b4e4-854056aabf22','題壁','廬陵田父','宋','宋诗','song-poetry','','[]','雲兮雲兮，變化有神靈兮。',57,'全唐诗/poet.song.220000.json','["雲兮雲兮，變化有神靈兮。", "捲起地下黄，飛去天上青兮。", "仙人乘雲天尺五，借我清陰覆赤土。", "雲間逍遥人間苦，年年苦時望君雨。"]'),
('3bda1c57-3a0b-4744-8324-cd8b05b01b20','長江問對篇','章公權','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','問長江，以汝衛南邦，北人遥想心已降。',301,'全唐诗/poet.song.220000.json','["問長江，以汝衛南邦，北人遥想心已降。", "方今大勢全倚汝，不知汝亦許不許。", "國人皆悠悠，我心良獨憂。", "長城已坦道，黄河已安流。", "淮邊日夜風颼颼，汝今孤矣非昔比。", "問汝若何真可倚。", "長江對，壯爾南邦以吾在。", "今來古往只東流，人世興亡自更改。", "句踐臨齊晉，劉裕入長安，項王北渡黄河西破關。", "北方或可取，吾不爲君阻。", "赤壁中流曾喪兵，廣陵望見波濤驚，瓜步欲渡說虛聲。", "南方長可守，吾獨爲君有。", "吾之勢何但抵長城，長城今已平。", "吾之力可以當百萬，百萬昔嘗散。", "吾能限南北，不能輸事力。", "吾能鼓風濤，不能用英豪。", "君不見吳之末，陳之季，豈必斯時吾獨異。", "朝無政事國無人，烏有長江專可倚。", "辱君有問答君知，正恐知之亦忽之。", "煩君奉此獻之國，索裘勿俟大寒時。"]'),
('31a2fdcb-ebd5-4b11-b2d8-c019613ee5f9','廣德村寺壁間次前尉王文昌韻','張汝鍇','宋','宋诗','song-poetry','','[]','世事反觀俱了了，鷃鵬何大亦何小。',32,'全唐诗/poet.song.220000.json','["世事反觀俱了了，鷃鵬何大亦何小。", "木人起舞中郎拍，問著木人應不曉。"]'),
('85e77758-d391-4114-9449-f74f65130460','題象鼻巖','張汝鍇','宋','宋诗','song-poetry','','[]','曾入蒼舒萬斛舟，至今鼻準蘸清流。',32,'全唐诗/poet.song.220000.json','["曾入蒼舒萬斛舟，至今鼻準蘸清流。", "君王玉輅催行駕，安得身閑伴白鷗。"]'),
('668d27cc-24d8-4022-92a9-244e084acf8e','招六賢之歌','王巳','宋','宋诗','song-poetry','','[]','矩矱兮姱美，風節兮凌厲。',102,'全唐诗/poet.song.220000.json','["矩矱兮姱美，風節兮凌厲。", "鶴媒兮一空，宇宙兮莫窮。", "六賢去兮不復返，魂漂摇兮渺何在。", "飛揚千里兮層冰峨峨，雄虺九首兮壺蜂繁多。", "挾飛仙兮同遊，揖清獻兮並輈。", "俯幽蘭兮延佇，褰杜衡兮實處。", "援北斗兮椒漿，聊徜徉兮此堂。"]'),
('dbe835db-9b94-43d7-82ab-895b7a606f42','遊黄山','焦炳炎','宋','宋诗','song-poetry','','[]','秀出雲霄一丈探，諸峰高下護晴嵐。',64,'全唐诗/poet.song.220000.json','["秀出雲霄一丈探，諸峰高下護晴嵐。", "丹成兔臼香生杵，影見龍津月在潭。", "洞暖有花因七七，雲深無語住三三。", "粥魚敲動山林興，合傍浮丘去結庵。"]'),
('9e8a23e9-cf3e-4501-bf31-3b1b9079cbe6','句','焦炳炎','宋','宋诗','song-poetry','','[]','跡雖無地著，心實有天知。',24,'全唐诗/poet.song.220000.json','["跡雖無地著，心實有天知。", "一禽從不獲，不敢範驅馳。"]'),
('a20502b2-e31d-4b52-8a19-5d48706d1976','題黄山送別圖','焦煥炎','宋','宋诗','song-poetry','','[]','我家黄山隅，不識黄山面。',106,'全唐诗/poet.song.220000.json','["我家黄山隅，不識黄山面。", "不自到黄山，見圖如不見。", "如何黄山客，又別黄山去。", "落日晚烟昏，黄山在何處。", "黄山有湯泉，可以洗滌塵世緣。", "黄山有瑶草，可以餌之長不老。", "黄山有神丹，得之可以超塵寰。", "胡爲別却黄山去，祇把生綃寫空翠。"]'),
('ed6c0034-01c0-4e59-b891-f12d959b9872','青陽洞天呈青陽主人曾少裕','利登','宋','宋诗','song-poetry','','[]','兩崖蒼蒼峭天柱，停策崖邊喚舟渡。',176,'全唐诗/poet.song.220000.json','["兩崖蒼蒼峭天柱，停策崖邊喚舟渡。", "青巾羽客打舟來，驚起靈蛇絕溪去。", "千年神漿不自惜，萬里晴天安得雨。", "但見飛流落半空，空中此水來何處。", "岩下猶涵太古泉，安知上不通銀浦。", "蒼藤半濕苔蘚昏，石罅無根迸孤樹。", "洞門一隙僅通人，可惜鑿空開洞府。", "乾坤明晦自有時，突然棟宇那非數。", "開闢豈無人到來，岩崖尚絕猿猱路。", "先生朝昏息丹岩，萬壑歸心心不語。", "瑶磬一聲天壁寒，白雲紫霧驚相顧。"]'),
('f418695b-d989-4575-bc13-5c62de6ca609','雜興  其一','利登','宋','宋诗','song-poetry','','[]','渺渺江河流，蛟龍所爲沼。',72,'全唐诗/poet.song.220000.json','["渺渺江河流，蛟龍所爲沼。", "高山苟無松，不如低平阜。", "潔身服休美，榮辱非所囿。", "孤航何翩翩，獨往不我覯。", "眷言友仙喬，寤寐耿長抱。", "安得翔風鸞，棲神此蓬島。"]'),
('f2e01de4-9432-47a5-ae94-f5eed6fc7b95','雜興  其二','利登','宋','宋诗','song-poetry','','[]','我昔遊蓬萊，道過崑崙山。',84,'全唐诗/poet.song.220000.json','["我昔遊蓬萊，道過崑崙山。", "青壁峭千仞，中分兩徑前。", "上逕險且難，行可求神仙。", "下逕極夷易，蛇虺交蜿蜒。", "毫釐一殊軌，安危異千年。", "棄之從上征，高步追飛鸞。", "勿謂下途易，下途前更艱。"]'),
('d6164c5c-eabd-4a5e-a9fd-3b6e63303fd7','雜興  其三','利登','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','滯凍釋陽淵，嫩和改陰囿。',180,'全唐诗/poet.song.220000.json','["滯凍釋陽淵，嫩和改陰囿。", "草色誰與媒，青青一何驟。", "美人振長袖，竚立傷年少。", "芳紅不少留，况乃飄殘照。", "飄零可柰何，四氣如環珂。", "白雲雖有反，不反亦已多。", "曲流傷直水，遠蔭無近柯。", "誰令天有漢，杳杳隔秋娥。", "桂林有秋色，洞庭有秋波。", "濯衣千仞溪，滌垢非悅眼。", "涓辰萬里遊，寧以霖雨緩。", "丈夫秉道心，摧挫志逾勉。", "豈如甘與橙，南北隨所變。", "大鵬擊逍遥，鷦粒有餘羨。", "嗜好非固殊，夫亦各所願。"]'),
('d322e6f9-3a0d-40b9-b286-92c88251f2ed','雜興  其四','利登','宋','宋诗','song-poetry','','[]','朝吾出東門，回首瞻長坂。',84,'全唐诗/poet.song.220000.json','["朝吾出東門，回首瞻長坂。", "凄然數根松，枯華困凌踐。", "時春百卉肥，綠苔亦青婉。", "如何虬鳳姿，獨爾失嶄岸。", "伐明根下摧，樵炊枝上剪。", "忍此棘荆蕃，寧此棟梁爨。", "棟梁君自遺，文木固不賤。"]'),
('fe950a24-1054-4715-9259-ac733d8ec336','雜興  其五','利登','宋','宋诗','song-poetry','','[]','西登巫陽峰，悵望高唐女。',60,'全唐诗/poet.song.220000.json','["西登巫陽峰，悵望高唐女。", "靈顧不須臾，而自虧澄素。", "竚嘆爲君懷，惜此蘭臺賦。", "不惜蘭臺賦，惜此天下雲。", "茫茫八紘中，是非誰得論。"]'),
('58dc0b79-dab9-41e0-bcef-49d719f0eeb7','雜興  其六','利登','宋','宋诗','song-poetry','','[]','松柏托茂林，高不尋丈至。',84,'全唐诗/poet.song.220000.json','["松柏托茂林，高不尋丈至。", "寸喬附太山，未長已千里。", "置身患不高，餘事安足擬。", "遊必蓬萊遊，棲必崑崙棲。", "仙遊必祥雲，仙茹必靈芝。", "鳳凰雖自饑，妄食固不回。", "癡鳶嚇腐鼠，可笑空自疑。"]'),
('e78e8c8d-b06a-485b-a39d-89dc11c44a85','雜興  其七','利登','宋','宋诗','song-poetry','','[]','我昔此園遊，寒梅吐孤艷。',36,'全唐诗/poet.song.220000.json','["我昔此園遊，寒梅吐孤艷。", "重來幾何間，叢青倏以遍。", "誰云花與葉，同樹不相見。"]'),
('107e9b3b-f815-4b20-9055-a03897471c52','雜興  其八','利登','宋','宋诗','song-poetry','','[]','昨宵狂風起，折我桑樹枝。',72,'全唐诗/poet.song.220000.json','["昨宵狂風起，折我桑樹枝。", "徘徊履桑園，賤妾當何依。", "豈無薜蘿生，亦有柔苧肥。", "素情在君子，綺帛良重斯。", "無桑蠶安食，無蠶我安衣。", "長嘆反初路，渺渺天四垂。"]'),
('a4b5ff8d-b782-4361-8a10-5df53131f2f3','北溪蒼山謀避寇念青陽蒼山徘徊不忍作古調開之','利登','宋','宋诗','song-poetry','','[]','憶我昨選勝，瓶錫來蒼山。',288,'全唐诗/poet.song.220000.json','["憶我昨選勝，瓶錫來蒼山。", "上巖豁萬里，下峽窮重玄。", "謂此已勝絕，可以無梅川。", "後同北溪遊，青陽稅塵鞍。", "險流貫地軸，危瀑垂天關。", "雲氣夜結構，如有飛來仙。", "迥然幽且深，直可無塵寰。", "乃知天壤寬，淺目非所沿。", "亦豈無勝此，天不丐我閑。", "豺虎白日行，俘掠無崖巔。", "此境亦莫保，惜此時運艱。", "二君皆駿人，銓時洞遐觀。", "考槃擇澗谷，取數良已慳。", "天尚不子與，而遣纏世患。", "十月崆峒路，霜風吹羈單。", "回首舊遊處，野狐嘷暮烟。", "天地豈不寬，我身靡所安。", "思古英達士，豈皆薄龍盤。", "求隠有不可，勳名乃窮年。", "困衡心慮閒，庸非大任緣。", "勉哉慎所從，致主或不難。", "逃死復誦此，自笑還自憐。", "念我昔時語，夢驚老雲間。", "茲事今已晚，誰能復長嘆。"]'),
('82b448a5-a747-4208-b6ad-9430477cb298','梅川莫令君拉蒼山諸詩友用予松風首句爲韻招予遊金精至而盜作不果遊走佛岩有感','利登','宋','宋诗','song-poetry','','[]','此行爲山來，至此事已非。',192,'全唐诗/poet.song.220000.json','["此行爲山來，至此事已非。", "雲火四地動，御風誰與期。", "剝床漸及膚，欲去迷所之。", "蒼黄走澗谷，勝遊翻在斯。", "石梯盤七折，頓豁萬里奇。", "擁岩千脩篁，中著寒泉飛。", "天壤有此景，惜我前不知。", "逃難乃邂逅，自愧還自悲。", "山風送萬古，開闢知誰爲。", "亦有如我徒，慷慨來登茲。", "罹難本因此，不悔仍攀窺。", "天亦無如頑，更供愛日暉。", "平生江海眼，此志良未癡。", "忽憶家山遠，寒馬鳴相依。", "母子各一方，而皆窘賊圍。", "欲歸莽無從，痛毒沾我衣。"]'),
('12946f07-9cbd-4b2e-a97c-9e860255490e','盜犯金川境扶侍母妹復走興安有懷','利登','宋','宋诗','song-poetry','','[]','歉歲古多盜，于今起豐年。',180,'全唐诗/poet.song.220000.json','["歉歲古多盜，于今起豐年。", "村村遞遷偪，旗鼓莽相聯。", "蚍蝣信有力，復此走興安。", "淋漓雨萬壑，駭浪驚前山。", "携持母妹孤，寄此一葉寒。", "猶勝去年冬，我身落梅川。", "母子各一方，而中隔妖躔。", "呼酒相勞苦，茲猶幸團欒。", "百年幾星霜，十九落憂患。", "人生亦何樂，四顧愁我顔。", "平生百事貧，所得惟林泉。", "亦復不過取，溢量常恐顛。", "天公尚不與，謂我取傷廉。", "前登馬崗雲，回首東南天。", "惻惻不得語，蕭然淚潺湲。"]'),
('af1cda76-1ea2-4cd7-9b90-be1516224ce9','予與子寔避盜同走崆峒予以其年十一月歸侍金川踰月而子實走豫章閲三載子實携婉妹歸梅川道經旴予自金川侍親歸會之酒酣作是詩以餞別壬辰十一月二十七日','利登','宋','宋诗','song-poetry','','[]','聞君歸梅水，經我鳳凰山。',96,'全唐诗/poet.song.220000.json','["聞君歸梅水，經我鳳凰山。", "走馬來相會，匆匆具杯盤。", "君行今已反，我歸夢尚寒。", "回首舊遊處，白骨猶荒烟。", "昔年崆峒別，心已死生看。", "今日寒林霜，收悲暫欣懽。", "善還已不期，惡別似不難。", "世事未可極，臨分更盤桓。"]'),
('3e09f2be-c0ef-4c89-8d19-92e9fddc13a6','田家即事','利登','宋','宋诗','song-poetry','','[]','小雨初晴歲事新，一犁江上趁初春。',32,'全唐诗/poet.song.220000.json','["小雨初晴歲事新，一犁江上趁初春。", "豆畦種罷無人守，縛得黄茅更似人。"]'),
('e36a6554-4e97-4bf6-9eeb-5161d72de0b4','癸巳十一月二十五辭家雪甚作愴然有懷','利登','宋','宋诗','song-poetry','','[]','歲暮遊子歸，余始爲行客。',84,'全唐诗/poet.song.220000.json','["歲暮遊子歸，余始爲行客。", "朔風萬里長，吹雪犯巾幘。", "臨行不言苦，不忍母心惻。", "乾坤迫短景，寒日易傾仄。", "冰池綠骨巉，凍車瓊網澀。", "一寒忍已熟，浪出還自責。", "撫劍睨前岡，雲重楚天黑。"]'),
('054dc697-43f9-4f47-a02b-13a5969167b3','董叔宏爲予道溪莊勝趣賦古調','利登','宋','宋诗','song-poetry','','[]','一澗潺潺瀉烟樹，流到溪莊平不度。',96,'全唐诗/poet.song.220000.json','["一澗潺潺瀉烟樹，流到溪莊平不度。", "竹風凄瑟夏猶寒，石氣蕭森朝自霧。", "時平古寨尚留名，世否誰人此逃數。", "乾坤一轉地有靈，日月無邊江又暮。", "幽潭聞說尚龍宮，石屋安知非洞府。", "願君半天更高樓，送此到海長溪去。"]'),
('11949579-0b21-4cda-a96d-32789a78390f','野燒','利登','宋','宋诗','song-poetry','','[]','初如螢燈一點明，須臾數點如疎星。',270,'全唐诗/poet.song.220000.json','["初如螢燈一點明，須臾數點如疎星。", "忽然聯亙勢不斷，儼如金蛇破夜驚縱橫。", "又如長虹百尺渴奔飲江罷，蜿蜒夭矯勢欲凌青冥。", "奇光異色不可以正視，倒影茅屋但覺燁弈光熒熒。", "我聞昔者王家有寶鏡，鏡橫八寸名紫珍。", "塗以金膏傅珠粉，碧光絳氣連屬日月含天庭。", "又聞西方聖者釋迦子，祇林演法導群生。", "祥光自頂湧不盡，三千世界合作一色白月明。", "今之奇光異色無乃是，不然安得有此瑞彩突兀來崢嶸。", "天公有妙手，變化誰能名。", "忽從青青現有象，還復槁滅歸無形。", "遺燼尚足澤萬物，生意行又盈乾坤。", "乃知元氣本不死，不逐火化常存存。", "君看餘澤滋萌達，豈彼死灰能神靈。", "秋風浩蕩吹萬寶，拭目千室倉箱盈。"]'),
('2753c3b8-afd5-4bc2-95de-ad508ddfbb7f','贈南豐宰趙虛齋二章  其一','利登','宋','宋诗','song-poetry','','[]','芳鮮桃李花，燁弈春風道。',36,'全唐诗/poet.song.220000.json','["芳鮮桃李花，燁弈春風道。", "春風不可名，桃李花自笑。", "人閑雙睫浄，玉立軍峰峭。"]'),
('3d66ea63-337f-43f0-b01e-060b66e3d5c7','贈南豐宰趙虛齋二章  其二','利登','宋','宋诗','song-poetry','','[]','有口寧食薇，有身寧衣褐。',36,'全唐诗/poet.song.220000.json','["有口寧食薇，有身寧衣褐。", "居然觀八荒，獨立招皓月。", "清風亦知人，蕭蕭動幽樾。"]'),
('b8ca5d96-7989-4c20-9fc9-d0f7fcec0aaf','友人自臨川來携庾臺趙先生與曾丈諸葛帳幹丈聯和康樂三谷詩句奇格老追遺韻千年間因難見巧玉疊瓊重殆非窘才者所宜逐響矣不鑒蕪庸欲藉手以竊風斲之誨輒依韻爲四章因承教二丈  其一','利登','宋','宋诗','song-poetry','','[]','謝遊半天下，晚歲來茲山。',120,'全唐诗/poet.song.220000.json','["謝遊半天下，晚歲來茲山。", "平生未識見，驚此紅玉泉。", "散珠流芳詞，策瓊想遺賢。", "上探霞生巖，下歷雲度阡。", "名存有瑶刻，事往如金烟。", "世有好奇士，剪茨闡繩筌。", "希此紅泉名，欲作疑信傳。", "勝境會即是，何必戶牖前。", "洗耳天河邊，聽之流潺湲。", "語發謗已兆，況復然不然。"]'),
('eb9d504b-ac72-4ae3-9c66-edb5217987db','友人自臨川來携庾臺趙先生與曾丈諸葛帳幹丈聯和康樂三谷詩句奇格老追遺韻千年間因難見巧玉疊瓊重殆非窘才者所宜逐響矣不鑒蕪庸欲藉手以竊風斲之誨輒依韻爲四章因承教二丈  其二','利登','宋','宋诗','song-poetry','','[]','先生學者師，文筆峭如山。',120,'全唐诗/poet.song.220000.json','["先生學者師，文筆峭如山。", "有時騁奇怪，倒引天上泉。", "達觀古有作，奇探今孰賢。", "我亦頗自好，種芝東南阡。", "笑倚巖間月，冷歌松下烟。", "陸耘秀新插，水捕排舊筌。", "聞師有紫書，願啟黄笈傳。", "三月下汝江，支離拜師前。", "歸來鳳岡上，藉蘭潄潺湲。", "服師雙麟芝，至今腹果然。"]'),
('7a1e6d98-25ef-4f2c-ab9e-ebd8acb6b85b','友人自臨川來携庾臺趙先生與曾丈諸葛帳幹丈聯和康樂三谷詩句奇格老追遺韻千年間因難見巧玉疊瓊重殆非窘才者所宜逐響矣不鑒蕪庸欲藉手以竊風斲之誨輒依韻爲四章因承教二丈  其三','利登','宋','宋诗','song-poetry','','[]','吾聞烟霞外，粵有天桂山。',120,'全唐诗/poet.song.220000.json','["吾聞烟霞外，粵有天桂山。", "其中多仙子，傲睨遊乳泉。", "三仇久已絕，七試嗟獨賢。", "願持琅玕樹，種之瓊瑶阡。", "從此仙子遊，上下陵祥烟。", "羽玄師華存，靈變師道筌。", "湧龍出寶臺，紹彼真一傳。", "肯如幽求癡，仙景愕不前。", "亦不畫肉芝，平地生潺湲。", "所求聖胎凝，視世蟬蛻然。"]'),
('667844c1-3c86-4cc0-8ca5-58292404afb5','友人自臨川來携庾臺趙先生與曾丈諸葛帳幹丈聯和康樂三谷詩句奇格老追遺韻千年間因難見巧玉疊瓊重殆非窘才者所宜逐響矣不鑒蕪庸欲藉手以竊風斲之誨輒依韻爲四章因承教二丈  其四','利登','宋','宋诗','song-poetry','','[]','家住姑山下，朝暮遊姑山。',120,'全唐诗/poet.song.220000.json','["家住姑山下，朝暮遊姑山。", "澄潭貫地脈，飛流接天泉。", "永栖無昔老，暫遊謾時賢。", "古藤蔓直木，蒼檜隨曲阡。", "猶存萬古月，尚照千年烟。", "誰其籙青華，嘿然語玄筌。", "紫鋒變窗塵，重此鑪簡傳。", "九障儻不存，五靈森在前。", "昨者携友朋，攀蘿掬潺湲。", "神交善爽徒，宇宙空茫然。"]'),
('49bf6291-6c0c-4ed3-b631-58ad96093000','沽酒','利登','宋','宋诗','song-poetry','','[]','有錢但沽酒，莫買南山田。',24,'全唐诗/poet.song.220000.json','["有錢但沽酒，莫買南山田。", "勾引催租人，驚散青松煙。"]'),
('edb999c1-b0e8-4af6-964c-422b8f5e94de','春日','利登','宋','宋诗','song-poetry','','[]','幽偏無一事，終日自長哦。',48,'全唐诗/poet.song.220000.json','["幽偏無一事，終日自長哦。", "課僕鋤荒圃，邀人補斷簑。", "爲貧沽酒少，因病著衣多。", "昨夜岡頭雨，春風生綠波。"]'),
('415430fb-ab9b-4ac7-b48e-1358b52e524b','寄黄希聲  其一','利登','宋','宋诗','song-poetry','','[]','相會不幾日，相別又經時。',48,'全唐诗/poet.song.220000.json','["相會不幾日，相別又經時。", "居然感我懷，何以寫所思。", "舉目皆我友，我心知者誰。", "知心而久離，此情悲不悲。"]'),
('22dd6859-57ac-4cfa-910d-d907775cf05d','寄黄希聲  其二','利登','宋','宋诗','song-poetry','','[]','八月寒氣高，芳蓮謝幽池。',48,'全唐诗/poet.song.220000.json','["八月寒氣高，芳蓮謝幽池。", "時運迅不留，俛仰黄華暉。", "少年不再得，而不從以嬉。", "蕭條旅館秋，滿耳寒螿啼。"]'),
('a1bcec7a-7ece-4768-b242-668ca3bcb137','晚步','利登','宋','宋诗','song-poetry','','[]','住在山塘深更深，門前落葉與階平。',64,'全唐诗/poet.song.220000.json','["住在山塘深更深，門前落葉與階平。", "高人聽鶴來相過，野老因樵熟識名。", "一水欲流山影去，斷雲時伴燒痕生。", "翛然獨步蓮峰夕，十里松風秋月明。"]'),
('5f4cd2fd-39ed-437e-92fc-4a5000f3f380','觀雪溪傍  其一','利登','宋','宋诗','song-poetry','','[]','平昔起常晚，茲晨獨不眠。',48,'全唐诗/poet.song.220000.json','["平昔起常晚，茲晨獨不眠。", "乍驚花遶院，頓覺樹連天。", "竹壓溪頭路，冰垂巖下泉。", "四時長似此，未必有人憐。"]'),
('f5406aee-852a-41ab-87ef-ae0025a75b20','觀雪溪傍  其二','利登','宋','宋诗','song-poetry','','[]','愛雪不能寐，凌晨步水濱。',48,'全唐诗/poet.song.220000.json','["愛雪不能寐，凌晨步水濱。", "斷梢驚宿鳥，倒竹礙行人。", "疊疊畬堪數，層層屋頓勻。", "梅花無處認，唯覺暗香春。"]'),
('62b035cb-8d39-4933-8911-4137082ae9c0','觀雪溪傍  其三','利登','宋','宋诗','song-poetry','','[]','山齋坐不隠，復此出衡門。',48,'全唐诗/poet.song.220000.json','["山齋坐不隠，復此出衡門。", "溜澀冰還結，風高竹自翻。", "凍流看欲濁，饑鳥啄仍喧。", "好是今風景，令人憶故園。"]'),
('33363deb-8b9a-4148-a1dd-db9826e44a49','觀雪溪傍  其四','利登','宋','宋诗','song-poetry','','[]','密雪飛零亂，開窗坐小軒。',48,'全唐诗/poet.song.220000.json','["密雪飛零亂，開窗坐小軒。", "鳥寒飛不去，鴉啄俛仍翻。", "稚子爭團塔，山翁半掩門。", "那堪長皓色，終古照乾坤。"]'),
('2ac8d4d4-c82f-4677-bcce-bac30eba7f4f','郊外','利登','宋','宋诗','song-poetry','','[]','春色到江斷，野香涵日嬌。',24,'全唐诗/poet.song.220000.json','["春色到江斷，野香涵日嬌。", "鳥穿芳樹語，人隔遠山樵。"]'),
('8b8f0f3f-2c18-4d9d-80f0-90c8984d82ea','春日','利登','宋','宋诗','song-poetry','','[]','雨過苔猶濕，風來戶半開。',24,'全唐诗/poet.song.220000.json','["雨過苔猶濕，風來戶半開。", "閑花忽落盡，啼鳥自飛來。"]'),
('a5eb43d3-f44c-4ea7-9b16-9cd265721966','仙塘茅舍  其一','利登','宋','宋诗','song-poetry','','[]','住在山深處，門前數曲灘。',48,'全唐诗/poet.song.220000.json','["住在山深處，門前數曲灘。", "近村煙勢闊，傍水樹陰寒。", "釣客嗔棋僻，高人借鶴看。", "只愁山水怪，嫌我著儒冠。"]'),
('6da06a9f-d7cf-4e6b-a617-1b076989f377','仙塘茅舍  其二','利登','宋','宋诗','song-poetry','','[]','門對平蕪闊，荒田带水聲。',48,'全唐诗/poet.song.220000.json','["門對平蕪闊，荒田带水聲。", "牧童兼鴨養，野老叱牛耕。", "山暖松花重，園春菜子生。", "杖藜斜日裏，籬外白雲橫。"]'),
('a8b94980-1b0d-44e2-a0e5-084f2d7c700b','仙塘茅舍  其三','利登','宋','宋诗','song-poetry','','[]','莫言賓客少，幽僻長莓苔。',48,'全唐诗/poet.song.220000.json','["莫言賓客少，幽僻長莓苔。", "也有樵人到，唯無詩士來。", "山風花落盡，溪雨燕飛回。", "又覺年光暮，庭陰滿綠槐。"]'),
('bb1ffbb0-62a4-4a41-8995-45b9ea9170cd','仙塘','利登','宋','宋诗','song-poetry','','[]','一椽自著此山幽，蘆葦蕭蕭繞屋頭。',64,'全唐诗/poet.song.220000.json','["一椽自著此山幽，蘆葦蕭蕭繞屋頭。", "野老屢來詢姓字，社人相約賽春秋。", "寒山此去無飛燕，白水初傳有遠鷗。", "病起偶然成獨往，冷煙斜照使人愁。"]'),
('2b149f8a-0231-46cd-9973-ea94c2a67ae7','稚子','利登','宋','宋诗','song-poetry','','[]','雙雙稚子戲柴關，摶土爲人半印錢。',32,'全唐诗/poet.song.220000.json','["雙雙稚子戲柴關，摶土爲人半印錢。", "更過十年那有此，短簑篷笠種荒田。"]'),
('6d293a67-eab4-47cd-80ef-c28d82422aab','後坑茅舍','利登','宋','宋诗','song-poetry','','[]','松風颯颯繞回谿，遥带居人竹一籬。',32,'全唐诗/poet.song.220000.json','["松風颯颯繞回谿，遥带居人竹一籬。", "想自不知雲水好，却令行客立多時。"]'),
('70d55bf9-c590-4435-aa08-9b94f70e2c01','用趙南塘贈黄希聲韻呈南塘  其一','利登','宋','宋诗','song-poetry','','[]','長天漠漠升虬龍，龍光鱗鱗涵紫空。',64,'全唐诗/poet.song.220000.json','["長天漠漠升虬龍，龍光鱗鱗涵紫空。", "黑雲忽起瀛海上，白日不照寒郊蓬。", "九野茫茫路如織，我自路絕非途窮。", "緩商同宮琴再撫，四顧欲駕班麟風。"]'),
('37c3e18b-c01a-4dd1-96a2-96620934d93b','用趙南塘贈黄希聲韻呈南塘  其二','利登','宋','宋诗','song-poetry','','[]','鳳凰一翥千里論，營營燕蝠爭朝昏。',64,'全唐诗/poet.song.220000.json','["鳳凰一翥千里論，營營燕蝠爭朝昏。", "黄河波清縱可待，失計已落千年渾。", "蹇予生居百代後，上究笙典窮珠墳。", "綠圖丹書竟杳寞，嗷嗷宋玉徒招魂。"]'),
('076af0bd-7c82-42aa-9a44-b0196d787b9f','江亭','利登','宋','宋诗','song-poetry','','[]','江亭凭望久，野色暝蒼蒼。',48,'全唐诗/poet.song.220000.json','["江亭凭望久，野色暝蒼蒼。", "古木浮寒霧，空山入夕陽。", "水流前夜月，風作早來霜。", "却笑垂綸者，因漁亦自忙。"]'),
('03b2c189-5427-4d97-bf94-dba512dc1472','走佛岩道中','利登','宋','宋诗','song-poetry','','[]','避亂走佛岩，依依絕溪水。',132,'全唐诗/poet.song.220000.json','["避亂走佛岩，依依絕溪水。", "有客六弟昆，遮予訪行事。", "一云分路亡，庶或一不死。", "一云相爲命，生死同所值。", "遠逝宿無舂，近逃寇能至。", "垂涕贈之言，此身苦難避。", "山剽無崖巔，兵驕有城市。", "共守固已非，分逃豈云是。", "風聞宜邑郛，聚落復烟燬。", "沸鼎無清鱗，四瞻誰善地。", "不辰自至斯，乾坤古無際。"]'),
('e47d07ab-d9cd-44c4-914d-eae64cedbe42','梅川行','利登','宋','宋诗','song-poetry','','[]','我來蒼山未一日，平固弄兵剽寧邑。',288,'全唐诗/poet.song.220000.json','["我來蒼山未一日，平固弄兵剽寧邑。", "此時烏合猶懼官，風鶴入耳心早寒。", "來無與角去無捕，堂堂墟邑自來去。", "墮軍長寇那可言，初時數百俄數千。", "受旗翕忽亙千里，聚落一燼如捲水。", "就中閨女尤可愁，肩緡背篋步牽牛。", "重重闕地搜伏窖，謂無白日再天曉。", "我時避盜逃佛岩，親眼見盜循山南。", "紅葛蒙頭履躔頂，縈身錦被翻紅浪。", "招賢三尺刃如霜，夾以巨盾張朱鎗。", "皇皇我寨神呵護，山上澄明山下霧。", "路迷躑躅不敢前，依依遂犯連湖去。", "六盜飛紅登其巔，環山叫呼聲連天。", "紛紛毬雪半空落，赤子甘心自投壑。", "州忘縣邑縣忘鄉，我實自弱非賊彊。", "捐金買靜恐不售，尸祝鼠輩拖朱黄。", "何人此日不爲盜，已矣獨嘆吾生忙。", "已矣獨嗟吾生忙，乾坤回首空斜陽。"]'),
('ef644aa7-af28-4b60-936a-535504277c77','秋步述所見','利登','宋','宋诗','song-poetry','','[]','趁晴收斷薪，破曉循幽浦。',60,'全唐诗/poet.song.220000.json','["趁晴收斷薪，破曉循幽浦。", "山寒樹欲風，雲重天將雨。", "兔奔初種畦，雞拾穫殘畝。", "葉深樵無蹤，水落魚可數。", "幽草不須生，千林秋已素。"]'),
('85ef0371-ab5b-4e5c-87ba-e41a27d80d73','梅花吟','利登','宋','宋诗','song-poetry','','[]','落日孤煙寒不度，梅花忽見橋西樹。',96,'全唐诗/poet.song.220000.json','["落日孤煙寒不度，梅花忽見橋西樹。", "疎影猶含澗外雲，暗香欲薄山前霧。", "寒死不作女兒面，幽絕却懷廊廟具。", "但知殿後壓年芳，誰識攙先啟春路。", "初開寧無仙子來，已落尚恐神明護。", "後來紅紫競春風，此已成功鼎鼐去。"]'),
('2e3b55c6-5e1c-433f-b304-82910a2b9f7b','早起見雪','利登','宋','宋诗','song-poetry','','[]','折竹聲高曉夢驚，寒鴉一陣噪冬青。',32,'全唐诗/poet.song.220000.json','["折竹聲高曉夢驚，寒鴉一陣噪冬青。", "起來簷外無行處，昨夜三更猶有星。"]'),
('78a7fee0-64aa-45ce-a11b-ef7bcde40c0f','次琬妹月夕思親之什','利登','宋','宋诗','song-poetry','','[]','緩作行程早作歸，倚門親語苦相思。',32,'全唐诗/poet.song.220000.json','["緩作行程早作歸，倚門親語苦相思。", "白頭親老今多病，不似當初別汝時。"]'),
('64dda2d5-89e5-484e-a3a5-6a66ed5d8dca','田父怨','利登','宋','宋诗','song-poetry','','[]','黄雲百畝割還空，垂老禾堂泣晚舂。',32,'全唐诗/poet.song.220000.json','["黄雲百畝割還空，垂老禾堂泣晚舂。", "償却公私能幾許，販山燒炭過殘冬。"]'),
('92562f3d-443b-41ed-b295-d785be29a5b5','野農謠','利登','宋','宋诗','song-poetry','','[]','去年陽春二月中，守令出郊親勸農。',214,'全唐诗/poet.song.220000.json','["去年陽春二月中，守令出郊親勸農。", "紅雲一道擁歸騎，村村鏤榜粘春風。", "行行蛇蚓字相續，野農不識何由讀。", "唯聞是年秋，粒顆民不收。", "上堂對妻子，炊多糴少饑。", "號啾下堂見官吏，稅多輸少喧征求。", "呼官視田吏視釜，官去掉頭吏不顧。", "內煎外迫兩無計，更以饑軀受笞箠。", "古來丘壠幾多人，此日孱生豈難棄。", "今年二月春，重見勸農文。", "我勤自鍾惰自釜，何用官司勸我氓。", "農亦不必勸，文亦不必述。", "但願官民通有無，莫令租吏打門叫呼疾。", "或言州家一年三百六十日，念及我農惟此日。"]'),
('6bb7664e-10b0-4a05-b51d-afc55adcc814','兩過黄伯厚皆不遇留詩別之','利登','宋','宋诗','song-poetry','','[]','兩過安禪寺，皆言尚未歸。',48,'全唐诗/poet.song.220000.json','["兩過安禪寺，皆言尚未歸。", "情知相見近，猶欲復來辭。", "灘淺舟行澀，風輕雨下微。", "白雲回首地，天闊柳絲絲。"]'),
('648b9d51-9095-4c38-b5bc-7e8eeb3661cd','冬日','利登','宋','宋诗','song-poetry','','[]','藤果累累熟，山晴自遶簷。',48,'全唐诗/poet.song.220000.json','["藤果累累熟，山晴自遶簷。", "斷薪經雨濕，野菜著霜甜。", "詩少客相笑，家貧鶴不嫌。", "誰能更惆悵，癡坐卷疎簾。"]'),
('ca909b20-6844-4f87-88bc-1b3f0f650954','玉臺體  其一','利登','宋','宋诗','song-poetry','','[]','兩彎弓月眉端照，一朶鬆雲鬢畔歸。',32,'全唐诗/poet.song.220000.json','["兩彎弓月眉端照，一朶鬆雲鬢畔歸。", "欲默不能言不可，嬌心無著凭青衣。"]'),
('7274dbe5-0765-451a-915a-1d69ee127d17','玉臺體  其二','利登','宋','宋诗','song-poetry','','[]','六曲鴛屏紫玉環，寐衣紅地繡雙鸞。',32,'全唐诗/poet.song.220000.json','["六曲鴛屏紫玉環，寐衣紅地繡雙鸞。", "相思未必君如我，一夜芙蓉翠露寒。"]'),
('a38febb8-a810-4da6-97a3-e56f1f63b53c','玉臺體  其三','利登','宋','宋诗','song-poetry','','[]','行雲一夢去無蹤，鳳尾羅衾翠謾重。',32,'全唐诗/poet.song.220000.json','["行雲一夢去無蹤，鳳尾羅衾翠謾重。", "人壽幾何禁此別，海棠花下悔相逢。"]'),
('ee551431-d660-4cde-94fc-09586e6688e5','玉臺體  其四','利登','宋','宋诗','song-poetry','','[]','朱楊冉冉四垂春，綠霧低迷慘去程。',32,'全唐诗/poet.song.220000.json','["朱楊冉冉四垂春，綠霧低迷慘去程。", "斜日半山烟半嶺，人生不合遇傾城。"]'),
('08697d5d-aca2-4cd6-a37b-c08cf3c2987d','貴谿有石相背而生俗名之背夫石余謂妻安背夫抑夫棄之耳易之曰夫棄石','利登','宋','宋诗','song-poetry','','[]','雙石巑岏倚雲瘦，背立蒼蒼兩成醜。',76,'全唐诗/poet.song.220000.json','["雙石巑岏倚雲瘦，背立蒼蒼兩成醜。", "不知底事忤夫君，千載春風不回首。", "妾身雖棄妾不冤，混沌初開已相守。", "君興蟠天雲，妾亦助君去。", "終當爲霖九地回，白日昭昭此情傃。"]'),
('18b0e3db-1fc4-43ee-a1c6-f52e05404724','臨平春日有懷','利登','宋','宋诗','song-poetry','','[]','少年賤生理，嗜書彊解事。',144,'全唐诗/poet.song.220000.json','["少年賤生理，嗜書彊解事。", "長懷希南風，趨數慚北鄙。", "乾坤雙鬢改，日月寸心死。", "誓從鹿豕遊，乃復叨一第。", "兩年三作別，雲霧生馬耳。", "臨平二月春，花事歸桃李。", "獨尋處士梅，三肅湖邊水。", "一官未得仕，畏首復畏尾。", "旁觀未知羞，自愧已無地。", "懸知簪紱禽，擾擾事萬起。", "終當綠霧中，友彼乘龜子。", "南柯不世勳，僅足雄衆蟻。"]'),
('2cf4300f-da60-4ba5-a695-7602205f1699','觀溪流','利登','宋','宋诗','song-poetry','','[]','西山連夕雨，漲此百尺渾。',48,'全唐诗/poet.song.220000.json','["西山連夕雨，漲此百尺渾。", "怒濤響半空，氣可飄崑崙。", "一朝勢力盡，枯葦有不能。", "洋洋溟渤寬，終古無虧盈。"]'),
('3d27e02b-5619-49ae-8fbc-e2638fecfb49','感興  其一','利登','宋','宋诗','song-poetry','','[]','聖域久蕪漫，功利時競趨。',72,'全唐诗/poet.song.220000.json','["聖域久蕪漫，功利時競趨。", "管晏苟有實，安必世唐虞。", "開明周孔心，頼有伊洛儒。", "古來正其心，平治信有餘。", "彼哉典午時，相師談清虛。", "未知千載人，視今又何如。"]'),
('40502050-4e6a-48ff-83d4-6cc5d473fd58','感興  其二','利登','宋','宋诗','song-poetry','','[]','寂寂卧空晝，憂懷忽無端。',84,'全唐诗/poet.song.220000.json','["寂寂卧空晝，憂懷忽無端。", "攬衣亂西澗，復此凌西山。", "春事已無多，半消霜霰間。", "狂風更甚雨，時蔽江南天。", "寒草昔衰靡，及茲秀平阡。", "日晚幽陽生，餘光草中妍。", "徘徊桃李花，瑟瑟飄寒煙。"]'),
('aa39bdad-2ef0-4ef4-b1f5-1b1ec180ec83','別遊天台雲卧往','利登','宋','宋诗','song-poetry','','[]','半月陪杖屨，此別情詎忘。',96,'全唐诗/poet.song.220000.json','["半月陪杖屨，此別情詎忘。", "平生兩知心，蹤跡長相望。", "茲遊天相之，簷雨對夜床。", "旅行得心朋，在客如家鄉。", "如何遽此去，泛彼天台航。", "知君愛奇觀，赤城有霞光。", "儻逢五百尊，問我今行藏。", "詩骨瘦未改，雙鬢塵已蒼。"]'),
('8a4b1a89-78d4-408b-b0b5-b9c491640248','至家','利登','宋','宋诗','song-poetry','','[]','明時射策難爲合，塵世求名本是浮。',64,'全唐诗/poet.song.220000.json','["明時射策難爲合，塵世求名本是浮。", "整頓書籤還夜課，增添酒甕與寒謀。", "羞逢山友長低面，悔把漁竿不到頭。", "盡日小樓凝遠望，白雲黄菊十分秋。"]'),
('67a48b73-2c56-40b3-a3f5-4da2f242e96b','永新道中','利登','宋','宋诗','song-poetry','','[]','冉冉螺川路，茲行本不期。',48,'全唐诗/poet.song.220000.json','["冉冉螺川路，茲行本不期。", "地平風到疾，山僻雪消遲。", "漸遠鄉人少，初行岐路疑。", "斷雲無意緒，直欲上梅枝。"]'),
('ebcd611e-c083-4fbf-99ce-0c8b93193a5f','月','利登','宋','宋诗','song-poetry','','[]','哀哀半規月，前日猶盈輪。',72,'全唐诗/poet.song.220000.json','["哀哀半規月，前日猶盈輪。", "冉冉幾何間，光彩倏已淪。", "至精孰如斯，猶不逃虧盈。", "天地亦無根，萬化無長存。", "矧茲寄一形，隨天運渾冥。", "若無重素規，誰信天地精。"]'),
('32943cab-a947-4553-9e8c-8fe11fbeb6ed','金川早行','利登','宋','宋诗','song-poetry','','[]','著野霜方新，照天日未出。',36,'全唐诗/poet.song.220000.json','["著野霜方新，照天日未出。", "蒼茫霧氣昏，慘淡一片白。", "吾疑九天外，與此同一色。"]'),
('63cce010-744e-4bb4-a7e8-923a04fe717f','和希聲蓮華樵人遇仙行','利登','宋','宋诗','song-poetry','','[]','蘆溪之山高插天，蓮峰更壓蘆溪山。',205,'全唐诗/poet.song.220000.json','["蘆溪之山高插天，蓮峰更壓蘆溪山。", "峰頭青壁幾千年，誰知玉闕藏神仙。", "平明採樵陳氏子，五雲深處樓臺起。", "中有七仙白玉冠，方瞳射人秋自寒。", "臺前一道白蓮泉，七始花開一成蓮。", "固知此子無仙骨，祇以{彳空}㣚入仙室。", "低頭乞命却走回，尚復褰裳取蓮實。", "歸來疑信互相傳，朴哉此子非妄言。", "安知瓊樓玉室峭千尺，即非面前崔嵬一片石。", "安知世人俗氣厚如山，翻把瓊樓玉室作石看。", "亦非仙人幻作石，世人俗眼自不識。", "安得鴻都道士白玉簪，持我此詩扣青壁。"]'),
('5ca43200-5f9e-4554-9e17-7c7a0865d4a8','仙塘即事','利登','宋','宋诗','song-poetry','','[]','山齋臨薄霧，徙倚杏花枝。',48,'全唐诗/poet.song.220000.json','["山齋臨薄霧，徙倚杏花枝。", "獵客驚熊館，行人指鸛池。", "爲貧耡藥賣，因懶上陂遲。", "林外孤煙起，遥知日午時。"]'),
('6635391a-e65d-4b01-b85f-c7f186b13b1b','衡陽贈定父詠常','利登','宋','宋诗','song-poetry','','[]','半世擇交友，深知僅數人。',48,'全唐诗/poet.song.220000.json','["半世擇交友，深知僅數人。", "情親無語忌，歲久轉心真。", "世亂身難定，話長天易晨。", "相逢元不料，一笑鴈峰春。"]'),
('5cd796d4-df8c-4553-b1e1-47126ce25b00','次蒼山晚出聞汀寇之什','利登','宋','宋诗','song-poetry','','[]','山齋無一事，步到白蘋洲。',48,'全唐诗/poet.song.220000.json','["山齋無一事，步到白蘋洲。", "灘近溪聲夜，雲寒石氣秋。", "煙塵深冉冉，天地入悠悠。", "回首東南路，干戈半白頭。"]'),
('511d560e-241f-4876-a985-17791da9c2d4','寶陀清賞夙慕展遊願不從心因成小詠','利登','宋','宋诗','song-poetry','','[]','寶陀十里路，此日想同遊。',48,'全唐诗/poet.song.220000.json','["寶陀十里路，此日想同遊。", "萬古不收雨，四時長是秋。", "樹寒煙半擁，山濕霧長流。", "獨我思歸苦，無因到上頭。"]'),
('aa5aec8c-d1c0-47fa-9be2-f35c1e53e464','臨川道上','利登','宋','宋诗','song-poetry','','[]','晚覺儒冠誤，力耕已不任。',60,'全唐诗/poet.song.220000.json','["晚覺儒冠誤，力耕已不任。", "風雲入書史，日月送煙林。", "古來一日養，人子百年心。", "清風滿天下，欲棲無寸陰。", "太息復太息，孤雲生暮岑。"]'),
('edc957f6-768d-4176-a2af-503fecbb3678','玉臺體  其一','利登','宋','宋诗','song-poetry','','[]','羸馬前山東復東，沈沈窗戶鎖愁紅。',32,'全唐诗/poet.song.220000.json','["羸馬前山東復東，沈沈窗戶鎖愁紅。", "春風一把相思骨，又落江南煙雨中。"]'),
('623d3ff1-ba10-4a6b-82ed-aae441e4635e','玉臺體  其二','利登','宋','宋诗','song-poetry','','[]','濃綠千竿湑欲流，春風疑只在池頭。',32,'全唐诗/poet.song.220000.json','["濃綠千竿湑欲流，春風疑只在池頭。", "相思一夕天相似，望斷西南四百州。"]'),
('ea7247d2-f5ae-4cdc-a689-b4f004f2f316','壽丞相  其一','吳勢卿','宋','宋诗','song-poetry','','[]','六月麟書雨作霖，生賢此際見天心。',64,'全唐诗/poet.song.220000.json','["六月麟書雨作霖，生賢此際見天心。", "江都分洒雖名世，莘野商霖始見今。", "門館無□儀表正，經綸有道本原深。", "正人命脈家常主，一念公忱朋盍簪。"]'),
('b1e5bd94-0c19-4baa-b0d8-51c257ae0fdb','壽丞相  其二','吳勢卿','宋','宋诗','song-poetry','','[]','昨丙辰年相魏公，當時克敵首歸功。',64,'全唐诗/poet.song.220000.json','["昨丙辰年相魏公，當時克敵首歸功。", "何如手補西天漏，仍更神驅塞北空。", "一隙暇時關國祚，十分重任頼忠臣。", "天生賢佐興王業，正看周詩六月中。"]'),
('2828e1f6-bc5b-4b43-804a-d841b069a26e','壽丞相  其三','吳勢卿','宋','宋诗','song-poetry','','[]','兼善工夫自古難，有誰志學合伊顔。',64,'全唐诗/poet.song.220000.json','["兼善工夫自古難，有誰志學合伊顔。", "儒先拈得四書出，名相措諸萬事閒。", "功向時危尤易見，道於世運實相關。", "魯論一半猶收效，壽國應須安似山。"]'),
('3c0750f6-e3a6-4b93-a646-8aedc2e6b9d2','壽宗室','吳勢卿','宋','宋诗','song-poetry','','[]','海珠吐月海水紅，翠竹巖近蓬萊宮。',272,'全唐诗/poet.song.220000.json','["海珠吐月海水紅，翠竹巖近蓬萊宮。", "晨遊東華天帝所，望舒前導參豐隆。", "帝曰炎圖億萬載，往哉汝諧盤石宗。", "授之虹玉金斗印，一佛出世群仙從。", "麟兮定兮已爲瑞，綵袖接武葛氏龍。", "憶昔京畿得賢輔，胥濤欲囓粒食空。", "百萬生靈袵席上，三日事業方寸中。", "至今途歌與里詠，活民生佛稱我公。", "公侯衮衮世罕有，初心本願皆陰功。", "枌榆社內木連理，華萼樓間天九重。", "邦臣未識買臣貴，天子應知劉向忠。", "未央前殿催元會，天詔傳宣一字封。", "武夷之山三十六，僕居八曲鼓子峰。", "白馬仙人向我說，高牙今駐秦甬東。", "起看梅花玉的皪，記得誕日今重逢。", "去年已獻鶴飛曲，今年作詩尤未工。", "一年一軸從今始，鄴架軸少詩無窮。"]'),
('50f15c00-1815-4851-abf6-13765658b406','壽劉監丞  其一','吳勢卿','宋','宋诗','song-poetry','','[]','昨陪駿馬驟芳塵，怪得梅花喜色新。',64,'全唐诗/poet.song.220000.json','["昨陪駿馬驟芳塵，怪得梅花喜色新。", "恰則祝堯開瑞節，居然生甫已今辰。", "冰壺緩度壺天日，翠玉交輝玉樹人。", "天下至榮公占盡，綵衣皂蓋更青春。"]'),
('63b4c0c7-bce1-4838-9fd2-05dd86e3e7f5','壽劉監丞  其二','吳勢卿','宋','宋诗','song-poetry','','[]','佩玉徐行勝急馳，悠然滋味獨深知。',64,'全唐诗/poet.song.220000.json','["佩玉徐行勝急馳，悠然滋味獨深知。", "地當韓愈分符處，人羨買臣懷綬時。", "已出六奇陪授鉞，更藏一著要觀棋。", "經綸畢竟還精密，大任非公更屬誰。"]'),
('d2eff900-18f2-4797-a956-bfb3166e25f4','壽王通判五首  其一','吳勢卿','宋','宋诗','song-poetry','','[]','銀潢漾漾月華清，寶婺輝聯處士星。',32,'全唐诗/poet.song.220000.json','["銀潢漾漾月華清，寶婺輝聯處士星。", "中有老人南極現，三台齊色照篁屏。"]'),
('4458289f-9e1a-44a9-9e6b-544a313ee260','壽王通判五首  其二','吳勢卿','宋','宋诗','song-poetry','','[]','仙都仙子錦雲裳，手授長生不死方。',32,'全唐诗/poet.song.220000.json','["仙都仙子錦雲裳，手授長生不死方。", "觀惠春風今幾度，童顔不改只劉郎。"]'),
('a12b80b8-b95c-4320-98a6-d1ad37a4e5eb','壽王通判五首  其三','吳勢卿','宋','宋诗','song-poetry','','[]','留槎閣外記前回，龜伴高齋今再來。',32,'全唐诗/poet.song.220000.json','["留槎閣外記前回，龜伴高齋今再來。", "試問劍州餘父老，棠陰勿剪又栽培。"]'),
('9eae17af-124b-418d-bce1-6a7a34968979','壽王通判五首  其四','吳勢卿','宋','宋诗','song-poetry','','[]','古稱半刺已翺翔，□壘回旋舞袖長。',32,'全唐诗/poet.song.220000.json','["古稱半刺已翺翔，□壘回旋舞袖長。", "頼有治齊清凈法，宏開壽域海沂康。"]'),
('3e2ae95c-d83b-4928-852d-178b1949736b','壽王通判五首  其五','吳勢卿','宋','宋诗','song-poetry','','[]','流霞瀲灧照炎天，雪藕調冰佐玳筵。',32,'全唐诗/poet.song.220000.json','["流霞瀲灧照炎天，雪藕調冰佐玳筵。", "屈指西風凉意近，且拚劇飲管流年。"]'),
('7647f227-5d86-4a05-a51f-21f6023eb4df','望闕致語','吳勢卿','宋','宋诗','song-poetry','','[]','鎬燕雲開紀誕辰，括山人即華封人。',64,'全唐诗/poet.song.220000.json','["鎬燕雲開紀誕辰，括山人即華封人。", "聖明天子千秋節，帖泰時年半月春。", "龍左角占農事好，殿西頭喜捷書頻。", "小臣有錄如金鑑，願獻吾君德日新。"]'),
('6373d3c6-d95f-4833-ac1a-86cbe26a673b','當筵致語','吳勢卿','宋','宋诗','song-poetry','','[]','此去京師一握天，太平官府似神仙。',64,'全唐诗/poet.song.220000.json','["此去京師一握天，太平官府似神仙。", "九重明聖無疆壽，千里封圻大有年。", "政已和平春緩緩，民無愁歎鼓淵淵。", "三呼三祝情何已，稽首君恩雨露邊。"]'),
('8411dae0-55d7-4d3a-a1c7-d8f32b8bf490','挽蔡久軒  其一','吳勢卿','宋','宋诗','song-poetry','','[]','道學相承祖子孫，諸儒誰得似淵源。',64,'全唐诗/poet.song.220000.json','["道學相承祖子孫，諸儒誰得似淵源。", "銅川而上誰家世，程氏之門止弟昆。", "後世定知尊所學，當時未盡用其言。", "四書功用彌天地，惜不推行半魯論。"]'),
('24dbeb21-eea4-494a-a4ae-6f8acb6318a3','挽蔡久軒  其二','吳勢卿','宋','宋诗','song-poetry','','[]','識見先幾炳蔡蓍，艱難國事慮阽危。',64,'全唐诗/poet.song.220000.json','["識見先幾炳蔡蓍，艱難國事慮阽危。", "龜山如用救得半，君實未亡猶可爲。", "人渺江濤已如此，公騎箕尾欲何之。", "門生老病丹心折，竚立空山有所思。"]'),
('f1cc0103-3aff-4230-8733-67101184b034','挽歐陽梅坡','吳勢卿','宋','宋诗','song-poetry','','[]','穆陵老進士，歸侍白雲鄉。',48,'全唐诗/poet.song.220000.json','["穆陵老進士，歸侍白雲鄉。", "前輩風流遠，斯文感慨長。", "平生足千載，盛德在諸郎。", "斜日城頭路，寒梅立莽蒼。"]'),
('27776b08-b3fa-438e-939f-b189a97b8d67','詠后山鎮水月奇觀閣','吳勢卿','宋','宋诗','song-poetry','','[]','厭逐京華輦路塵，歸來傑閣敞虛明。',64,'全唐诗/poet.song.220000.json','["厭逐京華輦路塵，歸來傑閣敞虛明。", "斜陽兩岸暮山紫，明月一天秋水橫。", "芳草盡頭黄犢樂，蘆花深處白鷗聲。", "是中不仗詩模寫，一片丹青可得成。"]'),
('d9d53060-e61e-4327-932f-f45a9d7977c4','呈徐知院題意一堂','吳勢卿','宋','宋诗','song-poetry','','[]','幾載辛勤有此堂，芝峰直面麗譙傍。',64,'全唐诗/poet.song.220000.json','["幾載辛勤有此堂，芝峰直面麗譙傍。", "千章山木朝烟合，百尺樓陰夜月涼。", "物我本於仁上一，居諸偏向靜中長。", "衰年燭武知何用，空有憂時兩鬢霜。"]'),
('0394b26c-f72c-49d6-865d-e90b73976ca5','風月之樓落成','吳勢卿','宋','宋诗','song-poetry','','[]','手揖雙峰俯霽虹，近窺喬木欲相雄。',64,'全唐诗/poet.song.220000.json','["手揖雙峰俯霽虹，近窺喬木欲相雄。", "一溪流水一溪月，八面疎櫺八面風。", "取用自然無盡藏，高寒如在太虛空。", "落成恰值三秋半，敢請吹開白兔宮。"]'),
('8fb7d104-cfa1-46ab-8240-6975c7219572','上鄭丞相','徐儼夫','宋','宋诗','song-poetry','','[]','新樂初濫觴，孰聞正始音。',72,'全唐诗/poet.song.220000.json','["新樂初濫觴，孰聞正始音。", "末流遂滔天，盡入侏離衿。", "一夔亦足矣，焉用喧秋吟。", "願洗笙笛耳，悉意尊球琳。", "聽者或酣卧，豈識君子心。", "鳳兮復鳳兮，來儀當於今。"]'),
('d754e31a-7297-4687-8bf3-bd1950fc9b34','賀黄見山應薦','徐儼夫','宋','宋诗','song-poetry','','[]','莫道功名負見山，老天須向定中看。',64,'全唐诗/poet.song.220000.json','["莫道功名負見山，老天須向定中看。", "但教有子能登第，遠勝先生自得官。", "秋日幾人誇鶚薦，春風容我共鵬摶。", "卜鄰自有東君約，一笑樽前萬慮寬。"]'),
('568c6435-586c-459b-8404-a232987bb075','直鉤和韻','徐儼夫','宋','宋诗','song-poetry','','[]','一曲湖邊一釣磯，桃花風定柳綿飛。',32,'全唐诗/poet.song.220000.json','["一曲湖邊一釣磯，桃花風定柳綿飛。", "漁人豈識濠梁趣，只解沙頭盡醉歸。"]'),
('354683b7-d858-4623-bf06-775f6de76150','春晚','徐儼夫','宋','宋诗','song-poetry','','[]','門掩春深過客稀，綠陰時復數紅飛。',32,'全唐诗/poet.song.220000.json','["門掩春深過客稀，綠陰時復數紅飛。", "疎簾半捲荼䕷雨，小立黄昏待燕歸。"]'),
('7fab6346-dbaf-4078-9551-2cec5c5f78b3','和阮環綠紅白梅','汪夢雷','宋','宋诗','song-poetry','','[]','白白紅紅相映開，迎春破臘要爭魁。',32,'全唐诗/poet.song.220000.json','["白白紅紅相映開，迎春破臘要爭魁。", "誰知月上紗窗後，一種橫斜度影來。"]'),
('f1f0518a-3eaf-47d5-85d3-5019fd94d5e4','偶成','汪夢雷','宋','宋诗','song-poetry','','[]','晚望荒城重感嗟，十年行客倦思家。',64,'全唐诗/poet.song.220000.json','["晚望荒城重感嗟，十年行客倦思家。", "渚田稻薄無來雁，庭樹枝寒少宿鴉。", "書爲在官長廢讀，酒因多病久停賒。", "何時日暖尋初約，同探疎梅幾著花。"]'),
('4d77b41f-8b81-4ed7-9861-2d8c42806d11','喜客泉次韻','馮去非','宋','宋诗','song-poetry','','[]','白雲在空山，丹光照崖水。',72,'全唐诗/poet.song.220000.json','["白雲在空山，丹光照崖水。", "仙人跡如埽，客至泉輒喜。", "世路多不平，箇中太清生。", "政以靜自怡，亦與凡將迎。", "風波處處息，坎離人人有。", "要使到此蹤，盡作蓬瀛友。"]'),
('aafaeb25-c5f1-4445-8c18-986ea32d450d','鳳凰臺','馮去非','宋','宋诗','song-poetry','','[]','許大乾坤裏，那無一鳳鳴。',48,'全唐诗/poet.song.220000.json','["許大乾坤裏，那無一鳳鳴。", "臺欹紅日晚，梧拂翠雲生。", "瑣瑣六朝夢，悠悠千古情。", "寒潮如有恨，時打石頭城。"]'),
('838c78ba-4f53-4f31-848b-19d67f6d04f0','題道士鄭渭濱詩卷','馮去非','宋','宋诗','song-poetry','','[]','江湖曾是飲清波，筆染霜華秋最多。',32,'全唐诗/poet.song.220000.json','["江湖曾是飲清波，筆染霜華秋最多。", "夢裏誦君新句子，覺來無奈月明何。"]'),
('6a187ea5-f4e9-4f8c-b00e-f124240afb45','江上','馮去非','宋','宋诗','song-poetry','','[]','清秋不可奈，先自懶登樓。',48,'全唐诗/poet.song.220000.json','["清秋不可奈，先自懶登樓。", "一雁叫寒水，數峰生遠愁。", "乾坤消劍氣，江海笑詩流。", "不解人間事，眠鷗儘自由。"]'),
('65997584-56fc-45c5-9883-b40409b88627','寓居','馮去非','宋','宋诗','song-poetry','','[]','身世漂流付等閑，向來感慨鬢毛斑。',64,'全唐诗/poet.song.220000.json','["身世漂流付等閑，向來感慨鬢毛斑。", "喚船載夢西興渡，借屋盛書北固山。", "開到黄花風漸銳，照殘清野月頻彎。", "江流送我東來了，何日潮頭送我還。"]'),
('b9f6f989-aa9c-49e5-943d-cdfa7c1cc434','祁門道中','馮去非','宋','宋诗','song-poetry','','[]','麥穎垂垂稻已秧，好風晴日燕飛忙。',32,'全唐诗/poet.song.220000.json','["麥穎垂垂稻已秧，好風晴日燕飛忙。", "無人得似游絲懶，相逐秋千過粉牆。"]'),
('6379e08e-dffb-4990-9ac2-d70944d3021e','所思','馮去非','宋','宋诗','song-poetry','','[]','雁自飛飛水自流，西風不寄小銀鈎。',32,'全唐诗/poet.song.220000.json','["雁自飛飛水自流，西風不寄小銀鈎。", "斜陽何處橫孤簟，十二闌干一樣愁。"]'),
('7d64657a-dc54-4938-b3cd-63a71d0727c7','懷頤山老','馮去非','宋','宋诗','song-poetry','','[]','枯吟世慮輕，求道不求名。',48,'全唐诗/poet.song.220000.json','["枯吟世慮輕，求道不求名。", "病起春風過，閑居野草生。", "遊山尋舊屐，煮茗試新鐺。", "別久空相憶，疏鐘隔水鳴。"]'),
('2c20fc69-ec6b-4746-8da2-ef169da65476','張季海園梅','馮去非','宋','宋诗','song-poetry','','[]','到眼春流急，當橋梅影斜。',48,'全唐诗/poet.song.220000.json','["到眼春流急，當橋梅影斜。", "怕聞連夜雨，爲愛隔年花。", "寺古名多誤，鄰新酒少賒。", "如何雙屐齒，太半白鷗沙。"]'),
('6178f9a9-b23a-450c-b02d-20607b041254','山家','馮去非','宋','宋诗','song-poetry','','[]','別崦人家笑語微，好風渾在綠楊枝。',32,'全唐诗/poet.song.220000.json','["別崦人家笑語微，好風渾在綠楊枝。", "清明定是花開遠，太半蜜蜂經宿歸。"]'),
('66777bf5-c63a-4101-b538-e97483b697ea','鶴山居靖','馮去非','宋','宋诗','song-poetry','','[]','耿耿虛堂一榻秋，人間高枕幾王侯。',64,'全唐诗/poet.song.220000.json','["耿耿虛堂一榻秋，人間高枕幾王侯。", "亂雲未放曉山出，片月不隨溪水流。", "檢校一身唯有懶，平章千古得無愁。", "湘波見說清人骨，恨不移家阿那州。"]'),
('be3c3cef-a2e2-4410-a819-492f62e9f65c','偶成','馮去非','宋','宋诗','song-poetry','','[]','春風吹送笑談香，玉漏銀燈破夜涼。',32,'全唐诗/poet.song.220000.json','["春風吹送笑談香，玉漏銀燈破夜涼。", "歸去東華聽宮漏，杏花落盡六更長。"]'),
('66fbfe50-e54f-438f-8b61-7c5607b9564f','句  其一','馮去非','宋','宋诗','song-poetry','','[]','茶疏緣睡少。',6,'全唐诗/poet.song.220000.json','["茶疏緣睡少。"]'),
('4f02ede8-90a8-4c22-958f-ff4bb6f8ee14','句  其二','馮去非','宋','宋诗','song-poetry','','[]','却是後生王介甫，不曾携妓涴東山。',16,'全唐诗/poet.song.220000.json','["却是後生王介甫，不曾携妓涴東山。"]'),
('df34b3f9-8ae6-4346-bb25-04a90c62b1ad','石軒席上分韻得石字','胡仲弓','宋','宋诗','song-poetry','','[]','解衣坐虛窗，夜闌萬籟寂。',132,'全唐诗/poet.song.220000.json','["解衣坐虛窗，夜闌萬籟寂。", "月出東南隅，照我樓半壁。", "對影欲起舞，袖短不成拍。", "浩歌慰心賞，歡聲動金石。", "拊欄發長嘯，清風生兩腋。", "吟聲鬼神悲，醉眼江湖窄。", "吾自樂吾生，光陰似過客。", "物我打一塊，天地失形跡。", "山鶴從何來，點破春空碧。", "我欲從之遊，八荒隨所適。", "戛然鳴一聲，雲深何處覓。"]'),
('c05b1237-d5ec-435d-b55f-009a0ca2d289','余用十字爲座右銘因足成一首','胡仲弓','宋','宋诗','song-poetry','','[]','不貪以爲寶，持戒如護珠。',48,'全唐诗/poet.song.220000.json','["不貪以爲寶，持戒如護珠。", "暮夜金可納，鬼神不可誣。", "男兒重氣義，何物分錙銖。", "渴飲盜泉人，靡靡真凡夫。"]'),
('c1f1ad74-5412-4e08-957a-030944f3d0de','咏冰','胡仲弓','宋','宋诗','song-poetry','','[]','羣陰正膠轕，結作千丈冰。',84,'全唐诗/poet.song.220000.json','["羣陰正膠轕，結作千丈冰。", "江河凍欲枯，雪意猶憑陵。", "舟楫不可濟，水波那能興。", "世路多風寒，履此何兢兢。", "本是汙濁流，一合乃許凝。", "陽氣動地回，陰無間可乘。", "一旦自消融，紅日東方升。"]'),
('7ff03f34-4266-4804-a01e-f522174ca499','送沈鍊師歸武夷  其一','胡仲弓','宋','宋诗','song-poetry','','[]','僊骨久已蛻，尚遺空石函。',48,'全唐诗/poet.song.220000.json','["僊骨久已蛻，尚遺空石函。", "白雲最深處，猿鶴情相諳。", "松花饑可飧，渴飲寒泉甘。", "招邀武夷君，清風資玄談。"]'),
('cafea7d2-e0ae-496c-a266-7de8831968b1','送沈鍊師歸武夷  其二','胡仲弓','宋','宋诗','song-poetry','','[]','焚香禮象緯，步虛聲摩空。',48,'全唐诗/poet.song.220000.json','["焚香禮象緯，步虛聲摩空。", "升真古洞天，依稀五明宮。", "寶珠如黍米，懸懸太虛中。", "鍊師於此時，金丹滿爐紅。"]'),
('41ddbc65-2d07-4f45-a04d-e2a9965d39b9','念昔遊四首  其一','胡仲弓','宋','宋诗','song-poetry','','[]','昔年遊徑山，身在九天上。',144,'全唐诗/poet.song.220000.json','["昔年遊徑山，身在九天上。", "倚欄少徘徊，八極歸一望。", "秋容澹如洗，景物呈萬狀。", "松風奏琴筑，烟嶼列屏障。", "清遠嘯枯藤，野鶴唳幽曠。", "僧僮課梵唄，婉娩如學唱。", "解带臨西風，灑落無盡藏。", "緇流亦可人，邀往坐清曠。", "盤飧飣黄獨，侑之茅柴釀。", "感師有古意，愧我無酒量。", "長嘯下山來，一路時膽壯。", "重作記遊篇，付之覆瓿醤。"]'),
('3fdd4cd8-23ed-447f-9a6d-378136bfe681','念昔遊四首  其二','胡仲弓','宋','宋诗','song-poetry','','[]','昔遊金山寺，一葦破滄溟。',180,'全唐诗/poet.song.220000.json','["昔遊金山寺，一葦破滄溟。", "怒濤正拍天，風雨歘晦冥。", "江豚急吹浪，水面轟雷霆。", "滿船失顔色，莫辨死與生。", "此時婁師德，高卧看長鯨。", "過午忽開霽，濟岸猶登瀛。", "清風泛我衣，陽光射簷楹。", "舟人相慰勞，山僧笑出迎。", "行行金鼇背，月鑑浮空明。", "波平濛天影，潮靜聞經聲。", "殿閣耀金碧，守護真龍形。", "繫纜少沉吟，紅輪江西傾。", "炬火爍江面，直使潜鱗驚。", "因成一宿覺，問津維揚城。", "重來知幾時，未計歲月成。"]'),
('ae4c6400-d7eb-4f66-ba99-fd082132f015','念昔遊四首  其三','胡仲弓','宋','宋诗','song-poetry','','[]','昔遊虎邱山，滿天飽風雪。',108,'全唐诗/poet.song.220000.json','["昔遊虎邱山，滿天飽風雪。", "氈帽騎款段，瘦嶺衰草歇。", "下馬獨支筇，十步八九蹶。", "石路古木僵，鐵花露土骨。", "生公何在許，空堂掛明月。", "衲僧九十餘，持戒常精潔。", "講經石點頭，奇哉廣長舌。", "我來欲參請，云無法可說。", "有井無轆轤，歸去心如渴。"]'),
('a475586b-e1e2-4d0b-bc2e-e464c1cddd90','念昔遊四首  其四','胡仲弓','宋','宋诗','song-poetry','','[]','昔遊半山寺，木落山欲童。',144,'全唐诗/poet.song.220000.json','["昔遊半山寺，木落山欲童。", "秋高嵐氣旺，曉日出曈矓。", "杖藜破莽蒼，舉步生清風。", "登堂發一笑，絕倒臨川公。", "舊像人所祠，新法人所攻。", "空使百年後，直筆誅姦雄。", "不知老瞿曇，衲被和頭蒙。", "是非不到耳，靜坐薝蔔叢。", "自吹無空笛，聖處時一中。", "我亦有髮僧，誤踏京塵紅。", "來此欲安禪，懶性學虛空。", "入門被師喝，歸去成匆匆。"]'),
('b4f059e0-6ddc-4a09-ab05-42bb9dd2ebec','夜夢蒙仲書監作二象笏與余各分其一覺而有賦','胡仲弓','宋','宋诗','song-poetry','','[]','古人創一物，在理不在飾。',204,'全唐诗/poet.song.220000.json','["古人創一物，在理不在飾。", "持此非備忘，潔白貴彰德。", "世無骨鯁臣，朝夕侍君側。", "善惡欠書諫，唾駡誰擊賊。", "吏進思效忠，官執欲稱職。", "姦回濁天縡，孰任排格力。", "願爲顧少連，勿學元友直。", "上意方簡在，竹符畀泥軾。", "政成秉介圭，入覲朝北極。", "簪筆裹紫囊，玉立凜正色。", "顧余初筮令，寒餓日驅迫。", "手板非倒持，倚席懼引慝。", "分我意何厚，榻前便指畫。", "一夢雖難憑，品秩從此得。", "毋但嘯西爽，清談更何益。", "課最璽書來，洗眼看黄敕。", "汲引會有期，并力扶社稷。"]'),
('d108c53f-8037-4d4e-ac80-4a8d0f543b47','夢黄吉甫','胡仲弓','宋','宋诗','song-poetry','','[]','夢傳失之妄，晝冀見而想。',84,'全唐诗/poet.song.220000.json','["夢傳失之妄，晝冀見而想。", "豈伊不可懷，而使我心往。", "山林老顛眴，數日占黄壤。", "舟輿來何遲，北望屢戃怳。", "西城薺花時，落魄隨兩槳。", "歲晚舟渚靜，水消烟渺莽。", "躊躕壁上字，期我無乃迋。"]'),
('ec7c5c40-30fa-4687-8e8d-d59f4c3a00c9','山中夜聞虎嘯','胡仲弓','宋','宋诗','song-poetry','','[]','日落山色黄，樵夫不敢下。',72,'全唐诗/poet.song.220000.json','["日落山色黄，樵夫不敢下。", "風號萬壑哀，鳥雀亦驚怕。", "人謂斑將軍，此地正爭霸。", "數聲地欲裂，咆哮直深夜。", "道人鐵石心，慣聽何足訝。", "若逢萬戶侯，羽鏃不汝赦。"]'),
('66305ee9-7962-4642-81c5-9d297a24ec6a','僧過澗圖','胡仲弓','宋','宋诗','song-poetry','','[]','溪急水摇石，野僧躡石度。',96,'全唐诗/poet.song.220000.json','["溪急水摇石，野僧躡石度。", "寒流漾笠影，歷險無窘步。", "僕夫後嶺來，木末跡樵路。", "蒼茫盼精藍，慘澹沒烟霧。", "憶昔山中行，顧瞻歌陟岵。", "今猶夢見之，覺乃忘其故。", "畫師從何知，展玩失毫素。", "悵然渺予懷，江鄉碧雲暮。"]'),
('a00f402c-badc-4cbb-8088-5b82a38cb53e','山中聞猿','胡仲弓','宋','宋诗','song-poetry','','[]','山人猶未去，空使山猿驚。',60,'全唐诗/poet.song.220000.json','["山人猶未去，空使山猿驚。", "迎風坐枯藤，吟作長短聲。", "山猿汝何知，亦有故舊情。", "人兮不如猿，冷暖隨時生。", "不見求友鶑，喬木長嚶嚶。"]'),
('e6e702b0-0bdb-4b0f-a777-78cecbc6eab5','感古十首  其一','胡仲弓','宋','宋诗','song-poetry','','[]','卞氏璧難售，淵明琴本瘖。',60,'全唐诗/poet.song.220000.json','["卞氏璧難售，淵明琴本瘖。", "自衒亦可醜，三獻機轉深。", "無絃避俚耳，舉世誰知音。", "所以古達士，萬事何容心。", "勿學卞氏璧，請事淵明琴。"]'),
('2bc317fb-b0ab-4409-aeb9-48e061e268d4','感古十首  其二','胡仲弓','宋','宋诗','song-poetry','','[]','管蔡厄周公，陳蔡厄夫子。',60,'全唐诗/poet.song.220000.json','["管蔡厄周公，陳蔡厄夫子。", "聖人於此時，所俟惟一死。", "絃歌乃自知，赤舄亦几几。", "未明周孔心，道統安所恃。", "天苟喪斯文，墜地扶不起。"]'),
('b33cd71d-f575-4732-85f5-51bd53967dfb','感古十首  其三','胡仲弓','宋','宋诗','song-poetry','','[]','豫讓口吞炭，智伯頭已漆。',60,'全唐诗/poet.song.220000.json','["豫讓口吞炭，智伯頭已漆。", "報仇須及晨，安用詐行乞。", "飲器骨已枯，癩啞特小術。", "壯士死於義，千古猶一日。", "棄主事讎人，萬死奚足卹。"]'),
('3f65dd29-ffa9-4304-9940-a312f34f31de','感古十首  其四','胡仲弓','宋','宋诗','song-poetry','','[]','相如歸全璧，范增撞玉斗。',60,'全唐诗/poet.song.220000.json','["相如歸全璧，范增撞玉斗。", "爲主心固同，逆順異所守。", "發怒俱忘身，裂眥欲碎首。", "此完彼玷缺，盡在一舉手。", "萬形各有敝，斯名長不朽。"]'),
('b01a2de7-9f81-4241-9043-119ee88ffa00','感古十首  其五','胡仲弓','宋','宋诗','song-poetry','','[]','共工觸不周，荆卿悲易水。',60,'全唐诗/poet.song.220000.json','["共工觸不周，荆卿悲易水。", "所遭雖異時，等爲血氣使。", "爭帝力已窮，報怨反害己。", "一爲狂夫愚，一爲刺客靡。", "二者俱無成，三歎而已矣。"]'),
('f938b5f6-b4e7-4235-8e9f-0b43f7149d06','感古十首  其六','胡仲弓','宋','宋诗','song-poetry','','[]','商君金徙木，趙高鹿爲馬。',60,'全唐诗/poet.song.220000.json','["商君金徙木，趙高鹿爲馬。", "徒欲取民信，疑心隨解瓦。", "罔民適自欺，何以刑天下。", "四維已滅亡，命脈存已寡。", "焚書火咸陽，斯言信非假。"]'),
('98106237-fea3-4517-b74d-5824dccb889f','感古十首  其七','胡仲弓','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','四皓隠商山，子陵隠嚴瀨。',60,'全唐诗/poet.song.220000.json','["四皓隠商山，子陵隠嚴瀨。", "隠身非隠名，清致一何在。", "羽翼若爲成，狂奴滋故態。", "一出竟奚爲，名被世人賣。", "所以終南山，捷徑不可再。"]'),
('7f5aa3ec-6555-4fca-9f81-37c30281e572','感古十首  其八','胡仲弓','宋','宋诗','song-poetry','','[]','范蠡泛五湖，子房從赤松。',60,'全唐诗/poet.song.220000.json','["范蠡泛五湖，子房從赤松。", "功成乞身退，明哲保令終。", "彼美二丈夫，世異轍則同。", "此道久不作，利欲塵相蒙。", "急流不知返，失脚機穽中。"]'),
('a0815f0c-c27f-4649-96ab-d16ed8c57191','感古十首  其九','胡仲弓','宋','宋诗','song-poetry','','[]','惠連夢春草，江淹夢彩筆。',60,'全唐诗/poet.song.220000.json','["惠連夢春草，江淹夢彩筆。", "一夢何足憑，材名繇此出。", "讀書三十年，僅可變形質。", "所向如面牆，此語難致詰。", "何事殷武丁，因夢得良弼。"]'),
('536d761c-5fd6-40e0-96a0-56169bb85ee8','感古十首  其一○','胡仲弓','宋','宋诗','song-poetry','','[]','杜康精酒法，陸羽修茶經。',60,'全唐诗/poet.song.220000.json','["杜康精酒法，陸羽修茶經。", "標致雖不同，均是勞吾形。", "采薇及茹芝，亦掇天地英。", "玄酒非麴糵，或可通神明。", "天不生杜陸，人間無醉醒。"]'),
('8d359ac6-57e8-4561-9991-c13804869877','山中值雨偶成','胡仲弓','宋','宋诗','song-poetry','','[]','山中雲氣多，忽合即爲雨。',96,'全唐诗/poet.song.220000.json','["山中雲氣多，忽合即爲雨。", "垤鸛鳴一聲，毒龍戲吞吐。", "翻手覆手間，紛紛不可數。", "彼蒼難致詰，陰晴竟誰主。", "此雨只在山，何以澤下土。", "阿香推不來，借我霹靂斧。", "斫破太虛空，銀河漏莫補。", "風雲只片時，一施天下溥。"]'),
('565c678e-75a5-4803-93d7-1385c2a810cb','采采歌','胡仲弓','宋','宋诗','song-poetry','','[]','朝采畹中蘭，暮采籬下菊。',96,'全唐诗/poet.song.220000.json','["朝采畹中蘭，暮采籬下菊。", "采采復采采，終日不盈掬。", "爲憐芳潔姿，忍受紅塵觸。", "采蘭殺風味，采菊盈芬馥。", "落英固可飧，何如飽藜藿。", "秋香亦可紉，何如鳴佩玉。", "俾爾全其天，得志在巖谷。", "所以山中人，終身抱幽獨。"]'),
('2558fd29-c93f-4ec0-82b8-806045803d37','次陳芸居問訊後村韻  其一','胡仲弓','宋','宋诗','song-poetry','','[]','人心真灧澦，世路多殽函。',48,'全唐诗/poet.song.220000.json','["人心真灧澦，世路多殽函。", "此險久已涉，此味久已諳。", "易節固不可，貧賤分所甘。", "浩歌一長慨，書與識者談。"]'),
('0077d0e9-f159-4a48-b9a2-c3ffeb9ae593','次陳芸居問訊後村韻  其二','胡仲弓','宋','宋诗','song-poetry','','[]','清夜萬感集，風蕩雲物空。',48,'全唐诗/poet.song.220000.json','["清夜萬感集，風蕩雲物空。", "倚樓看星斗，照破泥丸宮。", "靜觀人世人，顛倒醉夢中。", "佳趣有誰識，睡覺窗前紅。"]'),
('843a6779-1d8e-4c9a-9c8d-871e06bbb3e6','後村來書有此心如珠有物蒙之之語芸居有詩再用前韻  其一','胡仲弓','宋','宋诗','song-poetry','','[]','襟抱天樣寬，萬象并包函。',48,'全唐诗/poet.song.220000.json','["襟抱天樣寬，萬象并包函。", "富貴一蟲臂，此理君飽諳。", "直語苦如荼，回味留餘甘。", "吟詩秉史筆，未數司馬談。"]'),
('493491a1-e18c-47c8-8344-2aa401f57987','後村來書有此心如珠有物蒙之之語芸居有詩再用前韻  其二','胡仲弓','宋','宋诗','song-poetry','','[]','男兒重意氣，咄咄寧書空。',48,'全唐诗/poet.song.220000.json','["男兒重意氣，咄咄寧書空。", "笑人愧鄧禹，抵掌隨臧宮。", "信是心如珠，有物蒙其中。", "非珠亦非物，點雪付爐紅。"]'),
('f50fb479-b411-4ed2-bfd6-97cb1a407797','晴溪','胡仲弓','宋','宋诗','song-poetry','','[]','晴溪湛如酒，越兒中拍浮。',48,'全唐诗/poet.song.220000.json','["晴溪湛如酒，越兒中拍浮。", "羨之不可學，徙倚溪上樓。", "直下數遊鱼，咳唾魚驚愁。", "偷生幾漏網，爲龍知何秋。"]'),
('fca9b6ff-e8cc-4016-bab1-e984d0b8bb99','明朝是歲除','胡仲弓','宋','宋诗','song-poetry','','[]','明朝是歲除，萍梗身如寄。',48,'全唐诗/poet.song.220000.json','["明朝是歲除，萍梗身如寄。", "年光馬行疾，時事令人醉。", "直語顯官嗔，上書明主棄。", "但作送窮文，慎勿言災異。"]'),
('0181d5c4-31e5-425a-9ddb-3c124a54c0c0','四時月  其一','胡仲弓','宋','宋诗','song-poetry','','[]','春月如處女，皎皎暮雲間。',48,'全唐诗/poet.song.220000.json','["春月如處女，皎皎暮雲間。", "嬋娟不自衒，欲見乃許難。", "春雲多變態，玉貌長端端。", "封姨掃塵匣，略與幽人看。"]'),
('9836d05f-5acc-4012-a2d2-db78104c9488','四時月  其二','胡仲弓','宋','宋诗','song-poetry','','[]','夏月如循吏，見者皆懽顔。',48,'全唐诗/poet.song.220000.json','["夏月如循吏，見者皆懽顔。", "當此烈日餘，和氣一夜還。", "龔黄久不作，元在青雲間。", "欲往從之遊，天高恐難攀。"]'),
('283a7051-0de7-4c55-8db8-d4c6d7f9a9e9','四時月  其三','胡仲弓','宋','宋诗','song-poetry','','[]','秋月如翰林，標致清如許。',48,'全唐诗/poet.song.220000.json','["秋月如翰林，標致清如許。", "天上白玉堂，子獨於中處。", "夜直五雲邊，冰壺了無滓。", "幾度醉歸來，安用金蓮炬。"]'),
('f7fa3698-c1c8-4da0-b980-d8e3efe82656','四時月  其四','胡仲弓','宋','宋诗','song-poetry','','[]','冬月如御史，正色凝雲端。',48,'全唐诗/poet.song.220000.json','["冬月如御史，正色凝雲端。", "風霜何凜凜，一見應膽寒。", "烏飛繞三匝，禁樹相團欒。", "心術晦昧人，不敢擡頭看。"]'),
('461423c9-727e-4532-a5a1-9d584022c55f','老母適至時已見黜','胡仲弓','宋','宋诗','song-poetry','','[]','千里迎阿㜷，相見翻不樂。',108,'全唐诗/poet.song.220000.json','["千里迎阿㜷，相見翻不樂。", "微祿期奉親，親至祿已奪。", "所悲乏故交，何以寓漂泊。", "向來耿介心，饋遺拒不諾。", "及茲誰賑恤，俛首念囊橐。", "空餘聲譽在，未足救饑渴。", "傳言仁義飽，理豈填溝壑。", "况因直道黜，自省何愧怍。", "阿㜷幸無憂，兒有平生學。"]'),
('79bdfdbc-3393-4bf4-b7e8-14d0b534a856','歲饑郡行賑卹過餘杭呈辛縣尹','胡仲弓','宋','宋诗','song-poetry','','[]','山城百貨集，富庶如豐年。',84,'全唐诗/poet.song.220000.json','["山城百貨集，富庶如豐年。", "市有醉人卧，野無餓莩眠。", "天目發深秀，餘不流清妍。", "山花墮酒琖，水鳥上漁船。", "祿薄吏如隠，心閒令欲仙。", "人言風土美，我羨長官賢。", "何須論赤望，此地稱華顛。"]'),
('70d835a1-01e4-45dc-a9de-c339020e1184','送懷玉之越謁秋房使君','胡仲弓','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','紛紛人海中，有客面如鐵。',168,'全唐诗/poet.song.220000.json','["紛紛人海中，有客面如鐵。", "前日方遊吳，今日又走越。", "一身天地間，行役勞歲月。", "問子去何爲，豈是事干謁。", "往訪蓬萊翁，欲換詩仙骨。", "此行遇故知，茂林有清樾。", "元龍百尺樓，千鈞引一髮。", "妙年負壯志，三軍不可奪。", "不見韓致光，虎鬚手曾捋。", "不見燭之武，雖老更奇崛。", "一杯壯行色，肯作兒女別。", "朔風正凝寒，柳已不堪折。", "贈子一枝梅，掉我三寸舌。", "臨風語未終，長江櫓聲發。"]'),
('1fab1aa4-7c1c-44fb-b363-489c6856f7d6','送方及民罷官東歸','胡仲弓','宋','宋诗','song-poetry','','[]','咄咄復咄咄，北地多霜雪。',96,'全唐诗/poet.song.220000.json','["咄咄復咄咄，北地多霜雪。", "誰能路坦夷，驥足亦遭跌。", "天風本不惡，鳳翅乃爾折。", "材大用則小，人巧己則拙。", "問訊既不通，去就當早决。", "雖阨阮籍途，難斷張儀舌。", "木天宜晚開，紫薇遲後發。", "會有溧水公，薦書來不絕。"]'),
('0e1e2504-3894-4846-8154-f811e96706a5','邀月坐中庭','胡仲弓','宋','宋诗','song-poetry','','[]','邀月坐中庭，清影不可駐。',48,'全唐诗/poet.song.220000.json','["邀月坐中庭，清影不可駐。", "舉酒澆枯腸，落筆欠長句。", "瀣氣惟沾衣，秋聲遠鳴樹。", "磕睡依危欄，夢斷足幽趣。"]'),
('3512c939-5ecb-4b97-9b9c-47538bc428fb','山行八韻','胡仲弓','宋','宋诗','song-poetry','','[]','山行有奇觀，勝處每自省。',96,'全唐诗/poet.song.220000.json','["山行有奇觀，勝處每自省。", "振策響巖石，探入烟霞境。", "洗耳聽泉聲，緩步踏松影。", "幽鳥吟清風，塵夢忽喚醒。", "一僧從吾遊，策蹇度峻嶺。", "山家喜客來，呼兒瀹新茗。", "班荆坐茅簷，款話清晝永。", "何日遂歸耕，來此謀二頃。"]'),
('a341836c-b88c-4780-9eee-26b3d7d93639','中秋望月呈諸友','胡仲弓','宋','宋诗','song-poetry','','[]','長空萬里琉璃滑，冰輪碾上黄金闕。',128,'全唐诗/poet.song.220000.json','["長空萬里琉璃滑，冰輪碾上黄金闕。", "清光爍盡滿天星，桂枝摇落蟾蜍活。", "故園此夕盡翹首，望殺陰精眼瀝血。", "烏鵲遶樹飛且鳴，世間晝夜無分別。", "詩人兀坐冰壺中，清氣蕭蕭透毛骨。", "玉簫何處招鳳凰，更抱琵琶對風撥。", "可人來赴今秋期，共舉霞觴酌明月。", "醉邊且盡今宵歡，後會相望隔閩越。"]'),
('dfb46600-740e-48b1-8e18-8cb5a23e08e8','過大官嶺','胡仲弓','宋','宋诗','song-poetry','','[]','大官小官相送迎，閒雲割斷前山青。',112,'全唐诗/poet.song.220000.json','["大官小官相送迎，閒雲割斷前山青。", "前山萬仞如壁立，南轅北轍何時停。", "憧憧來往成何事，中有一路通天庭。", "天庭走馬平如掌，胡爲此地勞其形。", "從來大官無險阻，小官跋涉真零丁。", "道人長嘯烟霞表，祝君一語君須聽。", "大官小官喜經歷，咫尺前頭是相亭。"]'),
('6bddf751-15e3-4daf-b853-34062102e66a','晉安城東溫泉','胡仲弓','宋','宋诗','song-poetry','','[]','女媧補天愁天破，石底千年埋宿火。',128,'全唐诗/poet.song.220000.json','["女媧補天愁天破，石底千年埋宿火。", "火蒸泉脈爲溫湯，鑿開浴沼涵天光。", "美人含羞弄清泚，一朶芙蓉蘸秋水。", "起來無力著纖裳，冰肌縹緲輕雲香。", "人間何福能堪此，好與天家浴仙子。", "曾聞前代有華清，玉龍活動真妮驚。", "吾皇仁聖格天地，天錫玄符地呈瑞。", "風雷奔擊鬼神呼，溫泉一夕移燕都。"]'),
('332f3bd5-18c8-4817-8164-664c5d9fc539','夜聞琵琶','胡仲弓','宋','宋诗','song-poetry','','[]','金波西流雲路潔，千星萬星猶點纈。',176,'全唐诗/poet.song.220000.json','["金波西流雲路潔，千星萬星猶點纈。", "身世如在冰壺中，高卧風櫺賞清絕。", "誰家撥動鬰輪袍，自抱心聲細推說。", "猝然聞之耳亦清，徐聽令人心欲裂。", "八音獨有絲聲哀，似此琵琶聲更切。", "龍香動處絃欲折，自撥一聲三擊節。", "湓浦有人曾話別，舟中夜聞金縷掣。", "司馬酒腸剛似鐵，淚珠亦就青衫結。", "清音巧作聲嗚咽，此器特爲愁人設。", "韻如寒泉清且冽，安得曹綱同一撥。", "曲終忽作裂帛聲，萬籟沉沉天地闊。"]'),
('5aafb9af-e09d-4bc5-88ec-e057133bb781','次韻送水紋簟與芸居','胡仲弓','宋','宋诗','song-poetry','','[]','火雲飛空風日惡，展轉吟身何所托。',80,'全唐诗/poet.song.220000.json','["火雲飛空風日惡，展轉吟身何所托。", "珊瑚爲枕玉爲床，數卷新詩慰寥寞。", "湘紋曾浸水晶寒，有時纔展生微瀾。", "持與芸居作清供，百年强健長追歡。", "何日一樽陪李賀，羽扇綸巾看高卧。"]'),
('b3f1a606-8661-49a9-81d0-f61057b012d1','談星林漢留求詩','胡仲弓','宋','宋诗','song-poetry','','[]','君貧賣術我賣文，君貧似我貧一分。',64,'全唐诗/poet.song.220000.json','["君貧賣術我賣文，君貧似我貧一分。", "君挾天盤走湖海，我携破硯登青雲。", "兩窮相值君莫笑，賣文有時饑可療。", "天邊一點少微星，會與太陽來合照。"]'),
('0a96359f-b397-48c4-962b-ea9b389108da','秦氏樓','胡仲弓','宋','宋诗','song-poetry','','[]','秦氏樓中雙飛燕，樓前柳絮沾人衣。',48,'全唐诗/poet.song.220000.json','["秦氏樓中雙飛燕，樓前柳絮沾人衣。", "春風輕薄穿繡幃，抱琴指按黄金徽。", "鼓終一曲三歎息，思君子兮何時歸。"]'),
('4012dc6d-61c5-41ed-98a2-659019dd093e','題葉山甫見惠古琴走筆以謝','胡仲弓','宋','宋诗','song-poetry','','[]','南風之歌久絕響，生民不作聲希想。',160,'全唐诗/poet.song.220000.json','["南風之歌久絕響，生民不作聲希想。", "聲音之道與政通，審音知政惟絲桐。", "堪嗟世道多翻覆，幾度桑田變陵谷。", "摩挲古物憶當年，人在春風和氣天。", "治世之音安以樂，斯琴當年羽衣作。", "物換星移閲幾周，不圖今日爲君留。", "袖來贈與無絃客，得之何啻如珪璧。", "籀文篆古未爲奇，我思古人珍秘時。", "古人不可得而見，見琴如見當時面。", "安得尋聲問爨人，爲吾一洗琴上塵。"]'),
('ca7b3c84-5e1e-4bcb-ab27-78b858973aad','子經昔有黄筌玉筍圖故人陳衆仲題詩其上後爲人易去常追憶不已余往借觀臨之以歸鄭氏并識以詩','胡仲弓','宋','宋诗','song-poetry','','[]','春雷殷殷盎中鳴，籜龍驚起頭角獰。',144,'全唐诗/poet.song.220000.json','["春雷殷殷盎中鳴，籜龍驚起頭角獰。", "斕斑裂土穿石出，長鑱斸下津浮玉。", "山人嗜之比八珍，畫師寫生傳千春。", "纖纖翠交烟雨濕，山人嘆嗟山鬼泣。", "玉堂修撰富才情，歌詩贊畫增晶英。", "春花欲語嬌倚檻，蜀錦魯縞光可鑑。", "無端五窮睹揶揄，巧偷當面輸陶朱。", "我從借觀弄毫素，座間一夕珠還浦。", "自知詩盡劣陳黄，無人豪奪君無藏。"]'),
('90217046-90e0-4bb8-8131-f8230b06b88a','蛛絲巧','胡仲弓','宋','宋诗','song-poetry','','[]','蛛絲雖巧能害物，蠶絲雖拙能利人。',80,'全唐诗/poet.song.220000.json','["蛛絲雖巧能害物，蠶絲雖拙能利人。", "害物晨昏一飽足，利人往往害及身。", "乃知巧者能遠禍，拙者生死常爲鄰。", "吾寧爲蠶勿爲蛛，所願殺身以成仁。", "千絲萬縷何足恤，要令寒谷皆陽春。"]'),
('4698c360-a117-40b3-8b8a-37e57420e3a6','精衛','胡仲弓','宋','宋诗','song-poetry','','[]','子房鑄鐵報韓仇，智者反爲豪俠誤。',80,'全唐诗/poet.song.220000.json','["子房鑄鐵報韓仇，智者反爲豪俠誤。", "傾秦豈在博浪沙，繼世自聞嬴業仆。", "吁嗟精衛亦償冤，一旦奮飛身不顧。", "銜石填海抑何愚，豈在朝朝與暮暮。", "精衛精衛汝不知，滄海終有陵谷時。"]'),
('cf24c0e3-2cdf-46ae-8b17-4c3daffa9a58','感興','胡仲弓','宋','宋诗','song-poetry','','[]','有絲不繡平原君，有金不鑄鍾子期。',64,'全唐诗/poet.song.220000.json','["有絲不繡平原君，有金不鑄鍾子期。", "此心抱獨無人會，百年只有青天知。", "青天冥冥不可詰，舉頭當中有皦日。", "從來天日不可欺，何用區區守暗室。"]'),
('3b1ffcc3-fafd-47c1-a47c-e2d55193b95c','錢塘潮圖','胡仲弓','宋','宋诗','song-poetry','','[]','輕綃淡墨天冥冥，眼中似覺對西興。',96,'全唐诗/poet.song.220000.json','["輕綃淡墨天冥冥，眼中似覺對西興。", "銀山大浪萬鼓過，海潮逆上江倒行。", "前年南遊此餞別，親友握手難爲情。", "酒酣拂袂不忍顧，欹枕仰看雲帆輕。", "平生浪跡半天下，摇毫掉舌終何成。", "并州故鄉真可畫，新生白髮星星明。"]'),
('c2ff069e-b20d-4b11-a9be-1efade1d2ec2','抱拙以三通鼓爲韻見寄次韻','胡仲弓','宋','宋诗','song-poetry','','[]','夜闌缺月浸寒潭，亂山倒影空中涵。',144,'全唐诗/poet.song.220000.json','["夜闌缺月浸寒潭，亂山倒影空中涵。", "此時萬籟寂無語，碧雲鬰結如晴嵐。", "可人已趁春風去，舉盃對影成三三。", "割席賦詩鬭擊鉢，舟中醉卧推枕函。", "紅塵瞇目空相蒙，千金市駿輕花驄。", "何如濃墨恣揮灑，筆鋒掃退江文通。", "錦繡叢中燕鶑侶，惜花愛作風光主。", "何如揮麈共清談，朝訪安石暮夷甫。", "焚香燒燭恣狂吟，管甚鼕鼕催五鼓。"]'),
('19a411c7-295a-48a3-b7cf-9d79cb10f7fd','寄懶庵','胡仲弓','宋','宋诗','song-poetry','','[]','天寒日短道路長，白雲飛處知吾鄉。',144,'全唐诗/poet.song.220000.json','["天寒日短道路長，白雲飛處知吾鄉。", "大江之東渭之北，念我故人何可忘。", "別來楊柳春依依，只今開到梅花香。", "扁舟漫浪歸未得，京塵海裏安行藏。", "身名未立仰天笑，牀頭夜夜鳴干將。", "羨師物外無寵辱，庭前柏樹常蒼蒼。", "吁嗟無羽飛不到，二千里外空相望。", "五雲前墜滿室光，報師之意無以將。", "篇詩濃墨纔淋浪，一聲鴈過天南翔。"]'),
('97d50688-4780-449e-ac3d-8b2aad820fdc','舟中夜聞彈箏','胡仲弓','宋','宋诗','song-poetry','','[]','艤舟尋近岸，餘興月明中。',48,'全唐诗/poet.song.220000.json','["艤舟尋近岸，餘興月明中。", "鼓瑟人何在，彈箏意略同。", "聲和隨去浪，調古動悲風。", "銀甲無由見，清音出繡櫳。"]'),
('fd4cf51e-dba1-4cee-98d0-6e2cbad0b368','竹夫人','胡仲弓','宋','宋诗','song-poetry','','[]','虛心陪燕寢，不受虢秦封。',48,'全唐诗/poet.song.220000.json','["虛心陪燕寢，不受虢秦封。", "惟有冰霜節，全無雲雨蹤。", "李娥書舊恨，湘女斂愁容。", "却是專房寵，無人妬阿儂。"]'),
('30a55c29-6539-4381-b265-f6c3d426d23d','泛舟分韻得橫字','胡仲弓','宋','宋诗','song-poetry','','[]','艤舟迷近遠，鷗鷺許同盟。',48,'全唐诗/poet.song.220000.json','["艤舟迷近遠，鷗鷺許同盟。", "潮落沙仍漲，風晴浪不驚。", "一川平野秀，半嶺斷雲橫。", "後約何時再，吟篷卧月明。"]'),
('5a5f5e46-63ff-4983-bb40-2bd9e891ea86','湖邊','胡仲弓','宋','宋诗','song-poetry','','[]','乍過黄梅雨，湖邊物色饒。',48,'全唐诗/poet.song.220000.json','["乍過黄梅雨，湖邊物色饒。", "水深宜鳥浴，藻密礙魚跳。", "露重荷傾蓋，風高柳折腰。", "道人勤借問，此地好漁樵。"]'),
('50f601fc-c2b4-45c9-b6c5-69317a2347b1','山臺赴召','胡仲弓','宋','宋诗','song-poetry','','[]','世道今如許，先生亦肯來。',48,'全唐诗/poet.song.220000.json','["世道今如許，先生亦肯來。", "一番新詔命，只是舊山臺。", "心事雲間鶴，詩情雪後梅。", "諸公興黨論，未可薦人材。"]'),
('a772f093-842d-4039-be7e-0bf28f98813c','漫興','胡仲弓','宋','宋诗','song-poetry','','[]','大笑出塵間，吟身得暫閒。',48,'全唐诗/poet.song.220000.json','["大笑出塵間，吟身得暫閒。", "解衣臨水閣，倚杖看雲山。", "歸鳥聲如市，騎牛歌更蠻。", "明邊一點墨，元是野僧還。"]'),
('68a0e4b9-64f6-4561-9826-c1a47b03c4c0','遠眺','胡仲弓','宋','宋诗','song-poetry','','[]','袖手獨凭欄，乾坤杯酒間。',48,'全唐诗/poet.song.220000.json','["袖手獨凭欄，乾坤杯酒間。", "此心常坦易，何地不寬閒。", "木落山頭禿，冰堅水面頑。", "梅花可人意，一見一開顔。"]'),
('8155b557-ead9-4b6d-8f4b-71ebf3847b19','題潘庭堅響玉集後','胡仲弓','宋','宋诗','song-poetry','','[]','陛對端平日，雄文四海傳。',48,'全唐诗/poet.song.220000.json','["陛對端平日，雄文四海傳。", "一登黄甲後，多在紫巖邊。", "好客時招飲，貪詩夜廢眠。", "寥寥三百載，先後兩庭堅。"]'),
('694e57c2-97ce-46e4-ba16-41f85a2744a6','湖','胡仲弓','宋','宋诗','song-poetry','','[]','獨坐過湖船，涼生欲暮天。',48,'全唐诗/poet.song.220000.json','["獨坐過湖船，涼生欲暮天。", "鷗眠汀草亂，魚躍浪花圓。", "足迹烟霞外，吟聲風月邊。", "萬緣無所欠，只欠買山錢。"]'),
('b7af975b-d93b-4aff-976f-2715c703aec9','旅中早行','胡仲弓','宋','宋诗','song-poetry','','[]','前山風雨暗，欲去路還迷。',48,'全唐诗/poet.song.220000.json','["前山風雨暗，欲去路還迷。", "燭影照行李，鐘聲催曉鷄。", "年光銷旅况，秋氣入征蹄。", "如此困行役，何時歸去兮。"]'),
('a5ed18d5-305b-42cf-a274-cdcdc4f2a63b','還翁雪舟吟卷','胡仲弓','宋','宋诗','song-poetry','','[]','世間迂闊者，端的是詩人。',48,'全唐诗/poet.song.220000.json','["世間迂闊者，端的是詩人。", "獨坐無生計，相逢盡說貧。", "如君追古作，與我最情親。", "切莫輕辜負，元龍湖海身。"]'),
('b1118f1d-d204-4cc8-92eb-b03d5b34ac78','贈陳通妙','胡仲弓','宋','宋诗','song-poetry','','[]','雙成親囑咐，從此厭塵緣。',48,'全唐诗/poet.song.220000.json','["雙成親囑咐，從此厭塵緣。", "天上黄冠侶，人間紫府仙。", "金爐行殿曉，玉磬古壇烟。", "待得蟠桃熟，重逢又幾年。"]'),
('7c39a6f8-8b1a-462e-ba45-142627c1d5bb','除夕寄弟','胡仲弓','宋','宋诗','song-poetry','','[]','年華今告老，人事亦如斯。',48,'全唐诗/poet.song.220000.json','["年華今告老，人事亦如斯。", "漢殿藏鈎戲，戎家守歲時。", "世情方役役，雨意正垂垂。", "强作屠蘇醉，椒盤欲頌誰。"]'),
('e82646b5-b806-47b6-b4ee-3649b1927669','和雲心除夕韻','胡仲弓','宋','宋诗','song-poetry','','[]','歲除明日是，心事落梅邊。',48,'全唐诗/poet.song.220000.json','["歲除明日是，心事落梅邊。", "節物催雙鬢，情懷欠少年。", "桃符依帖寫，竹爆應聲圓。", "椒頌無人獻，酴酥亦自煎。"]'),
('e4b7cf18-a2da-4139-9e9c-8b4adad150e1','贈雲谷道士','胡仲弓','宋','宋诗','song-poetry','','[]','身形如野鶴，飛去每離羣。',48,'全唐诗/poet.song.220000.json','["身形如野鶴，飛去每離羣。", "玉磬隨緣定，金丹與衆分。", "渴摇花上露，卧枕谷中雲。", "傳得九仙訣，修真好似君。"]'),
('e3b46a07-3bde-4b77-ba9c-120273281810','矮道人','胡仲弓','宋','宋诗','song-poetry','','[]','白髮蒼顔老，孩童三尺身。',48,'全唐诗/poet.song.220000.json','["白髮蒼顔老，孩童三尺身。", "向來陽刺史，留得道州人。", "鳬膝應難續，龜趺卒莫伸。", "朝家無歲貢，流落瘴江濱。"]'),
('592ff01d-d6b9-4543-ba14-7443856e7b97','送丁鍊師歸福堂','胡仲弓','宋','宋诗','song-poetry','','[]','易東流派遠，千載見斯人。',48,'全唐诗/poet.song.220000.json','["易東流派遠，千載見斯人。", "金鼎烹龍虎，丹書役鬼神。", "形臞心更古，食淡語尤真。", "野鶴沖天去，空餘華表身。"]'),
('ccc55c15-3fbd-4f3c-b4e9-5d6379c0f333','失脚','胡仲弓','宋','宋诗','song-poetry','','[]','失脚江湖久，憂時鬢欲皤。',48,'全唐诗/poet.song.220000.json','["失脚江湖久，憂時鬢欲皤。", "壯心馳北闕，癡夢繞南柯。", "萬里關山遠，一春風雨多。", "窮簷茅屋下，忍聽扊扅歌。"]'),
('e90889de-067a-4dcb-98ce-5ca5a98277df','湯惠院以五言定交用韻以謝','胡仲弓','宋','宋诗','song-poetry','','[]','阿邕纔識面，轉盼便回春。',48,'全唐诗/poet.song.220000.json','["阿邕纔識面，轉盼便回春。", "藥籠還君富，詩囊笑我貧。", "學遵東魯訓，句逼晚唐人。", "五字論交意，吟邊憶李頻。"]'),
('bac19703-5f8a-42d7-9a3a-3e397edfacf3','春郊晚歸','胡仲弓','宋','宋诗','song-poetry','','[]','苔錢隨履跡，柳絮點春衣。',48,'全唐诗/poet.song.220000.json','["苔錢隨履跡，柳絮點春衣。", "塔影留殘照，鐘聲出翠微。", "扶將藜杖去，挑取錦囊歸。", "緩步微吟久，重城半掩扉。"]'),
('30f68da6-0877-465e-aca1-e8b54977ee4b','金粟道人','胡仲弓','宋','宋诗','song-poetry','','[]','曾食如瓜棗，蟠桃幾度開。',48,'全唐诗/poet.song.220000.json','["曾食如瓜棗，蟠桃幾度開。", "石榴書壁去，金粟滿包來。", "雲氣侵丹竈，春山入酒杯。", "步虛聲漸遠，何處覓蓬萊。"]'),
('bee2a7a7-888b-4627-a092-28264ad15f26','散策郊行有懷社友','胡仲弓','宋','宋诗','song-poetry','','[]','散策尋詩料，過從野老家。',48,'全唐诗/poet.song.220000.json','["散策尋詩料，過從野老家。", "水寬蛙世界，花暖蝶生涯。", "翠箔風爲捲，青山雲半遮。", "懷人千里外，搔首夕陽斜。"]'),
('50819576-98b4-40f6-94bf-12754dda7bb5','寒碧席上薪隠分韻得初字','胡仲弓','宋','宋诗','song-poetry','','[]','心遠塵難到，高堂便讀書。',48,'全唐诗/poet.song.220000.json','["心遠塵難到，高堂便讀書。", "鳳歸巢已覆，鶴去柵常虛。", "野水平荷葉，清風繞竹廬。", "靜邊生萬感，况復晚涼初。"]'),
('51f6831d-0151-4a1d-b1b8-43f3126d8e80','觀海口占','胡仲弓','宋','宋诗','song-poetry','','[]','揚帆飽風腹，望眼無東西。',48,'全唐诗/poet.song.220000.json','["揚帆飽風腹，望眼無東西。", "天圍滄海闊，日射崑崙低。", "魚鼈夜深泣，鴻鵠空中迷。", "風濤且莫作，心撼神龍棲。"]'),
('ca651a10-eb8d-4655-b43b-dcb43139b423','枯崖韻速藏叟和篇','胡仲弓','宋','宋诗','song-poetry','','[]','暗塵侵古鏡，抱膝月臺吟。',48,'全唐诗/poet.song.220000.json','["暗塵侵古鏡，抱膝月臺吟。", "大呂呼不出，小詩留至今。", "五言詩未下，什襲意何深。", "莫是推敲了，禪餘自賞音。"]'),
('66b90630-3953-4151-bf76-ae9e9057b6ef','和溪翁二首  其一','胡仲弓','宋','宋诗','song-poetry','','[]','學僧居丈室，不似客途中。',48,'全唐诗/poet.song.220000.json','["學僧居丈室，不似客途中。", "獨榻卧明月，長廊受晚風。", "書癡成病懶，詩債喜窮工。", "汩汩塵埃者，吾今愧此翁。"]'),
('35fca618-5f7a-402c-941e-11aa93d00d0c','和溪翁二首  其二','胡仲弓','宋','宋诗','song-poetry','','[]','片帆湖海闊，移纜晉江濱。',48,'全唐诗/poet.song.220000.json','["片帆湖海闊，移纜晉江濱。", "客思蛩邊老，秋蟬鴈外新。", "同吟兒對榻，獨酌影隨身。", "暗卜歸時節，修書托便鱗。"]'),
('d141dcc9-e2b4-4ea6-b822-d7c82cab472f','燈花','胡仲弓','宋','宋诗','song-poetry','','[]','根頭餘寸草，結作數層紅。',48,'全唐诗/poet.song.220000.json','["根頭餘寸草，結作數層紅。", "預卜門庭喜，非關造化功。", "開時常入夜，落後不因風。", "誤被燈蛾撲，從知色是空。"]'),
('396f8d31-fc63-49bc-84d5-b71696d65a8d','妙覺山用老溪寶葉二僧韻  其一','胡仲弓','宋','宋诗','song-poetry','','[]','登山無杖策，元不事依憑。',48,'全唐诗/poet.song.220000.json','["登山無杖策，元不事依憑。", "斜照穿林影，行雲礙石稜。", "鳥啼悲宿草，猿飲掛枯藤。", "曾著高僧住，何人爲續燈。"]'),
('0034f3a6-a4ac-44d3-b69e-728acffe9b64','妙覺山用老溪寶葉二僧韻  其二','胡仲弓','宋','宋诗','song-poetry','','[]','庵居天半壁，古道擬山陰。',48,'全唐诗/poet.song.220000.json','["庵居天半壁，古道擬山陰。", "風勁松鬚落，石高泉眼深。", "鐘聲清嶂合，幡脚翠嵐侵。", "二妙堪名世，詩人曾賞音。"]'),
('64a0c1e1-3cb4-4bfd-a392-13091ce9367e','凌霄塔','胡仲弓','宋','宋诗','song-poetry','','[]','浮圖山盡處，八表浩無涯。',48,'全唐诗/poet.song.220000.json','["浮圖山盡處，八表浩無涯。", "脚踏雷轟石，眼生陽艷花。", "天圍連海岱，雲氣雜烟霞。", "如此真孤絕，學仙能幾家。"]'),
('1be04000-d48b-444e-9a95-3ce5cffc972d','答頤齋併呈諸友','胡仲弓','宋','宋诗','song-poetry','','[]','陰晴千古事，落在醉吟中。',48,'全唐诗/poet.song.220000.json','["陰晴千古事，落在醉吟中。", "佳句何人續，清樽此日同。", "幕天浮大白，繡地纈殘紅。", "江上峰如舊，湘靈曲未終。"]'),
('27e8d374-4a09-4609-a2b5-cc5f3d04e031','答晚香','胡仲弓','宋','宋诗','song-poetry','','[]','一巢如燕寄，來傍主人居。',48,'全唐诗/poet.song.220000.json','["一巢如燕寄，來傍主人居。", "著脚須教實，圖名却是虛。", "髭因吟盡摘，愁遣酒能鉏。", "乾鵲簷前報，天邊有吉書。"]'),
('2eed5ace-aff8-4d05-abaa-1aa101986789','次韻答頤齋','胡仲弓','宋','宋诗','song-poetry','','[]','雀羅門外設，塵遠市廛居。',48,'全唐诗/poet.song.220000.json','["雀羅門外設，塵遠市廛居。", "抱膝吟梁父，摩聲賦子虛。", "苔錢何用鑄，草带莫教鉏。", "世事難開口，休投北闕書。"]'),
('ddfec2ea-ec76-4356-8014-ac765343411b','答青山閣見寄','胡仲弓','宋','宋诗','song-poetry','','[]','詩人無俗事，侵曉訪僧居。',48,'全唐诗/poet.song.220000.json','["詩人無俗事，侵曉訪僧居。", "山近市聲遠，樓空松影虛。", "耕雲雖有地，種藥恐無鉏。", "但學觀心法，何須課佛書。"]'),
('bdb513e0-2979-4c47-9d9a-4a8261398a61','次韻答方元吉','胡仲弓','宋','宋诗','song-poetry','','[]','新知如舊識，話久覺情真。',48,'全唐诗/poet.song.220000.json','["新知如舊識，話久覺情真。", "雲出壺山早，風行晉水春。", "家貧因過客，世變爲詩人。", "曾點龍門額，煩君再問津。"]'),
('865bcdb3-51e4-487e-8b64-0f11633895dd','爲續芸賦','胡仲弓','宋','宋诗','song-poetry','','[]','芸居老衣鉢，付與寧馨兒。',48,'全唐诗/poet.song.220000.json','["芸居老衣鉢，付與寧馨兒。", "舊種無多葉，生香不斷枝。", "折芳歸藝圃，賸馥入詩脾。", "粉省他年事，清名當自期。"]'),
('239a3052-7c10-40dc-8a56-863ce441145f','青蓮寺避暑','胡仲弓','宋','宋诗','song-poetry','','[]','盡日畏炎夏，隨緣到上方。',48,'全唐诗/poet.song.220000.json','["盡日畏炎夏，隨緣到上方。", "此心無熱惱，何地不清涼。", "款話移禪榻，高眠背夕陽。", "衣巾並枕簟，長带佛爐香。"]'),
('aadfd483-300e-4389-a21a-ffe710edc969','驟雨','胡仲弓','宋','宋诗','song-poetry','','[]','神龍奮頭角，頃刻致風雷。',48,'全唐诗/poet.song.220000.json','["神龍奮頭角，頃刻致風雷。", "雲逐溪南去，雨從山北來。", "炎凉分枕簟，灑落滿樓臺。", "物物皆霑足，餘膏及草萊。"]'),
('b93a27c8-dab6-47df-8285-8dada22af1eb','贈譚山人','胡仲弓','宋','宋诗','song-poetry','','[]','地僻人稀到，柴門鎮日開。',48,'全唐诗/poet.song.220000.json','["地僻人稀到，柴門鎮日開。", "依山泥藥竈，累石築經臺。", "野鶴連窠買，梅花間竹栽。", "世無真隠者，只此是蓬萊。"]'),
('f7ee6f43-b65c-408c-a4b3-02d82b64a8cb','夜過蕭寺','胡仲弓','宋','宋诗','song-poetry','','[]','尋僧過野寺，清話捧茶甌。',48,'全唐诗/poet.song.220000.json','["尋僧過野寺，清話捧茶甌。", "幡影風生樹，鐘聲月在樓。", "梅花薰紙帳，貝葉看銀鈎。", "爲問西來意，因成一夜留。"]'),
('8c4652a6-4c75-4a86-9640-0245e89127c7','長人詩','胡仲弓','宋','宋诗','song-poetry','','[]','裙長難掩膝，絕似漢金人。',48,'全唐诗/poet.song.220000.json','["裙長難掩膝，絕似漢金人。", "樓志幻全體，天丁現後身。", "眼高傾四海，力大引千鈞。", "手挽銀河水，來涓衣上塵。"]'),
('e144609d-b31c-4a24-b8a4-2a1a7e90bb3c','洪樓分得車字韻','胡仲弓','宋','宋诗','song-poetry','','[]','江湖詩境闊，終不似樓居。',48,'全唐诗/poet.song.220000.json','["江湖詩境闊，終不似樓居。", "老怕吟氈冷，生來酒興疎。", "愛閒隨有鶴，因病出無馿。", "莫笑柴扉窄，猶堪長者車。"]'),
('5f2953a0-06db-4eeb-b3d5-a90800c2886f','送趙庸齋去國','胡仲弓','宋','宋诗','song-poetry','','[]','十年居要路，依舊老書生。',48,'全唐诗/poet.song.220000.json','["十年居要路，依舊老書生。", "公論是非定，宗臣去就輕。", "羣鴉分地噪，一鳳仰天鳴。", "善類俄星散，何因見太平。"]'),
('0bd97c10-974f-4b51-90bf-23f00f940b3a','山居  其一','胡仲弓','宋','宋诗','song-poetry','','[]','懶踏紅塵路，山居世念輕。',48,'全唐诗/poet.song.220000.json','["懶踏紅塵路，山居世念輕。", "澆蘭清夜氣，撼竹引秋聲。", "缺月當欄掛，閒雲貼水輕。", "不知何處鶴，亦作太平鳴。"]'),
('4f5d7ab6-dd1d-40eb-aa1e-ad347b9e34c3','山居  其二','胡仲弓','宋','宋诗','song-poetry','','[]','山扉風自掩，地僻少將迎。',48,'全唐诗/poet.song.220000.json','["山扉風自掩，地僻少將迎。", "奇字挑燈看，新吟擊鉢成。", "鳳花開自落，螢草腐還生。", "靜聽鄰琴響，疑調慢角聲。"]'),
('122c1a2b-4bdd-4fcb-b75e-fcf77c6b1b67','寄林可山  其一','胡仲弓','宋','宋诗','song-poetry','','[]','相去各天涯，江湖會面遲。',48,'全唐诗/poet.song.220000.json','["相去各天涯，江湖會面遲。", "數年不通問，一見便言詩。", "近世無和靖，今人說項斯。", "孤山梅已熟，滋味獨君知。"]'),
('0c8c620a-7ca0-472d-9ea2-671f12322177','寄林可山  其二','胡仲弓','宋','宋诗','song-poetry','','[]','可人期不至，日日望山孤。',48,'全唐诗/poet.song.220000.json','["可人期不至，日日望山孤。", "不是招吟侶，多應覓酒徒。", "虛名付蕉鹿，清興動蓴鱸。", "見說同川好，能通一葦無。"]'),
('225de1a2-2292-4851-8ce0-e604b9052694','寄芸居','胡仲弓','宋','宋诗','song-poetry','','[]','京塵方衮衮，君獨此安居。',48,'全唐诗/poet.song.220000.json','["京塵方衮衮，君獨此安居。", "竹簡編科斗，芸香辟蠹魚。", "眼空湖海士，兒讀聖賢書。", "一樣吟樽樂，公卿未必如。"]'),
('0ee036d8-094c-4333-b181-5a9546ebc7f0','寄容老','胡仲弓','宋','宋诗','song-poetry','','[]','抖擻征衣著，京塵點涴深。',48,'全唐诗/poet.song.220000.json','["抖擻征衣著，京塵點涴深。", "羨君有丘壑，愧我未山林。", "卜隠中年事，懷人靜夜心。", "何時遂歸興，杯酒共清吟。"]'),
('3280bba5-24cb-49b3-b423-51d310b8a161','寄藏叟','胡仲弓','宋','宋诗','song-poetry','','[]','版扉常半掩，人靜少經過。',48,'全唐诗/poet.song.220000.json','["版扉常半掩，人靜少經過。", "禪思夜來得，吟情秋後多。", "月高幡影直，風定磬聲和。", "何日同携手，雲山訪薜蘿。"]'),
('69388662-0b22-42a5-933b-588a1c32ab76','寄懷玉','胡仲弓','宋','宋诗','song-poetry','','[]','別去未多時，征塵又滿衣。',48,'全唐诗/poet.song.220000.json','["別去未多時，征塵又滿衣。", "憂時閽屢叩，避俗手頻揮。", "病有詩堪療，貧無家可歸。", "半生湖海上，莫忘北山薇。"]'),
('31e02d88-b47a-4bc1-b50b-3bd9cdedf0fd','次同叔見寄二首  其一','胡仲弓','宋','宋诗','song-poetry','','[]','歸期何日卜，鴈不到天涯。',48,'全唐诗/poet.song.220000.json','["歸期何日卜，鴈不到天涯。", "謗有書盈篋，愁無地種花。", "吟梅銷旅況，刻竹記年華。", "心事憑誰說，凭欄數暝鴉。"]'),
('589d4378-d5b5-4342-93a2-986adee48882','次同叔見寄二首  其二','胡仲弓','宋','宋诗','song-poetry','','[]','昔年三笑地，目斷虎溪橋。',48,'全唐诗/poet.song.220000.json','["昔年三笑地，目斷虎溪橋。", "立雪腰難折，凌雲氣尚飄。", "乾坤雙轍跡，湖海一詩瓢。", "樽酒何時共，論文坐半宵。"]'),
('58b35df0-39b7-43e1-ba94-1b6ae6475385','王用和歸從莆水寄呈後村','胡仲弓','宋','宋诗','song-poetry','','[]','江湖從學者，盡欲倚劉牆。',48,'全唐诗/poet.song.220000.json','["江湖從學者，盡欲倚劉牆。", "自笑塵埃瞇，難薰衣鉢香。", "薜蘿緣古樹，桃李背春場。", "螢爝飄流去，能依萬丈光。"]'),
('60a85f6f-423d-49d8-84bf-67e2408752c2','寄頤齋','胡仲弓','宋','宋诗','song-poetry','','[]','蛙聲喧夜枕，買靜入林居。',48,'全唐诗/poet.song.220000.json','["蛙聲喧夜枕，買靜入林居。", "好句敲唐響，清談笑晉虛。", "素馨和月種，山藥带雲鋤。", "閒裏多忙事，篝燈課子書。"]'),
('1457034a-ae4d-4307-9327-abe6dab9387d','寄月塘','胡仲弓','宋','宋诗','song-poetry','','[]','懷人看皓月，清夢落梅邊。',48,'全唐诗/poet.song.220000.json','["懷人看皓月，清夢落梅邊。", "書債閒銷日，吟魂飛上天。", "爲貧驅宦牒，習懶坐寒氈。", "但得投簪去，何須二頃田。"]'),
('064e5ef8-4330-447f-a882-1b8f5377f00c','寄敏齋','胡仲弓','宋','宋诗','song-poetry','','[]','地隔馬牛風，村居野興濃。',48,'全唐诗/poet.song.220000.json','["地隔馬牛風，村居野興濃。", "宦情隨蝶夢，吟鬢覺龍鍾。", "竹外琴三疊，梅邊信一封。", "懷人不可耐，山水幾千重。"]'),
('aa993592-49cc-488b-ad2d-4fdf7dcceae1','寄適安朝宗','胡仲弓','宋','宋诗','song-poetry','','[]','桐陰湖水綠，清氣日盈門。',48,'全唐诗/poet.song.220000.json','["桐陰湖水綠，清氣日盈門。", "室邇人何遠，官卑道更尊。", "詩吟唐律語，琴寫古人言。", "三妙堪名世，無因得細論。"]'),
('852949e6-82c0-4ac1-aa81-eced806c4617','寄王道源','胡仲弓','宋','宋诗','song-poetry','','[]','南來趨斗祿，出處最分明。',48,'全唐诗/poet.song.220000.json','["南來趨斗祿，出處最分明。", "不受吏塵觸，常依古道行。", "宦情雲樣薄，心事水邊清。", "待洗巢由耳，欹風聽鳳鳴。"]'),
('642a9917-b0a8-4475-873e-dcb14daab16d','寄水竹','胡仲弓','宋','宋诗','song-poetry','','[]','吳江江上望，平處少波濤。',48,'全唐诗/poet.song.220000.json','["吳江江上望，平處少波濤。", "冬日思鱸鱠，天風落鳳毛。", "二難并四美，獨立仰三高。", "秀野曾招隠，清名不可逃。"]'),
('0f0135b4-fa5e-4863-8a22-8866d6244075','寄抱拙','胡仲弓','宋','宋诗','song-poetry','','[]','割席坐春風，清談滋味濃。',48,'全唐诗/poet.song.220000.json','["割席坐春風，清談滋味濃。", "齊門聽鼓瑟，長樂憶聞鐘。", "道等千鈞重，詩輕萬戶封。", "梅花今在望，載酒幾時重。"]'),
('c6cfa197-8367-4b0b-a21e-1c2577bedec2','懷悟書','胡仲弓','宋','宋诗','song-poetry','','[]','秋鴈欲離羣，懷人幾夜分。',48,'全唐诗/poet.song.220000.json','["秋鴈欲離羣，懷人幾夜分。", "吟當半窗月，坐斷兩山雲。", "旛影無心動，鐘聲出定聞。", "林間謀隠者，修潔莫如君。"]'),
('6395f1a5-9be3-4a5b-9faa-a2e1cb51a0b8','聽宮入琴','胡仲弓','宋','宋诗','song-poetry','','[]','羣哇方雜奏，忽聽數聲琴。',48,'全唐诗/poet.song.220000.json','["羣哇方雜奏，忽聽數聲琴。", "天地有清氣，君王知正音。", "悲風生指玉，明月照徽金。", "曾撫昭君怨，宮人淚滿襟。"]'),
('4f116cef-88cc-49bb-9229-ef8cece925b2','將之官越上留別諸友','胡仲弓','宋','宋诗','song-poetry','','[]','一官如許冷，况復是清貧。',48,'全唐诗/poet.song.220000.json','["一官如許冷，况復是清貧。", "槐市風何古，蘭亭本却真。", "春行蓬島外，月滿鑑湖濱。", "想得同吟者，携詩舉似人。"]'),
('f6120a04-7d59-45cc-a7ca-368b7b5bea6b','山中歸呈友人','胡仲弓','宋','宋诗','song-poetry','','[]','擬結巖邊草，懷君夜夢刀。',48,'全唐诗/poet.song.220000.json','["擬結巖邊草，懷君夜夢刀。", "山林勝朝市，道誼寄風騷。", "壯志貧難折，吟肩病越高。", "主人有公論，清氣屬吾曹。"]'),
('50b0bdf1-93b7-44e5-829e-4cbe95d7b02f','寄西澗葉侍郎','胡仲弓','宋','宋诗','song-poetry','','[]','擬立門前雪，來時春又深。',48,'全唐诗/poet.song.220000.json','["擬立門前雪，來時春又深。", "望塵思北面，因病負初心。", "形役猶甘分，腸枯費苦吟。", "升堂定何日，洗耳聽規箴。"]'),
('081f74ee-9134-43a1-b57d-d42d6ccbfeab','祈雪','胡仲弓','宋','宋诗','song-poetry','','[]','天意憐貧者，冬深雪尚慳。',48,'全唐诗/poet.song.220000.json','["天意憐貧者，冬深雪尚慳。", "朔風吹黑道，雲氣護青山。", "色瑞占三白，年豐露一斑。", "調元人已老，事體頗相關。"]'),
('0540814b-b447-4a21-a062-82f850c1cca4','和枯崖山居韻','胡仲弓','宋','宋诗','song-poetry','','[]','自了塵緣後，山林恨不深。',48,'全唐诗/poet.song.220000.json','["自了塵緣後，山林恨不深。", "百年渾是夢，萬事付無心。", "秋月寮中話，清風竹外吟。", "湖東多勝踐，何日共幽尋。"]'),
('d252a56f-1016-4775-88e3-39b6de69fee7','次馮深居韻贈原上人','胡仲弓','宋','宋诗','song-poetry','','[]','浄洗塵埃脚，時來訪道林。',48,'全唐诗/poet.song.220000.json','["浄洗塵埃脚，時來訪道林。", "但知謀隠是，何用入山深。", "瀹茗延新話，撞鐘動苦吟。", "夜分僧出定，靜聽海潮音。"]'),
('fc73a878-93e8-41f0-afba-438e44bf721f','次希道弟韻寄竹院孚上人','胡仲弓','宋','宋诗','song-poetry','','[]','閉門商古道，細雨濕青春。',48,'全唐诗/poet.song.220000.json','["閉門商古道，細雨濕青春。", "屬和卯君句，殷勤巳上人。", "蒲團安地位，秀語發天真。", "舊日曾同社，吾今愧許詢。"]'),
('3101b87f-d928-41a3-9f64-39ee4c03d528','懷枯崖悟師','胡仲弓','宋','宋诗','song-poetry','','[]','分携方解制，相約在嚴冬。',48,'全唐诗/poet.song.220000.json','["分携方解制，相約在嚴冬。", "巖脚日千里，山頭雲幾重。", "歸裝儂自悞，吟錫子何從。", "不應天台供，定知游雪峰。"]'),
('d5f3b41b-d9ba-41f8-b678-f62c93f41642','悟枯崖將過莆城參訪後村書此贈行','胡仲弓','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','吟單何日起，持鉢倚劉牆。',48,'全唐诗/poet.song.220000.json','["吟單何日起，持鉢倚劉牆。", "蓮社招師入，松陰去路長。", "白雲迷眼界，明月照詩囊。", "莫吸西江水，風波不可當。"]'),
('f406b33a-04ac-4c22-9238-17fe5a8dfef2','與瞻甫同訪際書記','胡仲弓','宋','宋诗','song-poetry','','[]','銷閒尋靜處，古寺與居同。',48,'全唐诗/poet.song.220000.json','["銷閒尋靜處，古寺與居同。", "坐語僧窗日，行吟塔樹風。", "香隨薝蔔化，句到葛藤空。", "未必西來者，能知一葦功。"]'),
('cd46577a-7264-405b-88b5-a97ba6cb20b5','約枯崖話','胡仲弓','宋','宋诗','song-poetry','','[]','雨中曾折角，策蹇訪僧寮。',48,'全唐诗/poet.song.220000.json','["雨中曾折角，策蹇訪僧寮。", "待約蕉庵住，莫從蓮社招。", "清風資話柄，流水走詩瓢。", "行道知何日，同携過石橋。"]'),
('1723e9af-306f-45b9-8133-89ecd271f449','和際書記見寄','胡仲弓','宋','宋诗','song-poetry','','[]','人生隨聚散，水面看浮萍。',48,'全唐诗/poet.song.220000.json','["人生隨聚散，水面看浮萍。", "夢入江湖社，詩傳河嶽靈。", "免毫揮月穎，鶴毳落霜翎。", "未洗塵埃脚，何因訪柏庭。"]'),
('e91b9e95-cf5c-435d-b683-db35afebc045','閒居寄枯崖','胡仲弓','宋','宋诗','song-poetry','','[]','地偏人罕到，獨榻擬禪床。',48,'全唐诗/poet.song.220000.json','["地偏人罕到，獨榻擬禪床。", "欹枕圓殘夢，推窗待晚涼。", "行雲無定跡，新月不多光。", "安得君同社，清談滋味長。"]'),
('0f297595-33c8-480b-a40a-c9551f153374','贈悟上人','胡仲弓','宋','宋诗','song-poetry','','[]','怪來趨向別，乃是拙庵孫。',48,'全唐诗/poet.song.220000.json','["怪來趨向別，乃是拙庵孫。", "秋色添禪寂，松聲奪俗喧。", "路行須避蟻，飯剩或呼猿。", "單鉢隨緣住，尋常懶出門。"]'),
('5321d695-8603-4151-94b8-9edc2c555d10','崇福寺次枯崖韻','胡仲弓','宋','宋诗','song-poetry','','[]','覺城向東際，寺在古松灣。',48,'全唐诗/poet.song.220000.json','["覺城向東際，寺在古松灣。", "流水意俱遠，白雲僧共閒。", "新吟呈繡佛，舊夢繞囊山。", "勘破趙州話，猶疑隔一關。"]'),
('8b858543-0520-4b46-b98b-e3c68e66b11a','和枯崖悟上人韻','胡仲弓','宋','宋诗','song-poetry','','[]','相逢疑夙昔，不擬定交初。',48,'全唐诗/poet.song.220000.json','["相逢疑夙昔，不擬定交初。", "餽我詩盈軸，知君腹有書。", "空門容不得，吟屬問何如。", "云是湯休輩，毋令相見疎。"]'),
('ad3c7f1d-9d90-444d-89c6-0b1d40c0a7e9','送枯崖歸囊山','胡仲弓','宋','宋诗','song-poetry','','[]','江湖無足禁，信步到溫陵。',48,'全唐诗/poet.song.220000.json','["江湖無足禁，信步到溫陵。", "借榻同爲客，打包別有僧。", "禪心如止水，詩句可傳燈。", "已盡山陰興，歸歟掃葛藤。"]'),
('0fe8551d-bad5-44a0-8bdd-b35bd9656d00','松灣訪僧','胡仲弓','宋','宋诗','song-poetry','','[]','一關鎖已透，見性復明心。',48,'全唐诗/poet.song.220000.json','["一關鎖已透，見性復明心。", "佛屋燈常續，禪房春又深。", "樓空遺稿在，琴古暗塵侵。", "待約許詢輩，時來訪道林。"]'),
('08b46bcc-11b1-4a50-bc1d-af9156f277a3','山中訪枯崖歸偶成','胡仲弓','宋','宋诗','song-poetry','','[]','尋僧歸路遠，策杖點苔痕。',48,'全唐诗/poet.song.220000.json','["尋僧歸路遠，策杖點苔痕。", "坐醉松間石，行吟郭外村。", "天風翻貝葉，海氣潤牆根。", "醉撚梅花笑，心期與子論。"]'),
('c41125a8-ce71-4741-a4c1-f65b3f1703ea','贈巖居僧','胡仲弓','宋','宋诗','song-poetry','','[]','清閒消不盡，方覺此身尊。',48,'全唐诗/poet.song.220000.json','["清閒消不盡，方覺此身尊。", "洞古少行跡，山空多燒痕。", "靜知心是佛，生與佛無恩。", "齋料從誰給，頻齏野菜根。"]'),
('7b7fd5f2-b329-4109-b296-05fb3261c1b8','次韻送黄耑玉歸莆','胡仲弓','宋','宋诗','song-poetry','','[]','主人情分熟，客興未應闌。',48,'全唐诗/poet.song.220000.json','["主人情分熟，客興未應闌。", "從古知心少，只今行路難。", "吟身霜竹瘦，歸夢早梅寒。", "若見潜夫說，官清貧亦安。"]'),
('da915354-c7a2-4c1a-98b9-e32f064e7650','倚窗詩','胡仲弓','宋','宋诗','song-poetry','','[]','倚窗成小立，風伯爲清塵。',48,'全唐诗/poet.song.220000.json','["倚窗成小立，風伯爲清塵。", "簾捲梅當戶，雲開月闖人。", "疎鐘來遠寺，落葉度吟身。", "無限關心事，棲遲寂寞濱。"]'),
('cbdd64e7-8cc1-4678-9d2b-b802e56c5ccd','雪後','胡仲弓','宋','宋诗','song-poetry','','[]','一冬寒意少，既雪又還晴。',48,'全唐诗/poet.song.220000.json','["一冬寒意少，既雪又還晴。", "地面冰初結，天涯春已深。", "六花隨雨化，三白有梅爭。", "袖手灞橋道，懷人心事清。"]'),
('7237cfd2-69af-4425-86e0-b1ecf34bc96a','雪中雜興四首  其一','胡仲弓','宋','宋诗','song-poetry','','[]','六花正零亂，却與雨相和。',48,'全唐诗/poet.song.220000.json','["六花正零亂，却與雨相和。", "地面頻頻化，山頭漸漸皤。", "歌樓寒較少，窮巷積偏多。", "百卉歸根後，惟松不改柯。"]'),
('4793261d-870f-4ee0-974f-8a90f48354f7','雪中雜興四首  其二','胡仲弓','宋','宋诗','song-poetry','','[]','獨坐看詩話，瓶梅相對清。',48,'全唐诗/poet.song.220000.json','["獨坐看詩話，瓶梅相對清。", "瓦燈寒不暈，雪屋夜偏明。", "煨栗填饑腹，煎茶長道情。", "睡魔排遣盡，窗外聽鷄聲。"]'),
('c4ad8e15-2e79-4121-b58e-7529bddff2d8','雪中雜興四首  其三','胡仲弓','宋','宋诗','song-poetry','','[]','怪得簷前溜，原來是雪消。',48,'全唐诗/poet.song.220000.json','["怪得簷前溜，原來是雪消。", "山枯空有骨，水涸不成潮。", "寒鴈鳴沙磧，饑鴉啄柳條。", "物情總如此，吟鬢任蕭蕭。"]'),
('d1297deb-9b08-4cea-8efa-eef78fd10a5b','雪中雜興四首  其四','胡仲弓','宋','宋诗','song-poetry','','[]','窮通俱莫問，久遠是前程。',48,'全唐诗/poet.song.220000.json','["窮通俱莫問，久遠是前程。", "涉世事多俗，吟詩人較清。", "論心欠蘭友，知己有梅兄。", "不被虛名縛，江湖得散行。"]'),
('7542ef72-5568-4e8b-8ff3-aed1f3fa641d','南雪','胡仲弓','宋','宋诗','song-poetry','','[]','南地無寒脈，胡爲雪載塗。',48,'全唐诗/poet.song.220000.json','["南地無寒脈，胡爲雪載塗。", "草池方積玉，瓦屋又跳珠。", "魚凍難爭水，鴉饑懶哺雛。", "玉堂與茅舍，隨分有紅爐。"]'),
('0f0a8816-6442-4c67-aaaf-c54af8723c46','寶應寺','胡仲弓','宋','宋诗','song-poetry','','[]','來借維摩榻，披襟待晚涼。',48,'全唐诗/poet.song.220000.json','["來借維摩榻，披襟待晚涼。", "鳴蜩喧古木，鬥雀墮虛廊。", "染翰題新壁，移樽避夕陽。", "二公亭畔路，愛惹芰荷香。"]'),
('daefce78-6930-4bdd-9c92-4032e2b67f8d','次心泉卜隠韻','胡仲弓','宋','宋诗','song-poetry','','[]','誅茅法石巔，知己有青天。',48,'全唐诗/poet.song.220000.json','["誅茅法石巔，知己有青天。", "猿鶴尋前約，山林續舊緣。", "烟霞來枕上，風月繞吟邊。", "窗戶多栽竹，相期晚節堅。"]'),
('cbb78d44-20bf-44d5-b493-26d1eccbced9','隠者  其一','胡仲弓','宋','宋诗','song-poetry','','[]','老去絕塵緣，人疑行地仙。',48,'全唐诗/poet.song.220000.json','["老去絕塵緣，人疑行地仙。", "釜中惟煮石，囊裏不儲錢。", "寄迹茅三架，隨身詩一編。", "雲山深處住，與鶴作忘年。"]'),
('892befd1-8a96-47c4-80cb-9426d964eb48','隠者  其二','胡仲弓','宋','宋诗','song-poetry','','[]','種藥滿山巔，山衣木葉聯。',48,'全唐诗/poet.song.220000.json','["種藥滿山巔，山衣木葉聯。", "有時扶杖出，只到洞門前。", "擊石求鮮火，敲冰引滯泉。", "深居聊避世，不爲學神仙。"]'),
('84326203-3989-448e-a0fa-87ebf67b6ec5','戊午天基聖節口號','胡仲弓','宋','宋诗','song-poetry','','[]','瓣香三舞蹈，咫尺是天顔。',48,'全唐诗/poet.song.220000.json','["瓣香三舞蹈，咫尺是天顔。", "雨露涵濡下，風雲際會間。", "寸心瞻北闕，萬壽祝南山。", "可是儒氈冷，堪陪玉筍班。"]'),
('4c9ebc59-2b7f-477e-9681-92e891dae321','選官圖','胡仲弓','宋','宋诗','song-poetry','','[]','百年窮仕宦，盡在此圖中。',48,'全唐诗/poet.song.220000.json','["百年窮仕宦，盡在此圖中。", "真假名雖別，升沉理則同。", "前程如漆黑，末著滿盆紅。", "時采毋虛擲，平遷至上公。"]'),
('db5d4901-5070-4a98-8c86-4ce7eb9f76bc','重九日法輪庵次鳳山韻  其一','胡仲弓','宋','宋诗','song-poetry','','[]','野眺逾高阪，鐘傳響外幽。',48,'全唐诗/poet.song.220000.json','["野眺逾高阪，鐘傳響外幽。", "僧從孤寺出，客倚一林秋。", "池上烟飛去，亭臯影尚留。", "遠風山下起，吹我上層樓。"]'),
('ac54912c-a31f-4d11-9656-a7c29020d708','重九日法輪庵次鳳山韻  其二','胡仲弓','宋','宋诗','song-poetry','','[]','竟日延荒寺，秋聲不可歌。',48,'全唐诗/poet.song.220000.json','["竟日延荒寺，秋聲不可歌。", "磬中聞午至，石上見寒過。", "野鳥心常肅，孤僧鬢已皤。", "欲歸情不盡，門外夕陽多。"]'),
('0d28fa31-8554-46e0-85aa-fdea4e725a60','送處遜渡淮謁秋壑','胡仲弓','宋','宋诗','song-poetry','','[]','江湖波浪惡，底事欲西往。',48,'全唐诗/poet.song.220000.json','["江湖波浪惡，底事欲西往。", "去作揚州客，來尋賈壘盟。", "金山迷遠望，玉樹候吟聲。", "野鶴曾遊處，登臨一愴情。"]'),
('73170fe1-cbf6-46c2-a698-aeca9b39f3d0','懷李希膺','胡仲弓','宋','宋诗','song-poetry','','[]','病居身懶出，可是故人疏。',48,'全唐诗/poet.song.220000.json','["病居身懶出，可是故人疏。", "春後無佳句，天邊有近書。", "改弦知不遠，製錦定何如。", "未剗門前草，難通長者車。"]'),
('5f1fce48-6144-4e51-84af-b7905e7e19a7','山行即事','胡仲弓','宋','宋诗','song-poetry','','[]','踏破幾重雲，來尋別墅春。',48,'全唐诗/poet.song.220000.json','["踏破幾重雲，來尋別墅春。", "促裝童僕懶，題壁主人嗔。", "瘦嶺盤山骨，枯藤絡樹身。", "野花長滿地，不犯軟紅塵。"]'),
('64d081c6-53b0-4a01-8819-de3e9324dd84','送松坡下第調官南歸','胡仲弓','宋','宋诗','song-poetry','','[]','同點龍門額，君先賦式微。',48,'全唐诗/poet.song.220000.json','["同點龍門額，君先賦式微。", "自憐爲客久，不忍送人歸。", "受鉞張油幙，行囊富綵衣。", "江干回首處，雲樹兩依依。"]'),
('5a19cdc9-1e56-4d68-939a-f60d12389cf1','過梨嶺作','胡仲弓','宋','宋诗','song-poetry','','[]','山頭日正焚，山脚雨紛紛。',48,'全唐诗/poet.song.220000.json','["山頭日正焚，山脚雨紛紛。", "石罅疑無地，樹身常出雲。", "神靈香不斷，天近路平分。", "星斗迫人句，晚唐詩亦云。"]'),
('2f85a591-753e-4335-a9a1-d33a613f7997','和枯崖山行韻','胡仲弓','宋','宋诗','song-poetry','','[]','名山僧占盡，甘作老盧能。',48,'全唐诗/poet.song.220000.json','["名山僧占盡，甘作老盧能。", "虎豹何堪捋，虬龍尚可登。", "吟隨雙蠟屐，醉倚萬年藤。", "興盡未歸去，斜陽上塔層。"]'),
('13274cab-0d0a-463b-9206-e49d6b539206','與石壁諸友山行分得山字','胡仲弓','宋','宋诗','song-poetry','','[]','藤蘿紆古徑，努力共躋攀。',48,'全唐诗/poet.song.220000.json','["藤蘿紆古徑，努力共躋攀。", "佛屋泉聲落，僧窗雲影閒。", "經殘香篆冷，盃短錦囊慳。", "興盡未歸去，夕陽猶在山。"]'),
('4494afd2-7aeb-40f8-bd92-6ddbaf33052c','分得臺字走筆','胡仲弓','宋','宋诗','song-poetry','','[]','白雲最深處，屐齒破蒼苔。',48,'全唐诗/poet.song.220000.json','["白雲最深處，屐齒破蒼苔。", "借榻尋僧話，携樽領客來。", "禽聲喧竹塢，日影過花臺。", "長嘯下山去，猶傾鑿落杯。"]'),
('74c2e316-7af7-4b9d-9709-3abdbca4f96a','次周懶窠韻','胡仲弓','宋','宋诗','song-poetry','','[]','風月無邊際，吟身樂未央。',48,'全唐诗/poet.song.220000.json','["風月無邊際，吟身樂未央。", "江湖三寸舌，文字九回腸。", "竹伴孤高節，梅熏暗澹香。", "笑他蒲柳質，耐得幾番霜。"]'),
('26592b81-d9b4-4120-a358-52d277609b61','次懶窠見寄韻','胡仲弓','宋','宋诗','song-poetry','','[]','園丁無擇種，蕭艾雜椒蘭。',48,'全唐诗/poet.song.220000.json','["園丁無擇種，蕭艾雜椒蘭。", "世俗欠真識，達人當大觀。", "無絃徒自賞，有鋏莫空彈。", "獨倚西風立，推敲一字難。"]'),
('29a3cdad-8eee-4818-8948-b7c6a0ba87ae','隠真巖次翁景輔韻','胡仲弓','宋','宋诗','song-poetry','','[]','山林營小隠，此隠未爲真。',48,'全唐诗/poet.song.220000.json','["山林營小隠，此隠未爲真。", "遺粟渾閒事，因金却誤人。", "洞迷歸去路，羽化本來身。", "後此巖居者，猶言寂寞濱。"]'),
('6435b880-6636-4ed2-9c39-db6995ac9986','過山庵','胡仲弓','宋','宋诗','song-poetry','','[]','天地一間屋，心安到處家。',48,'全唐诗/poet.song.220000.json','["天地一間屋，心安到處家。", "淡中嘗世味，吟裏足生涯。", "煨芋頻添炭，烹泉旋品茶。", "空山無紙帳，夢不到梅花。"]'),
('707831be-7b18-4c15-b2bc-000b24a3c744','觀蟻','胡仲弓','宋','宋诗','song-poetry','','[]','飽知羶可慕，來往鬭相迎。',48,'全唐诗/poet.song.220000.json','["飽知羶可慕，來往鬭相迎。", "忙似人行役，多於鴈出征。", "數行緣壁去，一半上階行。", "何處堪投宿，相逢細問程。"]'),
('961a5aa8-b41a-405e-baa9-ddd0b796791e','秋夜','胡仲弓','宋','宋诗','song-poetry','','[]','欹枕卧明月，西風拂帳塵。',48,'全唐诗/poet.song.220000.json','["欹枕卧明月，西風拂帳塵。", "病因貧作祟，閒與懶爲鄰。", "意少吟難足，愁多夢不真。", "數聲窗外竹，惱殺斷腸人。"]'),
('849cd0ad-0a90-4061-a653-0e6fbb28d005','端硯','胡仲弓','宋','宋诗','song-poetry','','[]','中書爲尚友，鐵面迫人寒。',48,'全唐诗/poet.song.220000.json','["中書爲尚友，鐵面迫人寒。", "易得烏龍角，難逢紫馬肝。", "石英能比玉，歙好不如端。", "曾記文闈內，蒙君青眼看。"]'),
('2b566b79-1979-44ab-9053-2b2df0caac2c','獨倚','胡仲弓','宋','宋诗','song-poetry','','[]','獨倚危樓望，清風動斗牛。',48,'全唐诗/poet.song.220000.json','["獨倚危樓望，清風動斗牛。", "功名兩蠻觸，身世一蜉蝣。", "樂道貧何損，吟詩醉便休。", "靜中生萬感，燒燭看吳鈎。"]'),
('c4093f29-fb17-44c1-b6df-dc17ad4ace9b','久客','胡仲弓','宋','宋诗','song-poetry','','[]','久作他州客，飄飄若轉蓬。',48,'全唐诗/poet.song.220000.json','["久作他州客，飄飄若轉蓬。", "物華秋色裏，心事杵聲中。", "讀易因知命，吟詩不諱窮。", "遣愁猶未了，一鴈叫西風。"]'),
('5cbd9dce-85c1-4e06-b0da-967ea31b0bcb','俠客','胡仲弓','宋','宋诗','song-poetry','','[]','仗劍一長笑，出門遊四方。',48,'全唐诗/poet.song.220000.json','["仗劍一長笑，出門遊四方。", "雄心吞宇宙，俠骨耐風霜。", "豺虎須擒攫，狐狸敢頡頏。", "大梁二壯士，千古姓名香。"]'),
('5a7af6eb-50ad-4a15-ac78-aeeb94bafe23','客裏','胡仲弓','宋','宋诗','song-poetry','','[]','客裏多風雨，征衣不厭重。',48,'全唐诗/poet.song.220000.json','["客裏多風雨，征衣不厭重。", "輕車須穩駕，狹路易相逢。", "灘淺水聲激，山深雲氣濃。", "迎人野花笑，絕色若爲容。"]'),
('2d862411-4b02-4ffe-a7c6-560474905235','和頤齋梅花韻','胡仲弓','宋','宋诗','song-poetry','','[]','寒谷有春意，南枝向北山。',48,'全唐诗/poet.song.220000.json','["寒谷有春意，南枝向北山。", "自經題品後，落在是非間。", "林外竹相亞，籬根鶴伴閒。", "折來休用插，恐點鬢毛斑。"]'),
('c27542e0-4689-4f44-91d9-dddeb40cf33e','梅花窠子','胡仲弓','宋','宋诗','song-poetry','','[]','園丁藏密室，不許雪霜欺。',48,'全唐诗/poet.song.220000.json','["園丁藏密室，不許雪霜欺。", "火氣十分燠，春風第一枝。", "橫斜無定影，屈曲漫趨時。", "人力奪天巧，東君未必知。"]'),
('fcf7040b-e789-4490-bad3-9316a82e0fa8','落梅','胡仲弓','宋','宋诗','song-poetry','','[]','謝娥三弄笛，錯恨五更風。',48,'全唐诗/poet.song.220000.json','["謝娥三弄笛，錯恨五更風。", "樹老餘香少，花殘瘦影空。", "深堆和靖墓，淺點壽陽宮。", "結果重來此，方知造化工。"]'),
('6484615f-3f45-40ca-9af8-97cc3e674310','錢塘江待潮','胡仲弓','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','潮至千艘動，濤喧萬鼓鳴。',48,'全唐诗/poet.song.220000.json','["潮至千艘動，濤喧萬鼓鳴。", "江翻晴雪卷，海漲石塘平。", "帆影林端見，波光屋上明。", "青山自吳越，相峙兩含情。"]'),
('62e7c21e-bdd7-4289-962a-666a1677ca70','雨中有懷','胡仲弓','宋','宋诗','song-poetry','','[]','一天風雨暗，樓外失青巒。',48,'全唐诗/poet.song.220000.json','["一天風雨暗，樓外失青巒。", "枕簟三更夢，襟懷六月寒。", "酒船知獨載，詩卷爲誰刪。", "咫尺松灣路，思君欲見難。"]'),
('65ae0117-0098-4098-9566-d058a222102b','哭墓','胡仲弓','宋','宋诗','song-poetry','','[]','拜親親不待，事事與心違。',48,'全唐诗/poet.song.220000.json','["拜親親不待，事事與心違。", "萬里有歸日，九泉無見時。", "愁生新綠綬，淚滿舊斑衣。", "從此白雲斷，何當慰所思。"]'),
('648ab57d-cb78-43f4-a767-73dbcd952fe9','題村居壁','胡仲弓','宋','宋诗','song-poetry','','[]','何處村居好，山邊况水邊。',48,'全唐诗/poet.song.220000.json','["何處村居好，山邊况水邊。", "數間茅屋下，一带槿籬前。", "遶舍千竿竹，傳家二頃田。", "但求安樂法，不必問流年。"]'),
('0bec634d-ca4d-4cb6-85a0-c26b190743ab','書懷','胡仲弓','宋','宋诗','song-poetry','','[]','貧居無外事，圖得念頭清。',48,'全唐诗/poet.song.220000.json','["貧居無外事，圖得念頭清。", "冷眼觀時政，平心閲世情。", "好花臨水種，瘦竹傍牆生。", "自足供幽致，何須隠姓名。"]'),
('ae14b544-e210-42dd-be53-aa7dbf8e9603','世途','胡仲弓','宋','宋诗','song-poetry','','[]','世途猶炙熱，一雨便成秋。',48,'全唐诗/poet.song.220000.json','["世途猶炙熱，一雨便成秋。", "長嘯風生腋，孤吟人倚樓。", "生涯付杯酒，清夢繞魚舟。", "壯士悲何事，湖山憶舊遊。"]'),
('18f143fe-5637-4e6c-bdbc-a1d0a6e7ec3f','將樂縣','胡仲弓','宋','宋诗','song-poetry','','[]','石徑盤千折，林楓大十圍。',48,'全唐诗/poet.song.220000.json','["石徑盤千折，林楓大十圍。", "山如昌化縣，水似弋陽溪。", "樓閣層層畫，田園種種宜。", "惜非鄉國遠，有意卜幽棲。"]'),
('217a0899-b025-419a-8dd2-f37ec87b93d9','賦玳瑁魚','胡仲弓','宋','宋诗','song-poetry','','[]','海靈如許巧，龜貝點成紋。',48,'全唐诗/poet.song.220000.json','["海靈如許巧，龜貝點成紋。", "背負十三卦，旁分四六文。", "殻中藏勺水，身後管梳雲。", "貴介諸公蛻，何因得似君。"]'),
('6630bbcc-a8ad-4ed2-a90e-ba95a2446cc1','雪晴','胡仲弓','宋','宋诗','song-poetry','','[]','雲解雪初晴，青山依舊青。',48,'全唐诗/poet.song.220000.json','["雲解雪初晴，青山依舊青。", "水涵霜夜月，梅落曉天星。", "造物無今古，人生幾醉醒。", "倚樓吟未足，更上武林亭。"]'),
('9adb0cc7-8c4e-45e6-b9dd-d964807be9db','懷錢塘舊居','胡仲弓','宋','宋诗','song-poetry','','[]','錢塘漂泊久，別後夢連宵。',48,'全唐诗/poet.song.220000.json','["錢塘漂泊久，別後夢連宵。", "忽聽灘頭水，猶疑江上潮。", "暗塵侵竹簡，夜雨洗芭蕉。", "料得蘇堤路，西風犯柳條。"]'),
('72461592-8db5-4096-a97c-9e65fdf0e136','西溪即事','胡仲弓','宋','宋诗','song-poetry','','[]','柴門斜對水，一逕鎖松蘿。',48,'全唐诗/poet.song.220000.json','["柴門斜對水，一逕鎖松蘿。", "積雨溪流急，閒雲山占多。", "村莊留客飯，樵父教兒歌。", "聽得田間語，安排收晚禾。"]'),
('c7d39ed0-dbd2-46f4-bd62-f070655903c2','憶昔','胡仲弓','宋','宋诗','song-poetry','','[]','憶昔歲云暮，狂吟天一涯。',48,'全唐诗/poet.song.220000.json','["憶昔歲云暮，狂吟天一涯。", "江湖聊寄跡，時節最思家。", "有擔空行李，無盤可頌花。", "寒梅带香味，相伴守年華。"]'),
('7140cfb6-7b14-4ed0-8be6-a3c2866dc74b','題水竹居','胡仲弓','宋','宋诗','song-poetry','','[]','雲根無覓處，藏在此山阿。',48,'全唐诗/poet.song.220000.json','["雲根無覓處，藏在此山阿。", "地僻塵緣少，心清詩料多。", "竹虛元有節，水止故無波。", "甚欲投簪去，同君住薜蘿。"]'),
('1755b74e-c63f-483c-bfd2-e39c0e26d360','夜行口占','胡仲弓','宋','宋诗','song-poetry','','[]','夜程多晦昧，舉步要分明。',48,'全唐诗/poet.song.220000.json','["夜程多晦昧，舉步要分明。", "肯以中途廢，須尋直道行。", "心燈長不燼，眼鏡自然清。", "白晝昏迷者，荆榛滿路生。"]'),
('66b0fbd2-27bd-4ace-80da-89134387f241','病後呈芸居','胡仲弓','宋','宋诗','song-poetry','','[]','病骨清於鶴，臨風直欲飛。',48,'全唐诗/poet.song.220000.json','["病骨清於鶴，臨風直欲飛。", "閒多酬病債，吟苦費心機。", "带緩腰圍減，囊空藥裹稀。", "未能全謝客，扶杖掃林扉。"]'),
('89f8639e-7340-4c09-bf92-0bcf369f62d9','腰痛','胡仲弓','宋','宋诗','song-poetry','','[]','門前齊雪立，因被病相魔。',48,'全唐诗/poet.song.220000.json','["門前齊雪立，因被病相魔。", "堪佩金魚否，能懸寶劍麽。", "折非陶令懶，瘦似沈郎多。", "已辦揚州鶴，其如十萬何。"]'),
('0efb1943-187e-4ad7-ac8a-1e3922718613','與社友定花朝之約','胡仲弓','宋','宋诗','song-poetry','','[]','花朝曾有約，來此定詩盟。',48,'全唐诗/poet.song.220000.json','["花朝曾有約，來此定詩盟。", "隠几江湖夢，閉門風雨情。", "身名千載共，心事一般清。", "且盡吟樽樂，徂徠不用賡。"]'),
('d2f454b6-f380-4e8c-97b3-92b14678d167','桃源圖','胡仲弓','宋','宋诗','song-poetry','','[]','桃源分二種，半在此源栽。',48,'全唐诗/poet.song.220000.json','["桃源分二種，半在此源栽。", "向爲逃秦去，今還歸趙來。", "山川猶古昔，人物不塵埃。", "劉阮何爲者，無言空自回。"]'),
('538d4c35-35f2-4568-9968-fe8d8608a91c','題葉石軒學僧寮','胡仲弓','宋','宋诗','song-poetry','','[]','靜坐求心印，傳經續祖燈。',48,'全唐诗/poet.song.220000.json','["靜坐求心印，傳經續祖燈。", "因吟呈佛句，方悟在家僧。", "芸葉熏薝蔔，枝辭剪葛藤。", "自從駡師後，無話可參承。"]'),
('f90b9df0-2b5b-4d1b-b40b-4995c2600f12','高陽山遠眺','胡仲弓','宋','宋诗','song-poetry','','[]','龍尋多偉觀，立馬少徘徊。',48,'全唐诗/poet.song.220000.json','["龍尋多偉觀，立馬少徘徊。", "地僻風埃少，天成圖畫開。", "僅留官驛在，無復酒徒來。", "一鴈長空去，凭高叫不回。"]'),
('658c921e-0a14-4026-87c2-e88ee369bd0b','金陵  其一','胡仲弓','宋','宋诗','song-poetry','','[]','龍虎猶盤踞，前頭白鷺洲。',48,'全唐诗/poet.song.220000.json','["龍虎猶盤踞，前頭白鷺洲。", "爲今形勝地，往昔帝王州。", "人物金陵古，風煙玉樹秋。", "六朝羅綺迹，分付大江流。"]'),
('4e320c5a-5f92-4c9c-8337-99d005987f6f','金陵  其二','胡仲弓','宋','宋诗','song-poetry','','[]','掩目新亭路，人言似洛陽。',48,'全唐诗/poet.song.220000.json','["掩目新亭路，人言似洛陽。", "山河多改變，今古幾興亡。", "有觀空鳷鵲，無臺棲鳳凰。", "當年足歌舞，不擬是偏方。"]'),
('c266514f-4956-47a2-acc7-e208be2ea831','南浦','胡仲弓','宋','宋诗','song-poetry','','[]','脩途無好况，滿面受風埃。',48,'全唐诗/poet.song.220000.json','["脩途無好况，滿面受風埃。", "見說山窮處，曾經水患來。", "溪橋橫獨木，田野長荒萊。", "薄暮投孤館，寒猿聲更哀。"]'),
('62fe84aa-e3bb-4d57-92b8-3270f1e159aa','次烟浦即事韻','胡仲弓','宋','宋诗','song-poetry','','[]','吟帆歸路遠，花雨落紛紛。',48,'全唐诗/poet.song.220000.json','["吟帆歸路遠，花雨落紛紛。", "鷺過山加點，鷗飛水破紋。", "淡烟依古樹，殘照下空墳。", "未見巫陽面，高塘韻漫分。"]'),
('48e6d476-afd0-4d56-ab02-562c3e81a760','觀碁聞近事有感','胡仲弓','宋','宋诗','song-poetry','','[]','盤中無活路，敗局幾番新。',48,'全唐诗/poet.song.220000.json','["盤中無活路，敗局幾番新。", "好著輸前輩，危機遜後人。", "靜邊閒袖手，窮處巧翻身。", "黑白無分別，歸歟當自陳。"]'),
('fad74a03-70fa-487e-aa40-dafe4b53a3fe','仙霞嶺','胡仲弓','宋','宋诗','song-poetry','','[]','未了江湖債，風霜鬢欲華。',48,'全唐诗/poet.song.220000.json','["未了江湖債，風霜鬢欲華。", "吟身長是客，旅舍不如家。", "山色籠晴晝，湍聲潄淺沙。", "不因韁鎖縶，來此老烟霞。"]'),
('adb7f733-1019-44aa-9f81-9a28babf322e','九日','胡仲弓','宋','宋诗','song-poetry','','[]','客中逢九日，此日倍思家。',48,'全唐诗/poet.song.220000.json','["客中逢九日，此日倍思家。", "野店蒭無味，疏籬菊未花。", "龍山孤節物，鴈影各天涯。", "一路看秋色，微吟解嘆嗟。"]'),
('1b570a32-3a61-4c92-9314-7934fc1a9d0a','離家','胡仲弓','宋','宋诗','song-poetry','','[]','大笑出門去，江湖天地寬。',48,'全唐诗/poet.song.220000.json','["大笑出門去，江湖天地寬。", "耐貧爲客易，生計靠詩難。", "日月雙車轂，功名百丈竿。", "上林有嘉樹，且擇一枝安。"]'),
('c4f24cf6-0529-40dd-85f3-cbb2c773f259','小吳園','胡仲弓','宋','宋诗','song-poetry','','[]','臨水開門徑，關防俗子來。',48,'全唐诗/poet.song.220000.json','["臨水開門徑，關防俗子來。", "竹添當戶筍，梅老靠牆枝。", "嵐氣侵衣袂，湖光媚酒巵。", "主人全謝客，時遣鶴相隨。"]'),
('22db6113-6ee1-424b-9145-bd176845bc88','集芳園','胡仲弓','宋','宋诗','song-poetry','','[]','園丁嚴鎖鑰，不許俗人看。',48,'全唐诗/poet.song.220000.json','["園丁嚴鎖鑰，不許俗人看。", "梅落黄金彈，荷開碧玉盤。", "小舟維柳外，青磬出林端。", "猿鶴不相識，行吟獨倚欄。"]'),
('4a36c557-5396-415c-8b2d-014700b1a3a3','元日','胡仲弓','宋','宋诗','song-poetry','','[]','元日復元日，吟邊閲歲華。',48,'全唐诗/poet.song.220000.json','["元日復元日，吟邊閲歲華。", "淺斟浮柏葉，清坐對梅花。", "人事年年改，生涯步步差。", "詩情無厚薄，春意又萌芽。"]'),
('431762a2-2621-4fa6-bc99-221939463598','無塵殿','胡仲弓','宋','宋诗','song-poetry','','[]','劫灰飛不到，人迹少曾來。',48,'全唐诗/poet.song.220000.json','["劫灰飛不到，人迹少曾來。", "浪說珊瑚樹，空涵玉鏡臺。", "洞虛風度竹，泉冷石無苔。", "汩汩樊籠者，何因避世埃。"]'),
('0c53685a-89aa-4f55-ada1-8de211a0f124','春晚遊蔣園次韻','胡仲弓','宋','宋诗','song-poetry','','[]','挽住斜陽脚，殷勤向小園。',48,'全唐诗/poet.song.220000.json','["挽住斜陽脚，殷勤向小園。", "柳眠猶學舞，花笑獨無言。", "自擬湖山景，親承雨露恩。", "祇愁人散後，腐草點苔痕。"]'),
('42449fbf-c01f-4221-89cf-0e4f3ec923fd','問陳禹錫太博病','胡仲弓','宋','宋诗','song-poetry','','[]','脈虛非別癥，身坐蠹魚癡。',48,'全唐诗/poet.song.220000.json','["脈虛非別癥，身坐蠹魚癡。", "造物不青眼，江湖此白眉。", "近年書不至，遠宦夢相隨。", "遣病無他囑，加餐誦杜詩。"]'),
('0e490932-5b56-402f-b909-bca9172f1de9','病後','胡仲弓','宋','宋诗','song-poetry','','[]','病髮凋零後，朱顔似舊無。',48,'全唐诗/poet.song.220000.json','["病髮凋零後，朱顔似舊無。", "愁多詩債減，貧劇故交疏。", "風挾砧聲急，雲拖鴈影孤。", "夜來長不寐，欹枕看方書。"]'),
('0352b858-09ad-4fee-ae5c-6cf91b7ef0ed','哭芸居','胡仲弓','宋','宋诗','song-poetry','','[]','錦囊方絡繹，忽報殞吟身。',48,'全唐诗/poet.song.220000.json','["錦囊方絡繹，忽報殞吟身。", "泉壤悲千古，江湖少一人。", "病懷詩眷屬，醫欠藥君臣。", "脂嶺西風急，興思暗愴神。"]'),
('85d2fad3-687c-4885-88c1-fd6b3d1e879f','元日次韻','胡仲弓','宋','宋诗','song-poetry','','[]','纔書元旦帖，清事繞吟身。',48,'全唐诗/poet.song.220000.json','["纔書元旦帖，清事繞吟身。", "杖履堪行樂，簞瓢不似貧。", "燈花天外喜，池草夢中春。", "强飲酴酥酒，陶陶太古民。"]'),
('2e055daa-b639-4380-9a0b-0cc340523d14','浴溫泉','胡仲弓','宋','宋诗','song-poetry','','[]','萬水皆清冷，溫泉獨爾奇。',48,'全唐诗/poet.song.220000.json','["萬水皆清冷，溫泉獨爾奇。", "硫黄聞俗論，礜石見唐詩。", "鷗鷺何曾下，魚龍定不知。", "無人發根本，空使世常疑。"]'),
('6a718f7c-7f67-410c-9810-5f1dbe9e4901','和梅臞瀑布韻','胡仲弓','宋','宋诗','song-poetry','','[]','銀河清夜決，一派落巖前。',48,'全唐诗/poet.song.220000.json','["銀河清夜決，一派落巖前。", "雷激驚龍蟄，霜飛冷鶴眠。", "醉鄉思入聖，吟骨欲登仙。", "世路風波惡，山中別有天。"]'),
('85d3a4db-933e-480d-b3ef-1cd24782d329','倚樓','胡仲弓','宋','宋诗','song-poetry','','[]','樓高天一握，山入白雲根。',48,'全唐诗/poet.song.220000.json','["樓高天一握，山入白雲根。", "寺在牛鳴地，人行犬吠村。", "晴窗薰野馬，寒木下孤猿。", "吟罷月初上，詩僧來扣門。"]'),
('8f6e50d5-d322-466a-9aea-de83c7967f0d','寄梅臞','胡仲弓','宋','宋诗','song-poetry','','[]','別去忽經旬，春風閲二分。',48,'全唐诗/poet.song.220000.json','["別去忽經旬，春風閲二分。", "幾番吟對雨，獨自暗思君。", "客裏加頻病，愁邊駭近聞。", "倚欄商不得，心目亂於雲。"]'),
('3ed3de7d-8c7a-4dc9-8ef7-25af0434b6f7','寄黄雲心','胡仲弓','宋','宋诗','song-poetry','','[]','竹屋少行跡，閉門春晝長。',48,'全唐诗/poet.song.220000.json','["竹屋少行跡，閉門春晝長。", "天時半晴濕，人意共炎凉。", "苔蘚侵階綠，荼䕷壓架香。", "冥搜尋杖履，不爲看花忙。"]'),
('5b4fc1e0-6716-4a5f-b9c2-9f4f778befb3','靜中','胡仲弓','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','靜中天地闊，歲月聽悠悠。',48,'全唐诗/poet.song.220000.json','["靜中天地闊，歲月聽悠悠。", "往事渾如夢，長江不盡流。", "蛩吟似懷古，鴈陣去防秋。", "習得看山癖，終朝懶下樓。"]'),
('3a5be64e-ba9a-486c-a81b-62c9842e43b3','身事','胡仲弓','宋','宋诗','song-poetry','','[]','身事未如意，眉頭不暇攢。',48,'全唐诗/poet.song.220000.json','["身事未如意，眉頭不暇攢。", "青衫笑官冷，白屋带儒酸。", "癖性生來澹，中年貧最安。", "不爲溫飽計，儘可耐饑寒。"]'),
('a64435b5-afb4-4b11-b9dd-0926f1660e8a','次韻抱拙即事','胡仲弓','宋','宋诗','song-poetry','','[]','一嘯立東臯，輕寒侵二毛。',48,'全唐诗/poet.song.220000.json','["一嘯立東臯，輕寒侵二毛。", "曉光浮野草，春色染夭桃。", "有水池添滿，無雲山更高。", "清源何日約，掃石共歌騷。"]'),
('f952236c-5620-419f-802c-78eb0a97c8a8','次韻琛庭即事','胡仲弓','宋','宋诗','song-poetry','','[]','吏塵飛不到，官况儘凄凉。',48,'全唐诗/poet.song.220000.json','["吏塵飛不到，官况儘凄凉。", "實貨歸周府，虛名屬晉堂。", "日移槐影轉，風細荔花香。", "若問公私事，閒蛙話最長。"]'),
('c8f6aa00-a043-4d5e-b5d2-da22a74cd869','一第','胡仲弓','宋','宋诗','song-poetry','','[]','六年收一第，不特爲榮身。',48,'全唐诗/poet.song.220000.json','["六年收一第，不特爲榮身。", "殿下拜明主，堂前有老親。", "衣冠新進士，湖海舊詩人。", "誤入功名網，歸來負釣綸。"]'),
('f154688b-369c-4237-a2e9-d2c50fb7d49d','喜郭吉甫擢第調尉八柱還里','胡仲弓','宋','宋诗','song-poetry','','[]','一第全家待，君今衣錦歸。',48,'全唐诗/poet.song.220000.json','["一第全家待，君今衣錦歸。", "折來新月桂，忘却故山薇。", "祿近鸂呈瑞，官清馬不肥。", "海門西去路，歸鳥故飛飛。"]'),
('66ddd1a2-3aa7-41ef-b91c-8bf00f4b9842','頤齋再作催梅詩次韻','胡仲弓','宋','宋诗','song-poetry','','[]','但是南枝盡向陽，凝寒未許暗傳香。',64,'全唐诗/poet.song.220000.json','["但是南枝盡向陽，凝寒未許暗傳香。", "水邊疎影空浮月，嶺外孤根淺带霜。", "北帝無因全漏泄，東君何事巧遮藏。", "好將羯鼓花前報，莫待狂風破麝囊。"]'),
('8a18b54b-989c-497f-8fb9-c5329ade07d1','送李茂先去國','胡仲弓','宋','宋诗','song-poetry','','[]','榻前一疏犯龍顔，身在危疑進退間。',64,'全唐诗/poet.song.220000.json','["榻前一疏犯龍顔，身在危疑進退間。", "自是直言難見售，却於大義頗相關。", "孤忠力爲朝廷計，衆望公歸臺省班。", "畢竟名高人所忌，且移別眼看青山。"]'),
('5c37dcf2-998d-4c01-b196-e3f05fa24d9f','嚴子陵釣臺','胡仲弓','宋','宋诗','song-poetry','','[]','聘幣凡三到水涯，東都莫是欠人才。',64,'全唐诗/poet.song.220000.json','["聘幣凡三到水涯，東都莫是欠人才。", "當時若使無新室，此地安知有釣臺。", "魚水相忘身外樂，羊裘曾卧禁中來。", "桐江一派清如昨，千古高風挽不回。"]'),
('a942c375-64ba-42a5-acf7-1257003c4a75','卧聽','胡仲弓','宋','宋诗','song-poetry','','[]','卧聽芭蕉捲雨聲，熟梅天氣半陰晴。',64,'全唐诗/poet.song.220000.json','["卧聽芭蕉捲雨聲，熟梅天氣半陰晴。", "幾年不作雲山夢，特地來尋泉石盟。", "竹杖芒鞋方得意，桃笙葵扇又關情。", "清和時節如寒食，昨日街頭人賣餳。"]'),
('ea3218c8-38b8-43f0-8b9d-861eba438082','次韻山居','胡仲弓','宋','宋诗','song-poetry','','[]','夕陽漏影射疎林，三兩人家桑柘陰。',64,'全唐诗/poet.song.220000.json','["夕陽漏影射疎林，三兩人家桑柘陰。", "鶻過桚開歸鳥路，鐘敲撞碎野猿心。", "常因境勝甘忘食，不爲家貧輒廢吟。", "說與門前樵牧者，日間過此可相尋。"]'),
('5c29a920-2a22-4eb3-b4ce-a7d7fbe2ad55','送後村去國二首  其一','胡仲弓','宋','宋诗','song-poetry','','[]','人言責備過春秋，笑出修門肯怨尤。',64,'全唐诗/poet.song.220000.json','["人言責備過春秋，笑出修門肯怨尤。", "去國早知如許急，勸君何事莫來休。", "是非不信無公論，勝負常關第一籌。", "史筆未青先結局，天刑人禍免推求。"]'),
('a091f791-90fc-4584-a46c-fd1ea71a3f61','送後村去國二首  其二','胡仲弓','宋','宋诗','song-poetry','','[]','累疏箋天乞掛冠，此時便合整歸鞍。',64,'全唐诗/poet.song.220000.json','["累疏箋天乞掛冠，此時便合整歸鞍。", "玉音不許難輕去，局面那知竟未安。", "但得中朝常有道，何妨右史左遷官。", "此行不被梅花累，把作尋常物外看。"]'),
('f2dd4940-8dfb-4219-a955-1e33f221449f','寄吳警齋  其一','胡仲弓','宋','宋诗','song-poetry','','[]','去國翩翩又許時，愛君何日不攢眉。',64,'全唐诗/poet.song.220000.json','["去國翩翩又許時，愛君何日不攢眉。", "二賢出處分明甚，四諫聲名今似之。", "朝奏一封排佞疏，暮收千首餞行詩。", "山林若問朝廷事，寶劍年來正倒持。"]'),
('fe8d814c-b6d3-4a5d-b75a-236a7e34a4c7','寄吳警齋  其二','胡仲弓','宋','宋诗','song-poetry','','[]','豸冠風采動簪紳，天子如何不得臣。',64,'全唐诗/poet.song.220000.json','["豸冠風采動簪紳，天子如何不得臣。", "去後赤心常體國，從前冷語頗冰人。", "好官盡屬時賢做，近事看來局面新。", "輪轍深依梅竹下，一僮一鶴伴吟身。"]'),
('5d6dee02-02c4-49d0-8d15-716aad015c9d','九月八日寄懶窠','胡仲弓','宋','宋诗','song-poetry','','[]','轉盼重陽在眼前，客中歲月浪推遷。',64,'全唐诗/poet.song.220000.json','["轉盼重陽在眼前，客中歲月浪推遷。", "雲飛千里家何處，鴈過一聲秋滿天。", "節近最關萱草夢，囊空猶欠菊花錢。", "瞑心九日山頭路，雖不登高亦惘然。"]'),
('fbd20f32-0382-47a7-bd21-3a4874101417','寄默菴','胡仲弓','宋','宋诗','song-poetry','','[]','剩得吟身漫浪遊，機心猶在莫盟鷗。',64,'全唐诗/poet.song.220000.json','["剩得吟身漫浪遊，機心猶在莫盟鷗。", "一枰碁裏乾坤大，九節筇邊歲月流。", "涉世間關如履險，憂時感慨似悲秋。", "但營二頃閒田地，却笑區區萬戶侯。"]'),
('17bc72d8-3641-405e-82fc-0ef5ff927c3b','寄松坡','胡仲弓','宋','宋诗','song-poetry','','[]','別去京華又一霜，懷人心事暮雲長。',64,'全唐诗/poet.song.220000.json','["別去京華又一霜，懷人心事暮雲長。", "高樓不見青山面，明月偏來照屋梁。", "湖海最深難久駐，乾坤許大任行藏。", "書生空抱憂時憤，何日與君同較量。"]'),
('815ce0a8-bcb4-4ec9-b263-72298beb32c5','寄適安','胡仲弓','宋','宋诗','song-poetry','','[]','別來不作故人書，堪笑癡翁懶有餘。',64,'全唐诗/poet.song.220000.json','["別來不作故人書，堪笑癡翁懶有餘。", "世路每於平處險，交情多是密中疎。", "梅花至老香猶在，竹節雖高心本虛。", "門對青山無一事，便教草長不須鋤。"]'),
('272c4b05-4922-4987-baad-5664cbaa33dd','和丘君就見寄','胡仲弓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','曾坐當年阮籍途，功成何敢嘆桑榆。',64,'全唐诗/poet.song.220000.json','["曾坐當年阮籍途，功成何敢嘆桑榆。", "嚼來世味十分淡，吟得詩腸一半枯。", "向日有書干北闕，只今無夢到西湖。", "訪君欲話前頭事，怕被秋風吹病軀。"]'),
('2d3cc00c-bd1d-4690-925e-8bac5302d57d','寄順適','胡仲弓','宋','宋诗','song-poetry','','[]','標格因詩總不羣，眼前餘子漫紛紛。',64,'全唐诗/poet.song.220000.json','["標格因詩總不羣，眼前餘子漫紛紛。", "江頭社裏新知己，文字行間舊識君。", "心事正須豪傑道，吟聲莫遣鬼神聞。", "歲寒消得梅花伴，肯共扁舟載白雲。"]'),
('b57bba34-880e-4f8e-a9b0-55dbdbd23e4a','寄沈迂叟','胡仲弓','宋','宋诗','song-poetry','','[]','鴈飛不到瘴江邊，別去而今又一年。',64,'全唐诗/poet.song.220000.json','["鴈飛不到瘴江邊，別去而今又一年。", "放下客愁非爲酒，擡高詩價莫論錢。", "從來富貴皆尤物，休把行藏問老天。", "世味料君如嚼蠟，白雲堆裏且安眠。"]'),
('b0979e15-ccf9-4f5a-8d42-1d3a5e9c0d3b','寄姚省齋','胡仲弓','宋','宋诗','song-poetry','','[]','笑俯修欄一欠伸，年來蹤迹尚埃塵。',64,'全唐诗/poet.song.220000.json','["笑俯修欄一欠伸，年來蹤迹尚埃塵。", "幾曾隻字商量酒，强把篇詩料理春。", "風雨無情鶑口噤，江山有恨柳眉顰。", "不知桃李成陰未，我欲行吟避醉人。"]'),
('8f99a24c-46e0-4cf9-af37-bd11fa994f58','寄李適安','胡仲弓','宋','宋诗','song-poetry','','[]','懶踏門前沒馬塵，適安亭上坐吟身。',64,'全唐诗/poet.song.220000.json','["懶踏門前沒馬塵，適安亭上坐吟身。", "慇懃風月一樽酒，斟酌湖山十里春。", "柳葉未舒先嫵媚，梅花雖老更精神。", "白鷗似會冥搜意，來往忘機欲傍人。"]'),
('95c8ec0b-93ea-4cd7-82a7-ee9f8fe2470d','寄李希膺二首  其一','胡仲弓','宋','宋诗','song-poetry','','[]','醉倚危欄望海鯨，乍看潮落又潮生。',64,'全唐诗/poet.song.220000.json','["醉倚危欄望海鯨，乍看潮落又潮生。", "眼中世界粟來大，身外乾坤葉樣輕。", "鷗鷺行藏無俗迹，魚龍變化詎虛聲。", "冥搜誤入蠻烟去，祇恐梅花句未清。"]'),
('ecfbdaae-f105-4b91-8dbb-cc034e381c8d','寄李希膺二首  其二','胡仲弓','宋','宋诗','song-poetry','','[]','綠玉樽前笑語嬉，青燈影裏坐彈碁。',64,'全唐诗/poet.song.220000.json','["綠玉樽前笑語嬉，青燈影裏坐彈碁。", "交情又屬後來者，樂事何如初見時。", "山寺論文辭太苦，海樓握手句尤奇。", "歲寒不見梅花面，辜負暗香疎影詩。"]'),
('a13cb1d7-c0fb-46a2-a11b-0a18b3d62eab','次秀野使君見寄','胡仲弓','宋','宋诗','song-poetry','','[]','分閫南來征弗庭，薦賢須到李陽冰。',64,'全唐诗/poet.song.220000.json','["分閫南來征弗庭，薦賢須到李陽冰。", "不從沙漠去投筆，便向雲山學負苓。", "鈴閣祇今增璽綬，路車何日飾鈎膺。", "匣中古劍牢收拾，下取須防有六丁。"]'),
('8502d089-bc33-4a0d-9312-c2d6a7eeb400','寄戴石屏','胡仲弓','宋','宋诗','song-poetry','','[]','子入天台我入閩，歸來又見六番春。',64,'全唐诗/poet.song.220000.json','["子入天台我入閩，歸來又見六番春。", "鴈書乏便通安道，鶴頸長延望叔倫。", "吃藥未逢醫國手，聽琴誰見賞音人。", "年來屢作江湖夢，細嚼君詩當問津。"]'),
('e91f54d6-fe48-47c5-ac2e-a81720b3495c','寄趙西巖','胡仲弓','宋','宋诗','song-poetry','','[]','自分男兒未著鞭，龍駒伏櫪更多年。',64,'全唐诗/poet.song.220000.json','["自分男兒未著鞭，龍駒伏櫪更多年。", "張儀舌在堪謀國，阮籍途窮只問天。", "彈鋏空歌雲夢句，焚香靜讀楚騷篇。", "吟魂常繞江湖上，莫道閩中無杜鵑。"]'),
('f6e92135-37fb-454a-9214-b59d6a5bdbb1','送謝刑部使君赴召  其一','胡仲弓','宋','宋诗','song-poetry','','[]','擿奸方喜俗無譁，一札飛來墨敕斜。',64,'全唐诗/poet.song.220000.json','["擿奸方喜俗無譁，一札飛來墨敕斜。", "職業已昇金掌貴，吏民空擁綵旗遮。", "絳車趣召二千石，輿頌歡傳十萬家。", "桃李競隨春脚去，僅留遺愛在桐花。"]'),
('fa67ff41-09df-4688-8ff2-484019dbe365','送謝刑部使君赴召  其二','胡仲弓','宋','宋诗','song-poetry','','[]','中和報政二年間，五馬朝天不可攀。',64,'全唐诗/poet.song.220000.json','["中和報政二年間，五馬朝天不可攀。", "南國願留申伯住，東山催起謝公還。", "銀鈎鐵畫輝棠蔭，玉鑑冰壺照笋斑。", "名在御屏推課最，前途重見璽書頒。"]'),
('2148aa67-1478-45d1-8843-27ace2382fcd','泛湖晚歸式之有詩見寄因次其韻','胡仲弓','宋','宋诗','song-poetry','','[]','晚趁歸舟醉復醒，一湖烟水淡冥冥。',64,'全唐诗/poet.song.220000.json','["晚趁歸舟醉復醒，一湖烟水淡冥冥。", "自憐吟鬢新添白，强學遊人去踏青。", "足跡未經龍井寺，夢魂常繞冷泉亭。", "何時携手同登覽，花滿烏紗酒滿缾。"]'),
('21f139a1-9ed2-4590-a722-93de5150db0a','蔡司業爭公議而去詩以送之','胡仲弓','宋','宋诗','song-poetry','','[]','此舉朝廷繫重輕，先生直以去爲榮。',64,'全唐诗/poet.song.220000.json','["此舉朝廷繫重輕，先生直以去爲榮。", "但令天下無邪黨，不願吾曹有令名。", "模楷昔曾宗李氏，搢紳今盡說陽城。", "是非公論從來定，少待前頭風浪平。"]'),
('d4b3e92a-278e-4b91-bb34-caa308fbedde','頤齋詩筒急遞次韻奉酬','胡仲弓','宋','宋诗','song-poetry','','[]','一日懷人三閲秋，白鷗飛去水悠悠。',64,'全唐诗/poet.song.220000.json','["一日懷人三閲秋，白鷗飛去水悠悠。", "江山磨盡古今事，風雨送來天地愁。", "蝸喜自沿商隠壁，燕歸錯認仲宣樓。", "笛聲只在欄干曲，須向西鄰高處求。"]'),
('641a79e8-85f4-4e52-a8be-b76e37e240f7','再和頤齋見寄','胡仲弓','宋','宋诗','song-poetry','','[]','胸懷拍拍貯陽秋，萬里江山思遠悠。',64,'全唐诗/poet.song.220000.json','["胸懷拍拍貯陽秋，萬里江山思遠悠。", "自笑半生行酒禁，可能一日免詩愁。", "圖書圍裏誰分榻，風雨中間獨倚樓。", "除却知心吾與汝，吟邊何事冀旁求。"]'),
('537d39fa-ddc4-495d-9cb0-6c5b0807c118','立春','胡仲弓','宋','宋诗','song-poetry','','[]','移文火急報花神，好趁陽和去問津。',64,'全唐诗/poet.song.220000.json','["移文火急報花神，好趁陽和去問津。", "未轉頭間猶是臘，一彈指頃便爲春。", "梅先得志求專寵，柳亦趨時願效顰。", "造化但隨人事改，幾回粧點幾回新。"]'),
('b7e74c57-1f28-41a5-81f4-dd69806b7517','泠風閣','胡仲弓','宋','宋诗','song-poetry','','[]','高閣凌雲四望賒，劍城橫案俯千家。',64,'全唐诗/poet.song.220000.json','["高閣凌雲四望賒，劍城橫案俯千家。", "乘風列子留行館，飛舄王喬有別衙。", "天女下遊簫引鳳，仙人來宴棗如瓜。", "溪山勝絕非塵世，帆過真疑海上槎。"]'),
('5fb4bbeb-2c5a-4bf2-a5a8-f1ceb4fca0f0','西湖懷古','胡仲弓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','水拍平堤欲蘸天，濯纓人在小橋邊。',64,'全唐诗/poet.song.220000.json','["水拍平堤欲蘸天，濯纓人在小橋邊。", "古今塵世知多少，滄海桑田幾變遷。", "駝巘勳名無竹寫，孤山衣鉢有梅傳。", "誰能撰取西湖傳，持到玉皇香案前。"]'),
('df1b9f7e-3667-4de5-b2f1-e762e603837a','旱湖','胡仲弓','宋','宋诗','song-poetry','','[]','老天動是一年晴，怪底遊人不出城。',64,'全唐诗/poet.song.220000.json','["老天動是一年晴，怪底遊人不出城。", "湖上幾時無好况，堤邊近日少吟聲。", "草深盍放牛羊牧，水涸難尋鷗鷺盟。", "但得孤山梅不死，其他風物弗關情。"]'),
('7183959d-8eb6-4880-9c47-552945c75328','晚眺  其一','胡仲弓','宋','宋诗','song-poetry','','[]','數點寒鴉過別村，晚來秋色眼中分。',64,'全唐诗/poet.song.220000.json','["數點寒鴉過別村，晚來秋色眼中分。", "木從闕處留殘照，山欲昏時雜亂雲。", "兩岸草深蟲語話，一汀沙白鳥耕耘。", "林間僧舍知何處，回首鐘聲遠近聞。"]'),
('70e1ca13-ec36-4dfe-9a74-c3badaa99a1e','晚眺  其二','胡仲弓','宋','宋诗','song-poetry','','[]','幾度徘徊對暮天，懷人珍重寄詩篇。',64,'全唐诗/poet.song.220000.json','["幾度徘徊對暮天，懷人珍重寄詩篇。", "古今上下幾千首，天地中間八九椽。", "喚醒吟魂歸濁酒，移將傑句上華顛。", "南來諸老凋零盡，回首斜陽倍黯然。"]'),
('5fa06d03-acf6-4e1a-ac8e-349149e7ca2a','次趙同叔春雨中韻','胡仲弓','宋','宋诗','song-poetry','','[]','焚香清坐話襟期，絕勝孤篷共載時。',64,'全唐诗/poet.song.220000.json','["焚香清坐話襟期，絕勝孤篷共載時。", "曉雨旋添山蕨菜，春風又上海棠枝。", "蝶隨癡夢飛丹闕，鶑带吟聲繞墨池。", "小待陰晴何日定，不成學圃事樊遲。"]'),
('fe55bafa-cb0c-44a7-aefb-3735dfe38e31','結交嘆','胡仲弓','宋','宋诗','song-poetry','','[]','湖海相逢一笑嬉，納交如此豈男兒。',64,'全唐诗/poet.song.220000.json','["湖海相逢一笑嬉，納交如此豈男兒。", "論心盡道同蘭臭，臨事無聞伐木詩。", "管鮑雖貧猶忍棄，左羊至死更相知。", "歲寒不負松筠約，除却梅花耐久誰。"]'),
('abc4b42c-980c-4af7-85ab-60b4f958567f','冬雨即事寄趙默庵','胡仲弓','宋','宋诗','song-poetry','','[]','梅尚花時便作霖，兒童造化本無心。',64,'全唐诗/poet.song.220000.json','["梅尚花時便作霖，兒童造化本無心。", "保身獨鶴歸華表，噤口羣鴉集禁林。", "物態盡隨時改變，天公不管世晴陰。", "絕憐西北風寒地，萬騎屯中雪正深。"]'),
('c0460c19-0e33-4938-9fff-5cb7d7bf0cc4','春日過西湖','胡仲弓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','百花如錦柳如烟，粧點西湖二月天。',64,'全唐诗/poet.song.220000.json','["百花如錦柳如烟，粧點西湖二月天。", "便道過從來四聖，扁舟旖旎訪三賢。", "錢塘門外蘇堤上，豐樂樓前芝寺邊。", "箇裏萬般俱索價，惟餘風月不論錢。"]'),
('b8277ada-89c7-4fe7-a420-75c768a25d7e','九日山拜姜相遺像','胡仲弓','宋','宋诗','song-poetry','','[]','別駕元來是重臣，窮通不足累其身。',64,'全唐诗/poet.song.220000.json','["別駕元來是重臣，窮通不足累其身。", "直言悟主成遺恨，勁節如公能幾人。", "泉瀉冢堂垂鶴淚，苔封碑石剝龍鱗。", "至今繪像丹青手，難寫靈臺一點真。"]'),
('dbd33ec8-b3ad-439f-ac39-4a701f54b020','次梅莊守歲韻','胡仲弓','宋','宋诗','song-poetry','','[]','吟邊闒茸過年餘，萬斛塵襟未掃除。',64,'全唐诗/poet.song.220000.json','["吟邊闒茸過年餘，萬斛塵襟未掃除。", "守歲有人獻椒頌，辟邪無術諉桃符。", "屠蘇不飲防心醉，春帖慵裁欠句書。", "說與江湖諸老大，浮生消得幾桑榆。"]'),
('e4a04936-83e3-42a4-9411-b844c35fe3c0','近事','胡仲弓','宋','宋诗','song-poetry','','[]','近事山中總不知，心清常是太平時。',64,'全唐诗/poet.song.220000.json','["近事山中總不知，心清常是太平時。", "勿於貧後方求藥，纔得閒來便賦詩。", "千里白雲勞夢想，一天明月負襟期。", "有書堪讀梅堪看，絕倒人間富貴癡。"]'),
('0fdaa204-b600-4749-af9e-bb25ac65b151','賀林自知兄登第','胡仲弓','宋','宋诗','song-poetry','','[]','賀客來遲休怪余，新篇準備暮春初。',64,'全唐诗/poet.song.220000.json','["賀客來遲休怪余，新篇準備暮春初。", "羣兒得志誠逾望，一第於君非有餘。", "喜脫平生場屋債，飽看太古聖賢書。", "由來天爵無窮樂，人爵雖榮百不如。"]'),
('990ba138-8e29-4c95-865c-b42dad5e8b7d','秀野','胡仲弓','宋','宋诗','song-poetry','','[]','主人風度不塵埃，幻作東西兩洞來。',64,'全唐诗/poet.song.220000.json','["主人風度不塵埃，幻作東西兩洞來。", "惟有桑田變陵谷，直從心地起樓臺。", "水于曲處流觴出，山到盡頭留屐回。", "倦客幾時歸去得，稅園隨分買花栽。"]'),
('8f1b4831-7f1c-454f-aeae-f6291f27ca3e','送湯武諭倅吳門','胡仲弓','宋','宋诗','song-poetry','','[]','諸賢出處最關時，獨有先生早見機。',64,'全唐诗/poet.song.220000.json','["諸賢出處最關時，獨有先生早見機。", "漢柜昔曾藏諫筆，吳江今可澣朝衣。", "剩留千古清名在，带得一身公論歸。", "世事如碁吾懶著，敢將局面例言非。"]'),
('262c255a-3051-4b3e-b520-8f0fc4547be1','郊行即事','胡仲弓','宋','宋诗','song-poetry','','[]','貪看梅花短作程，吟鞭不動馬蹄輕。',64,'全唐诗/poet.song.220000.json','["貪看梅花短作程，吟鞭不動馬蹄輕。", "村莊到處如知己，物色於人亦有情。", "去雁遠連潮水落，亂山低與暮雲平。", "倚欄無語閒商略，此景誰能畫得成。"]'),
('1ba1b17f-a386-420d-8b9b-111b18b10a93','富沙水後次壁間韻','胡仲弓','宋','宋诗','song-poetry','','[]','聚落成墟空白烟，亂鴉飛繞夕陽邊。',64,'全唐诗/poet.song.220000.json','["聚落成墟空白烟，亂鴉飛繞夕陽邊。", "大江東去有遺恨，流水西來無渡船。", "青女魂遊花委地，王孫腸斷草連天。", "一樽欲酹故人酒，知是瑶池第幾仙。"]'),
('98515cef-8a7d-45e4-ae9d-7151108fc8b7','送月塘回藍溪','胡仲弓','宋','宋诗','song-poetry','','[]','仕路無媒且折枝，官清不必計高卑。',64,'全唐诗/poet.song.220000.json','["仕路無媒且折枝，官清不必計高卑。", "塞翁失馬庸奚損，海客盟鷗盍見疑。", "世狹有材無用處，家貧擇宦欲何之。", "藍溪溪上風波少，自把梅花自賦詩。"]'),
('57d90239-ada4-4c6c-9c72-808e939cef55','可山席上','胡仲弓','宋','宋诗','song-poetry','','[]','爐亭鎮上坐書癡，不似山居得自怡。',64,'全唐诗/poet.song.220000.json','["爐亭鎮上坐書癡，不似山居得自怡。", "傾竹葉杯延舊友，倚梅花樹看新詩。", "嚼來此味清于水，語對鄉情甘似飴。", "外此不須談近事，相逢一笑且舒眉。"]'),
('4301d67c-81dd-4501-a214-ee2c90e3b02f','和抱拙韻  其一','胡仲弓','宋','宋诗','song-poetry','','[]','關關鳩婦亦收聲，天意猶慳一日晴。',64,'全唐诗/poet.song.220000.json','["關關鳩婦亦收聲，天意猶慳一日晴。", "槐綠儘供春晝夢，梅黄尚憶歲寒盟。", "海邊書托文鱗便，戶外詩來喜鵲鳴。", "千里宦情隨處好，秋風何用記蓴羹。"]'),
('f914a8ee-0e14-42c4-a95f-49a1b9263601','和抱拙韻  其二','胡仲弓','宋','宋诗','song-poetry','','[]','倚樓長笛兩三聲，雲淡風輕弄曉晴。',64,'全唐诗/poet.song.220000.json','["倚樓長笛兩三聲，雲淡風輕弄曉晴。", "翰墨林中新體製，江湖社裏舊宗盟。", "不堪甕牖聞蟬噪，獨喜梧岡聽鳳鳴。", "安得坡仙同把酒，山間玉糝可分羹。"]'),
('cf8743cc-6c6a-479f-8419-25ccb354a72f','和希膺韻','胡仲弓','宋','宋诗','song-poetry','','[]','醉將濃墨寫烏絲，湖海相逢彼一時。',64,'全唐诗/poet.song.220000.json','["醉將濃墨寫烏絲，湖海相逢彼一時。", "洗竹僅留牆外筍，買花空揀擔頭枝。", "白鷗早已寒前約，青鳥誰知誤後期。", "惆悵玉簫聲已斷，倚闌重省寄來詩。"]'),
('2f81bf0c-aa90-4b3d-92a1-b622ff9a481a','和李希膺見寄','胡仲弓','宋','宋诗','song-poetry','','[]','半生幾坐阮途窮，可是推敲得句工。',64,'全唐诗/poet.song.220000.json','["半生幾坐阮途窮，可是推敲得句工。", "所見豪雄惟子共，此音今古更誰同。", "西風有檄催行李，明月無情照酒筒。", "我去君留差左計，媒身豈在泛蓮紅。"]'),
('60c5cac9-140d-4c3d-9f7e-bc2cacecc3ea','有感時事  其一','胡仲弓','宋','宋诗','song-poetry','','[]','湖濱別去五經秋，喜得閒居無悔尤。',64,'全唐诗/poet.song.220000.json','["湖濱別去五經秋，喜得閒居無悔尤。", "華藻不因焚硯棄，功名直待蓋棺休。", "北山何假移文檄，西事猶堪借箸籌。", "四海茫茫才思竭，如君尚向古人求。"]'),
('f3765905-2cb7-47e4-87ec-3c23317db1e8','有感時事  其二','胡仲弓','宋','宋诗','song-poetry','','[]','近聞怒髮欲衝冠，便有驊騮懶駕鞍。',64,'全唐诗/poet.song.220000.json','["近聞怒髮欲衝冠，便有驊騮懶駕鞍。", "入洛幾年爲計密，擎天八柱果誰安。", "力排魏闕扶公論，人謂膺門出好官。", "猶幸甘陵無部黨，不然世事不堪看。"]'),
('42dbb0b7-6941-4ab1-8b4d-8d53c11107e3','上元觀燈','胡仲弓','宋','宋诗','song-poetry','','[]','月掛牆頭楊柳枝，繁燈爛漫玉琉璃。',64,'全唐诗/poet.song.220000.json','["月掛牆頭楊柳枝，繁燈爛漫玉琉璃。", "綺羅盡學宮粧樣，歌舞休傳外國詞。", "滿路競看花灼灼，故京誰念黍離離。", "他年同侍傳柑宴，記取樓前擲果時。"]'),
('22104704-6152-46e2-9bff-f6c5a280494f','題溪亭','胡仲弓','宋','宋诗','song-poetry','','[]','借得溪亭一解衣，忘機燕子去來飛。',64,'全唐诗/poet.song.220000.json','["借得溪亭一解衣，忘機燕子去來飛。", "採桑女伴携籃過，罷釣兒郎蕩槳歸。", "嫩草正芳鵝鴨鬭，淺潮初落蟹魚肥。", "開門坐對真山水，不信人間有是非。"]'),
('1b644841-4ec9-42f2-b0ab-64d821ecf574','陳氏溪亭次韻','胡仲弓','宋','宋诗','song-poetry','','[]','溪亭鎮日著吟身，不浣衣中一點塵。',64,'全唐诗/poet.song.220000.json','["溪亭鎮日著吟身，不浣衣中一點塵。", "水比世間機巧者，山如前輩典刑人。", "喚回魂夢敲茶臼，費盡工夫整釣綸。", "時有野僧排闥至，炷香清坐話頭新。"]'),
('3068accd-2a94-411d-a631-7f61d89d870d','溪亭夜吟','胡仲弓','宋','宋诗','song-poetry','','[]','繫纜隄邊江水平，風來細細襲衣輕。',64,'全唐诗/poet.song.220000.json','["繫纜隄邊江水平，風來細細襲衣輕。", "淡烟幾抹沙痕暗，新月一鈎天際明。", "錦繡圍中搜野趣，笙歌叢裏和吟聲。", "酒闌不盡遲留意，後約須尋李杜盟。"]'),
('c9c8e69b-82f9-43ed-acf9-b5ed3a0550ec','元日','胡仲弓','宋','宋诗','song-poetry','','[]','元日山堂羅俎豆，潛知木主亦悲辛。',64,'全唐诗/poet.song.220000.json','["元日山堂羅俎豆，潛知木主亦悲辛。", "土瓜溪筍非鄉物，臠肉村醪擬降神。", "盡日閒門無賀客，侵晨官道有行人。", "喜將弟妹同漂梗，綵服團欒壽老親。"]'),
('5e447e5c-fb6f-4db6-97e9-e8efdf2b87f7','題桃源圖  其一','胡仲弓','宋','宋诗','song-poetry','','[]','桃溪春水綠如苔，溪上紅桃夾岸開。',64,'全唐诗/poet.song.220000.json','["桃溪春水綠如苔，溪上紅桃夾岸開。", "乳燕掠將芳草去，子魚銜出落花來。", "田中黍稷隨時藝，雨後桑麻繞舍栽。", "此日逢人休問語，生涯聞已半蒿萊。"]'),
('59b03922-3076-4880-8cc3-cd577f3dfe8b','題桃源圖  其二','胡仲弓','宋','宋诗','song-poetry','','[]','圖中想像晉桃源，問著桃源不敢言。',64,'全唐诗/poet.song.220000.json','["圖中想像晉桃源，問著桃源不敢言。", "只道亂來無境土，誰知靜裏有乾坤。", "年深莫辨烟霞迹，洞古猶粘苔蘚痕。", "吟杖懶隨劉阮去，漫尋春色到柴門。"]'),
('d1e83363-d46b-45a4-b72a-e128bf11ac95','題窗間墨竹','胡仲弓','宋','宋诗','song-poetry','','[]','一寸毛錐當小鉏，新篁移傍野人居。',64,'全唐诗/poet.song.220000.json','["一寸毛錐當小鉏，新篁移傍野人居。", "難棲天上鳴陽鳳，且伴窗前剔蠹魚。", "大節肯隨風俯仰，數枝長带月扶疎。", "此君本是虛心物，那更形聲總是虛。"]'),
('2789d8ba-8530-4123-98e5-1099b9f92fb1','走筆和法石紀遊','胡仲弓','宋','宋诗','song-poetry','','[]','贏得工夫卧看山，山中地步較來寬。',64,'全唐诗/poet.song.220000.json','["贏得工夫卧看山，山中地步較來寬。", "苛留一段乾坤在，耐過幾番風雨寒。", "吟思正濃頻掃石，醉眸未豁且觀瀾。", "連鼇已落高人手，却是漁家欠巨竿。"]'),
('9dd3b702-f97a-4d02-bb21-c89b22375d51','訪枯崖不遇','胡仲弓','宋','宋诗','song-poetry','','[]','踏破門前苔蘚斑，尋曦不值只空還。',64,'全唐诗/poet.song.220000.json','["踏破門前苔蘚斑，尋曦不值只空還。", "行雲過處青山濕，野水明邊白鳥閒。", "捫蝨有人談古道，揮蠅無路透禪關。", "杖藜獨背西風去，偶見蒼官亦厚顔。"]'),
('b2bc8b31-1792-4ee3-b4ba-9b24831ce9ca','哭杜立齋先生','胡仲弓','宋','宋诗','song-poetry','','[]','鳳鳥纔看刷羽儀，胡爲遽報哲人萎。',64,'全唐诗/poet.song.220000.json','["鳳鳥纔看刷羽儀，胡爲遽報哲人萎。", "可憐如晦遄歸日，不及唐朝既效時。", "善類固知難著脚，小人未可便揚眉。", "老天欲壽斯文脈，後死當爲繼絕思。"]'),
('4ee17e0c-ecad-427f-a11b-29d18b7714bb','哭趙吏部','胡仲弓','宋','宋诗','song-poetry','','[]','篇詩曾送恥齋行，豈料存亡隔此生。',64,'全唐诗/poet.song.220000.json','["篇詩曾送恥齋行，豈料存亡隔此生。", "早控危衷敷鯁論，晚留遺愛在羊城。", "惜無金輅封同姓，空有玉棺歸九京。", "篋笥舊藏君雜藁，令人一讀一傷情。"]'),
('98ced1c7-5247-4679-8ddb-e3282440857a','次郭吉甫梅仙之官廣右','胡仲弓','宋','宋诗','song-poetry','','[]','路入天南更向西，春風匹馬赴瓜期。',64,'全唐诗/poet.song.220000.json','["路入天南更向西，春風匹馬赴瓜期。", "折將官柳送行客，歸及山梅結果時。", "池上鳳凰身未到，灘頭鸂鶒事先知。", "徐君曾下陳蕃榻，况是林宗早見推。"]'),
('42ad1c9a-0828-4967-9265-0152fe9199c7','和止泓姜秦祠韻','胡仲弓','宋','宋诗','song-poetry','','[]','九日山頭兩徑深，不同出處却同心。',64,'全唐诗/poet.song.220000.json','["九日山頭兩徑深，不同出處却同心。", "喚回浮世夢中夢，來向先生吟處吟。", "別駕堂空遺影在，隠君亭破野藤侵。", "古今陳迹休深問，且把寒泉當酒斟。"]'),
('5fb5a75b-2d18-494e-bf32-ef877fd3dbb3','西塔','胡仲弓','宋','宋诗','song-poetry','','[]','杖策來尋塔廟仙，半程便到碧霄邊。',64,'全唐诗/poet.song.220000.json','["杖策來尋塔廟仙，半程便到碧霄邊。", "三千世界浮塵外，百二山河在眼前。", "誰把孤標長插地，只消一柱可擎天。", "夜闌籟靜凭欄聽，隠隠星河人扣舷。"]'),
('8b932d9c-4d87-4b53-ba4c-9a8d0e865d0e','次韻答王東墅','胡仲弓','宋','宋诗','song-poetry','','[]','元龍湖海分棲遲，懶把琴心累子期。',64,'全唐诗/poet.song.220000.json','["元龍湖海分棲遲，懶把琴心累子期。", "不是三生曾有舊，如何一見便論詩。", "春行谷外鶑求友，月在吟邊鵲繞枝。", "甚欲買舟尋隠處，悔將名姓與人知。"]'),
('74d12394-e824-41ec-a4b8-ba2f2ab71a8e','答頤齋詩筒走寄  其一','胡仲弓','宋','宋诗','song-poetry','','[]','纔聽簷花點滴聲，錦囊入手便欣情。',64,'全唐诗/poet.song.220000.json','["纔聽簷花點滴聲，錦囊入手便欣情。", "啼乾杜宇春言別，賦到牡丹詩改盟。", "洗滌愁腸憑酒遣，揄揚心事借琴鳴。", "詰朝紫翠欄邊約，喜有溪毛可絮羹。"]'),
('22b18fcc-88b9-40ac-9acf-588bcec4dbdc','答頤齋詩筒走寄  其二','胡仲弓','宋','宋诗','song-poetry','','[]','剪燭西窗聽雨聲，曉天又弄半陰晴。',64,'全唐诗/poet.song.220000.json','["剪燭西窗聽雨聲，曉天又弄半陰晴。", "黄金塢裏知無分，紫翠樓前忍負盟。", "君有磚花占日影，我慚瓦釜答雷鳴。", "今朝茹素無清供，喜得鄰分玉版羹。"]'),
('2e6dd4b6-1465-412a-a76d-102884fada17','答頤齋詩筒走寄  其三','胡仲弓','宋','宋诗','song-poetry','','[]','綠陰團裏和吟聲，幽事相關雨未晴。',64,'全唐诗/poet.song.220000.json','["綠陰團裏和吟聲，幽事相關雨未晴。", "莫把越秦分異見，要知李杜是同盟。", "提壺沽酒牆頭報，布穀催耕屋背鳴。", "滿目雲山猶好在，何時鷄黍薦藜羹。"]'),
('cc5e65f4-01e9-4ebb-9651-d7c3bb592c76','春日','胡仲弓','宋','宋诗','song-poetry','','[]','春事都無十日留，何妨款段出城遊。',64,'全唐诗/poet.song.220000.json','["春事都無十日留，何妨款段出城遊。", "榴花不入詩人眼，柳絮偏供客子愁。", "枝上五禽言似訴，籠中二鼠去如流。", "斜風細雨湖山路，一片花飛人倚樓。"]'),
('1d0c89a0-54be-41d1-8bbc-afdae2c0584b','餞儲秀野赴廣西制司參議','胡仲弓','宋','宋诗','song-poetry','','[]','時艱急似救頭燃，快趁春風著一鞭。',64,'全唐诗/poet.song.220000.json','["時艱急似救頭燃，快趁春風著一鞭。", "人道輕車諳路熟，我疑重閫得君賢。", "狨衣便带楊花雪，鶴骨猶勝桂嶺烟。", "兵畫近來無可議，只消買靜向南邊。"]'),
('9b644fb9-1217-48e8-8193-14bf9e57b219','次傅德用府教授韻','胡仲弓','宋','宋诗','song-poetry','','[]','一握乾坤盡在望，江山好處即家鄉。',64,'全唐诗/poet.song.220000.json','["一握乾坤盡在望，江山好處即家鄉。", "古今萬事雲來去，身世百年亭短長。", "夢裏有時曾化蝶，吟邊得意亦亡羊。", "是非寵辱渾閒事，付與天公爲較量。"]'),
('54937cbe-bf01-4cdb-b3d7-77ee7689dfd7','送呂時可監丞朝假歸里','胡仲弓','宋','宋诗','song-poetry','','[]','局面新更著數寬，如何國手要投閒。',64,'全唐诗/poet.song.220000.json','["局面新更著數寬，如何國手要投閒。", "逆知後日清流禍，厭作中朝時樣官。", "兄弟真情求去易，君臣大義學來難。", "玉音不許違三月，此意應須反覆看。"]'),
('0ba6c439-446c-49e0-81c9-d4d3e1a7b8c1','次雪舟進退韻','胡仲弓','宋','宋诗','song-poetry','','[]','誰肯因貧賣寶刀，半生湖海分蹉跎。',64,'全唐诗/poet.song.220000.json','["誰肯因貧賣寶刀，半生湖海分蹉跎。", "春回池草吟魂覺，月在梅花瘦影高。", "旅况又隨年事長，交情偏耐歲寒多。", "項斯標格逢人說，讀到新詩語更騷。"]'),
('5b7fae0f-f511-4ffb-ba14-4abaec03630b','霸王廟','胡仲弓','宋','宋诗','song-poetry','','[]','慄悍攻城大不仁，拔山力盡誤終身。',64,'全唐诗/poet.song.220000.json','["慄悍攻城大不仁，拔山力盡誤終身。", "當初不學古兵法，到了翻成霸罪人。", "未造漢時知有漢，豈堪秦後又生秦。", "咄嗟氣象今何在，千古空留土木神。"]'),
('4c4e86b8-199f-49d7-8704-1478471877d1','張巡廟','胡仲弓','宋','宋诗','song-poetry','','[]','說著睢陽膽已傾，單師曾此控孤城。',64,'全唐诗/poet.song.220000.json','["說著睢陽膽已傾，單師曾此控孤城。", "一身肯作偷生計，千古長留不死名。", "廟饗毋忘艱食日，庭松猶學戰時聲。", "祠前碑記無尋處，頼有唐書爲發明。"]'),
('046ea5c1-b414-40b9-be6f-ac4aaa070597','雪磴','胡仲弓','宋','宋诗','song-poetry','','[]','石磴不可攀，前頭有積雪。',24,'全唐诗/poet.song.220000.json','["石磴不可攀，前頭有積雪。", "安得冰玉人，對此清高節。"]'),
('4d1d50b3-1209-4728-bf49-0bb064a54c42','曉枕聽禽言','胡仲弓','宋','宋诗','song-poetry','','[]','山鳥不知名，窗前作意鳴。',24,'全唐诗/poet.song.220000.json','["山鳥不知名，窗前作意鳴。", "自言還自答，終始一般聲。"]'),
('6b9c88c9-4622-417f-bb40-8ce5f238a498','皆春','胡仲弓','宋','宋诗','song-poetry','','[]','黄鐘一萌動，物物皆陽春。',24,'全唐诗/poet.song.220000.json','["黄鐘一萌動，物物皆陽春。", "天地妙橐籥，滿腔都是仁。"]'),
('875af877-224a-4bf8-a050-d639706415b2','意亭','胡仲弓','宋','宋诗','song-poetry','','[]','主人心地闊，以意名其亭。',24,'全唐诗/poet.song.220000.json','["主人心地闊，以意名其亭。", "長携一樽酒，坐對前山青。"]'),
('9aef3fd9-fc4a-4d70-84d1-6cf687809840','題野雲庵','胡仲弓','宋','宋诗','song-poetry','','[]','庵中有高人，不受紅塵觸。',24,'全唐诗/poet.song.220000.json','["庵中有高人，不受紅塵觸。", "吟詩每夜深，來伴山雲宿。"]'),
('699d33b7-6b6d-4a6d-91b6-9f26d75a63b5','適吾意','胡仲弓','宋','宋诗','song-poetry','','[]','嘲風詠月天，問花尋柳地。',24,'全唐诗/poet.song.220000.json','["嘲風詠月天，問花尋柳地。", "隨遇可行樂，但欲適吾意。"]'),
('4bfda10d-5fdf-4cc1-9c9d-4c2b2e1154f1','題陳希夷睡圖','胡仲弓','宋','宋诗','song-poetry','','[]','形睡神非睡，心閒身亦閒。',24,'全唐诗/poet.song.220000.json','["形睡神非睡，心閒身亦閒。", "是非都不管，高卧華州山。"]'),
('ae58e05d-9316-494d-a191-85407ed5191e','山館對月','胡仲弓','宋','宋诗','song-poetry','','[]','山寺聞晨鐘，深省靜中發。',24,'全唐诗/poet.song.220000.json','["山寺聞晨鐘，深省靜中發。", "展轉睡不成，推窗看明月。"]'),
('cbbbd969-5b45-4dae-bc54-e060d45ed0b9','雲思','胡仲弓','宋','宋诗','song-poetry','','[]','出岫本無心，雲在意亦在。',24,'全唐诗/poet.song.220000.json','["出岫本無心，雲在意亦在。", "松檜無高枝，舒卷何所礙。"]'),
('cfb2478a-4277-4837-836e-bc18d77e06b2','詠松  其一','胡仲弓','宋','宋诗','song-poetry','','[]','獨抱歲寒心，不知時有四。',24,'全唐诗/poet.song.220000.json','["獨抱歲寒心，不知時有四。", "赤日行炎天，林下自秋至。"]'),
('a98ed49c-55fe-41a0-a4d0-ad3293a69b07','詠松  其二','胡仲弓','宋','宋诗','song-poetry','','[]','凉飈起深谷，清影摇空山。',24,'全唐诗/poet.song.220000.json','["凉飈起深谷，清影摇空山。", "醉眠石上人，夢中度百灘。"]'),
('555be82b-3d69-470d-96d6-47b3dfb01029','詠松  其三','胡仲弓','宋','宋诗','song-poetry','','[]','林高動輕籟，雲靜天無風。',24,'全唐诗/poet.song.220000.json','["林高動輕籟，雲靜天無風。", "縹緲笙鶴下，依稀鸞佩逢。"]'),
('5c2e27be-196f-4cf2-a248-50051384b45e','詠松  其四','胡仲弓','宋','宋诗','song-poetry','','[]','蕭蕭琴瑟鳴，灑灑霜露下。',24,'全唐诗/poet.song.220000.json','["蕭蕭琴瑟鳴，灑灑霜露下。", "願期素心人，同遊明月夜。"]'),
('e9d0de68-4ecb-4d1f-bba5-84320fae1529','詠松  其五','胡仲弓','宋','宋诗','song-poetry','','[]','高風過巖麓，林杪撼潮海。',24,'全唐诗/poet.song.220000.json','["高風過巖麓，林杪撼潮海。", "滿地落松花，杖履襲清靄。"]'),
('e1ca3fac-ccd5-4d0c-9ce6-fa9ac0143210','詠松  其六','胡仲弓','宋','宋诗','song-poetry','','[]','潜心寫幽韻，洗耳聽寒濤。',24,'全唐诗/poet.song.220000.json','["潜心寫幽韻，洗耳聽寒濤。", "吟聲自摇動，誤疑泛魚舠。"]'),
('4cac6958-538f-4744-8dd5-a652e79b0216','詠松  其七','胡仲弓','宋','宋诗','song-poetry','','[]','老枝髯鬣動，古幹鱗甲翻。',24,'全唐诗/poet.song.220000.json','["老枝髯鬣動，古幹鱗甲翻。", "積陰生潤氣，芳菲翳蘭蓀。"]'),
('7f3996ae-8d0b-4428-9cb6-4e1082aee70b','春詠','胡仲弓','宋','宋诗','song-poetry','','[]','沂水樂吾道，蘭亭敘幽情。',24,'全唐诗/poet.song.220000.json','["沂水樂吾道，蘭亭敘幽情。", "古人不復作，四海無吟聲。"]'),
('5ec6c006-7d69-4c42-9ccc-df4f7e32055c','耕釣境','胡仲弓','宋','宋诗','song-poetry','','[]','莘野特浪耕，璜溪豈真釣。',24,'全唐诗/poet.song.220000.json','["莘野特浪耕，璜溪豈真釣。", "珍重富春翁，此境最高妙。"]'),
('443d2b60-bd99-4600-8e0e-00cb61996318','用烏山韻題碧吟卷','胡仲弓','宋','宋诗','song-poetry','','[]','湖海元龍氣，因吟恐負身。',24,'全唐诗/poet.song.220000.json','["湖海元龍氣，因吟恐負身。", "世間無謁客，天下有詩人。"]'),
('3a975b04-fd65-4326-934a-cc20d7b0423d','梅','胡仲弓','宋','宋诗','song-poetry','','[]','天地有生意，驗之陽氣回。',24,'全唐诗/poet.song.220000.json','["天地有生意，驗之陽氣回。", "所以霜雪中，春風先及梅。"]'),
('6a9b7122-cd12-4715-9999-c5d8b81b5d48','溪亭夜集走筆','胡仲弓','宋','宋诗','song-poetry','','[]','倚柱看潮生，漁歌靜中發。',24,'全唐诗/poet.song.220000.json','["倚柱看潮生，漁歌靜中發。", "吟罷寂無聲，江風對山月。"]'),
('e234f466-b68e-48e2-9ae2-eae003dea93c','次松坡梅花韻','胡仲弓','宋','宋诗','song-poetry','','[]','滿樹苔痕带老蒼，水邊籬落月昏黄。',32,'全唐诗/poet.song.220000.json','["滿樹苔痕带老蒼，水邊籬落月昏黄。", "丁寧僮子休教折，只聽枝頭獨自香。"]'),
('bd4701f2-fcdc-4322-b47b-3e03a23f754a','寄越友','胡仲弓','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u897f\u6e56"]','偶向津頭買釣蓑，懷人只隔一煙波。',32,'全唐诗/poet.song.220000.json','["偶向津頭買釣蓑，懷人只隔一煙波。", "扁舟欲渡長江去，奈此西湖明月何。"]'),
('5d38d7ca-5dbf-42f1-b8db-86ec756af234','寄楊藴古','胡仲弓','宋','宋诗','song-poetry','','[]','匹馬遊邊已千里，如何未奏凱歌聲。',32,'全唐诗/poet.song.220000.json','["匹馬遊邊已千里，如何未奏凱歌聲。", "太平不用干戈策，辜負胸中百萬兵。"]'),
('c6ccb191-70fd-4096-b86a-a55239aea465','題武適安寧卷','胡仲弓','宋','宋诗','song-poetry','','[]','聽琴未了聽吟聲，瀉出冰壺一片清。',32,'全唐诗/poet.song.220000.json','["聽琴未了聽吟聲，瀉出冰壺一片清。", "學到唐人超絕處，前身便是武元衡。"]'),
('a536511a-8bfd-4d09-a340-367d73fcc876','問梅','胡仲弓','宋','宋诗','song-poetry','','[]','費盡工夫點綴春，暗香動處少人聞。',32,'全唐诗/poet.song.220000.json','["費盡工夫點綴春，暗香動處少人聞。", "近來宮樣梳粧巧，只要明珠不要君。"]'),
('24eaf84d-f8fa-4c2f-a986-7abeef028dbf','孤山問梅','胡仲弓','宋','宋诗','song-poetry','','[]','每到山邊與水邊，有梅花處憶逋仙。',32,'全唐诗/poet.song.220000.json','["每到山邊與水邊，有梅花處憶逋仙。", "湖光清淺黄昏月，招得先生在眼前。"]'),
('1d51e003-ff3d-4050-a7d5-f8a72e9ccc7a','用韻答寶葉','胡仲弓','宋','宋诗','song-poetry','','[]','蒲團出定入玄微，盡是山間林下詩。',32,'全唐诗/poet.song.220000.json','["蒲團出定入玄微，盡是山間林下詩。", "安得遠公陪一笑，朗吟同過虎溪時。"]'),
('54ee1a60-d2ce-4e4c-8b69-d09fe086e56a','客星閣  其一','胡仲弓','宋','宋诗','song-poetry','','[]','太史當年奏客星，知君心事未全清。',32,'全唐诗/poet.song.220000.json','["太史當年奏客星，知君心事未全清。", "富春果是真謀隠，千古何人識姓名。"]'),
('65ddbbcc-42ff-4808-af5b-b851632d99da','客星閣  其二','胡仲弓','宋','宋诗','song-poetry','','[]','莫題詩句累先生，將謂先生亦釣名。',32,'全唐诗/poet.song.220000.json','["莫題詩句累先生，將謂先生亦釣名。", "說與往來臺下客，可移一語贈玄英。"]'),
('af1d6b17-27e6-45e3-9c73-fc8ea5449c59','省墳','胡仲弓','宋','宋诗','song-poetry','','[]','紙灰飛作滿山塵，倚遍靈丘暗愴神。',32,'全唐诗/poet.song.220000.json','["紙灰飛作滿山塵，倚遍靈丘暗愴神。", "日暮歸來殽核盡，松陰猶有乞墦人。"]'),
('642375d1-b252-47dc-b3e5-c6e42c8de5c7','梅花盛開有粉蝶衝寒而至','胡仲弓','宋','宋诗','song-poetry','','[]','翩翩拍舞下瑶階，知是東君間諜來。',32,'全唐诗/poet.song.220000.json','["翩翩拍舞下瑶階，知是東君間諜來。", "深入粉香人不見，花心摇落却飛回。"]'),
('e887c413-05fd-43a5-8fb0-ea468e3fc736','湖邊','胡仲弓','宋','宋诗','song-poetry','','[]','湖邊春色濃於酒，醉盡東西南北人。',32,'全唐诗/poet.song.220000.json','["湖邊春色濃於酒，醉盡東西南北人。", "獨有詩翁清到底，一生醒眼看青春。"]'),
('ab334bdb-b8e0-4218-bc16-a29dc75f8d58','斷橋觀釣','胡仲弓','宋','宋诗','song-poetry','','[]','一竿明月一絲風，心在煙波渺渺中。',32,'全唐诗/poet.song.220000.json','["一竿明月一絲風，心在煙波渺渺中。", "浮世只消如此過，何因得似釣魚翁。"]'),
('a21c2136-b0e1-439f-9912-4843a80a13c1','贈易數朱俊甫','胡仲弓','宋','宋诗','song-poetry','','[]','三絕韋編及太玄，潛虛象數究先天。',32,'全唐诗/poet.song.220000.json','["三絕韋編及太玄，潛虛象數究先天。", "前人推算空勞力，不似而今賣得錢。"]'),
('f8e3eda7-d01b-4338-b87c-3947b41453f1','早行','胡仲弓','宋','宋诗','song-poetry','','[]','曙色微分星漸稀，迎人犬吠出疎籬。',32,'全唐诗/poet.song.220000.json','["曙色微分星漸稀，迎人犬吠出疎籬。", "輕車穩坐誰知我，不是坡翁戴笠時。"]'),
('c45c7694-1408-4b1b-9c41-e9fa47d7b37c','曉來','胡仲弓','宋','宋诗','song-poetry','','[]','曉來對雪看唐詩，自暖茅柴酒一巵。',32,'全唐诗/poet.song.220000.json','["曉來對雪看唐詩，自暖茅柴酒一巵。", "絕勝五陵貴公子，銷金帳下飲羔兒。"]'),
('bcef914c-7bf4-415e-901d-ba9e08bf2c01','贈岳仁叔','胡仲弓','宋','宋诗','song-poetry','','[]','不學弓刀破敵圍，却拈刀筆學兒嬉。',32,'全唐诗/poet.song.220000.json','["不學弓刀破敵圍，却拈刀筆學兒嬉。", "世間多少真豪傑，飄落江湖人不知。"]'),
('f6209510-db69-4fed-8909-e328e13755cf','贈鄭琰','胡仲弓','宋','宋诗','song-poetry','','[]','狂風吹覆鳳凰巢，鴞鬼朝翔狐夜號。',32,'全唐诗/poet.song.220000.json','["狂風吹覆鳳凰巢，鴞鬼朝翔狐夜號。", "君有胸中千古鑑，世間妍醜想難逃。"]'),
('f1323c90-b2cf-406b-95be-8ce15f48a43d','九日雨','胡仲弓','宋','宋诗','song-poetry','','[]','避災野老尋蓑笠，送酒人來白衣濕。',32,'全唐诗/poet.song.220000.json','["避災野老尋蓑笠，送酒人來白衣濕。", "龍山路滑少人登，籬下菊花含淚泣。"]'),
('0dee89f9-2d22-490c-b7be-8e1e394a2977','春雨中遣懷二首柬梅臞  其一','胡仲弓','宋','宋诗','song-poetry','','[]','滿園桃李漸成莎，爲甚東君氣未和。',32,'全唐诗/poet.song.220000.json','["滿園桃李漸成莎，爲甚東君氣未和。", "莫是陽臺貪作夢，晴時常少雨常多。"]'),
('99f74d75-e637-4d5e-855c-f792e0f443f4','春雨中遣懷二首柬梅臞  其二','胡仲弓','宋','宋诗','song-poetry','','[]','蠟屐登山訪草亭，前山未放十分青。',32,'全唐诗/poet.song.220000.json','["蠟屐登山訪草亭，前山未放十分青。", "清明此去無多日，不信老天長晦冥。"]'),
('b33533e2-9d99-45e7-b185-89070f566d61','訪戴鍊師不值  其一','胡仲弓','宋','宋诗','song-poetry','','[]','雲淡風輕欲暮時，艤舟獨載剡溪湄。',32,'全唐诗/poet.song.220000.json','["雲淡風輕欲暮時，艤舟獨載剡溪湄。", "及門若遇戴安道，千古何人更有詩。"]'),
('7e46bace-3e4f-44b1-a2b5-4872ac4909d1','訪戴鍊師不值  其二','胡仲弓','宋','宋诗','song-poetry','','[]','數間茅屋柳成陰，中有幽人抱一琴。',32,'全唐诗/poet.song.220000.json','["數間茅屋柳成陰，中有幽人抱一琴。", "欲訪桃谿無覓處，桃谿更在白雲深。"]'),
('fdcec869-7fcb-4398-8fd6-d78fc6a9e16d','郊外即事  其一','胡仲弓','宋','宋诗','song-poetry','','[]','蹇馿逐逐背斜陽，纔到山間意便凉。',32,'全唐诗/poet.song.220000.json','["蹇馿逐逐背斜陽，纔到山間意便凉。", "勿聽鷓鴣行不得，雲山深處路尤長。"]'),
('04cdaca1-aad7-49e1-854d-160bf94f026f','郊外即事  其二','胡仲弓','宋','宋诗','song-poetry','','[]','林密深藏三四家，隔牆古柳著棲鴉。',32,'全唐诗/poet.song.220000.json','["林密深藏三四家，隔牆古柳著棲鴉。", "牧童兩兩眠芳草，不管羣牛食豆花。"]'),
('9f3816b0-dde2-4f0d-9b50-e4244b10718b','觀海','胡仲弓','宋','宋诗','song-poetry','','[]','海天雲氣入微茫，遥認潮頭數點檣。',32,'全唐诗/poet.song.220000.json','["海天雲氣入微茫，遥認潮頭數點檣。", "眼界只消如許闊，不知何處是東洋。"]'),
('572dab9a-a822-4b85-aad2-55fb3132fe94','即席次韻  其一','胡仲弓','宋','宋诗','song-poetry','','[]','前山雨過碧紋凹，領客携樽出近郊。',32,'全唐诗/poet.song.220000.json','["前山雨過碧紋凹，領客携樽出近郊。", "花壓重城歸去晚，一窗風月恣推敲。"]'),
('791cd0d0-128e-45d6-a8c2-610e1c251108','即席次韻  其二','胡仲弓','宋','宋诗','song-poetry','','[]','倚著欄干句便豪，我來登覽奈愁何。',32,'全唐诗/poet.song.220000.json','["倚著欄干句便豪，我來登覽奈愁何。", "山河一半無收拾，却道東南景最多。"]'),
('0b4db9e2-f0b2-400d-a5ef-6527addeb316','和趙同叔見寄韻  其一','胡仲弓','宋','宋诗','song-poetry','','[]','湖海歸來世念輕，短篷終日載吟聲。',32,'全唐诗/poet.song.220000.json','["湖海歸來世念輕，短篷終日載吟聲。", "天風約住雲來往，萬里長空一雁橫。"]'),
('449d9d74-3069-4818-a454-481f76b5795b','和趙同叔見寄韻  其二','胡仲弓','宋','宋诗','song-poetry','','[]','滿園桃李手親栽，治世何嘗棄不材。',32,'全唐诗/poet.song.220000.json','["滿園桃李手親栽，治世何嘗棄不材。", "可恨天南流落客，九霄雨露不曾來。"]'),
('f50187d9-5e95-4b8d-9079-114d30af27c8','和趙同叔見寄韻  其三','胡仲弓','宋','宋诗','song-poetry','','[]','星星吟鬢已成翁，萬斛塵埃一笑空。',32,'全唐诗/poet.song.220000.json','["星星吟鬢已成翁，萬斛塵埃一笑空。", "自是黄花留晚節，肯將顦顇怨西風。"]'),
('6e78fee4-49cb-48fd-8b6e-710890556bf5','次韻早梅','胡仲弓','宋','宋诗','song-poetry','','[]','枝頭未受雪霜催，偏傍江南暖處開。',32,'全唐诗/poet.song.220000.json','["枝頭未受雪霜催，偏傍江南暖處開。", "不是東君私造物，有何憑據作花魁。"]'),
('38e378d1-0efc-482c-9efb-c6b649eebffe','遊瑞源訪修上人','胡仲弓','宋','宋诗','song-poetry','','[]','羨師儘得山林趣，顧我初無朝市心。',32,'全唐诗/poet.song.220000.json','["羨師儘得山林趣，顧我初無朝市心。", "欲把山林換朝市，市朝未必似山林。"]'),
('7797bd1e-d9da-4c75-b714-2901b1c6e41f','題寶葉笑端','胡仲弓','宋','宋诗','song-poetry','','[]','碧潭秋月句尤奇，繫竹拈花總是詩。',32,'全唐诗/poet.song.220000.json','["碧潭秋月句尤奇，繫竹拈花總是詩。", "說著推敲便堪笑，問師端的笑何時。"]'),
('51598b0f-25ad-4532-9f3f-76ac0a535d51','與枯崖悟師','胡仲弓','宋','宋诗','song-poetry','','[]','振錫歸來又許時，苔痕猶汙坐禪衣。',32,'全唐诗/poet.song.220000.json','["振錫歸來又許時，苔痕猶汙坐禪衣。", "是非不定空懷古，慚愧高人蚤見幾。"]'),
('c1a63eae-f808-4560-848e-8907d1c38cf0','月臨關','胡仲弓','宋','宋诗','song-poetry','','[]','長笛一聲天地寒，不堪回首月臨關。',32,'全唐诗/poet.song.220000.json','["長笛一聲天地寒，不堪回首月臨關。", "山河不二無全影，莫說前頭桂可攀。"]'),
('7717ea54-b082-44e4-b532-1a0743da57b6','答林顓民','胡仲弓','宋','宋诗','song-poetry','','[]','鏌鋣如此甘埋光，猶向牖下尋筆床。',32,'全唐诗/poet.song.220000.json','["鏌鋣如此甘埋光，猶向牖下尋筆床。", "轅駒局促不千里，堂堂七尺空爾長。"]'),
('feecfbc3-6397-4f7a-b887-2e8d65207729','野燒','胡仲弓','宋','宋诗','song-poetry','','[]','朝見樵人縱斧斤，暮看野火擁紅雲。',32,'全唐诗/poet.song.220000.json','["朝見樵人縱斧斤，暮看野火擁紅雲。", "棘叢怕有芝蘭種，莫把芝蘭一例焚。"]'),
('4e347a34-740e-4bf3-a1f2-ce4083806103','不礙雲山','胡仲弓','宋','宋诗','song-poetry','','[]','贏得工夫看好山，吟魂飛不到人間。',32,'全唐诗/poet.song.220000.json','["贏得工夫看好山，吟魂飛不到人間。", "白雲本是無心物，纔得身高便可攀。"]'),
('36d4ec31-c52a-4e5c-bc13-18bd94c993a1','題勞勞亭','胡仲弓','宋','宋诗','song-poetry','','[]','流水無情去不還，白楊青草滿前山。',32,'全唐诗/poet.song.220000.json','["流水無情去不還，白楊青草滿前山。", "古今多少興亡事，人自勞勞亭自閒。"]'),
('50e74994-0e77-4ceb-aab7-e1942f14cb26','楊仲仁爲梅返魂有詩因次其韻  其一','胡仲弓','宋','宋诗','song-poetry','','[]','窗草不除生意足，朋谿瓶梅今似之。',32,'全唐诗/poet.song.220000.json','["窗草不除生意足，朋谿瓶梅今似之。", "噓枯苟得一援手，寒暖不問南北枝。"]'),
('42b2f32a-d9ec-4698-8d7c-0c9911fa4ae2','楊仲仁爲梅返魂有詩因次其韻  其二','胡仲弓','宋','宋诗','song-poetry','','[]','謝娥羌管徒浪說，東君造化何容私。',32,'全唐诗/poet.song.220000.json','["謝娥羌管徒浪說，東君造化何容私。", "更得孤根有所托，終有結果調羹時。"]'),
('94f3ef09-d048-42e8-bdb5-5605554c14e7','久雨','胡仲弓','宋','宋诗','song-poetry','','[]','桑田萬頃變滄海，四海茫茫不見津。',32,'全唐诗/poet.song.220000.json','["桑田萬頃變滄海，四海茫茫不見津。", "天漏祗今無補處，不知誰是作霖人。"]'),
('f66d3324-18cc-4679-98c9-910d593d5589','山中逢老人','胡仲弓','宋','宋诗','song-poetry','','[]','頭白不知今幾齡，兒時猶及見昇平。',32,'全唐诗/poet.song.220000.json','["頭白不知今幾齡，兒時猶及見昇平。", "可憐野老無知識，却認錢塘是汴京。"]'),
('fd266292-57b4-4339-88c7-e1b62bf3365a','世路','胡仲弓','宋','宋诗','song-poetry','','[]','春山寂寂鎖雲蘿，林外鉤輈聲最多。',32,'全唐诗/poet.song.220000.json','["春山寂寂鎖雲蘿，林外鉤輈聲最多。", "不是哥哥行不得，祇愁世路有風波。"]'),
('2ae29f26-6521-4306-9f5a-4a260c67b9b0','趙庸齋爲程生作梅窗二字因爲之賦','胡仲弓','宋','宋诗','song-poetry','','[]','作賦何如宋廣平，吟詩誰是老逋清。',32,'全唐诗/poet.song.220000.json','["作賦何如宋廣平，吟詩誰是老逋清。", "庸翁不喜詩兼賦，寫與閒人作美名。"]'),
('90088701-8483-42fa-a11c-434467a686fe','題山居十絕 深省','胡仲弓','宋','宋诗','song-poetry','','[]','鯨音千里送驚濤，偏爲人間破睡魔。',32,'全唐诗/poet.song.220000.json','["鯨音千里送驚濤，偏爲人間破睡魔。", "待得耳根清靜後，覺來醒處已無多。"]'),
('6b454d18-565f-42bc-9041-291038e83d8a','題山居十絕 柳塘','胡仲弓','宋','宋诗','song-poetry','','[]','翠眉低拂效宮顰，近水亭臺剩得春。',32,'全唐诗/poet.song.220000.json','["翠眉低拂效宮顰，近水亭臺剩得春。", "千古淵明扶不起，一枝贈與折腰人。"]'),
('76704f85-7e27-475d-b4ce-1221393e115f','題山居十絕 寒巖','胡仲弓','宋','宋诗','song-poetry','','[]','境於勝處築新巖，中有仙翁換骨函。',32,'全唐诗/poet.song.220000.json','["境於勝處築新巖，中有仙翁換骨函。", "門戶本來無鎖鑰，白雲從此不須緘。"]'),
('027c8aeb-85fc-401e-8a30-209cf242db23','題山居十絕 掬清','胡仲弓','宋','宋诗','song-poetry','','[]','止水中間別有天，濯纓人去自清漣。',32,'全唐诗/poet.song.220000.json','["止水中間別有天，濯纓人去自清漣。", "明珠萬斛歸塵土，不及山中一掬泉。"]'),
('e0c35851-df7e-4164-9f6b-d3f9557b919c','題山居十絕 一線天','胡仲弓','宋','宋诗','song-poetry','','[]','許大乾坤滿世間，管窺蠡測已爲難。',32,'全唐诗/poet.song.220000.json','["許大乾坤滿世間，管窺蠡測已爲難。", "誰將一線通天竅，輸與高人著眼看。"]'),
('3ac98b50-3ee8-4572-aa9a-26cc64567e6d','題山居十絕 雲卧','胡仲弓','宋','宋诗','song-poetry','','[]','來尋高處卧吟身，泉石中間避世塵。',32,'全唐诗/poet.song.220000.json','["來尋高處卧吟身，泉石中間避世塵。", "莫把白雲都占斷，也分一半與閒人。"]'),
('3f8ea3ed-c652-4d2b-a07e-aeeb8bf785f5','題山居十絕 平遠','胡仲弓','宋','宋诗','song-poetry','','[]','萬里江山萬里天，沙平鴈落遠相連。',32,'全唐诗/poet.song.220000.json','["萬里江山萬里天，沙平鴈落遠相連。", "西風吹斷雲衣細，一葉飛來是釣船。"]'),
('a526b195-27da-45ef-8fb3-8c44d31cdb75','題山居十絕 跨鼇','胡仲弓','宋','宋诗','song-poetry','','[]','驚濤日夜戰喧豗，危甚瞿塘灧澦堆。',32,'全唐诗/poet.song.220000.json','["驚濤日夜戰喧豗，危甚瞿塘灧澦堆。", "穩把一竿臨碧水，三神山上釣鼇來。"]'),
('fbba59ae-d995-4b7f-9075-9b2e45381f90','題山居十絕 梅澗','胡仲弓','宋','宋诗','song-poetry','','[]','今昨孤山迥不同，逋仙誰與管春風。',32,'全唐诗/poet.song.220000.json','["今昨孤山迥不同，逋仙誰與管春風。", "暗香疎影無尋處，元在泠泠一澗中。"]'),
('d74403cc-264e-4a5d-83f6-ecce2290f63e','題山居十絕 極目','胡仲弓','宋','宋诗','song-poetry','','[]','萬仞崗頭著此身，乾坤圍裏盡紅塵。',32,'全唐诗/poet.song.220000.json','["萬仞崗頭著此身，乾坤圍裏盡紅塵。", "欲知山水有窮處，却是離婁看得真。"]'),
('51f797bd-08b6-4e62-8fd4-55e2d619339b','雜興','胡仲弓','宋','宋诗','song-poetry','','[]','蘇堤拍拍水平湖，誰信田間苗欲枯。',32,'全唐诗/poet.song.220000.json','["蘇堤拍拍水平湖，誰信田間苗欲枯。", "路上行人方苦熱，山中七月已圍爐。"]'),
('070d915b-7520-4bdf-b03b-97af91543ecb','晚春','胡仲弓','宋','宋诗','song-poetry','','[]','萬紅千紫已摧殘，留得荼䕷一架看。',32,'全唐诗/poet.song.220000.json','["萬紅千紫已摧殘，留得荼䕷一架看。", "燕子不知人意懶，飛來簾裏訴春寒。"]'),
('979d6477-de87-4363-9f07-8b1f3b93cf4c','芭蕉花','胡仲弓','宋','宋诗','song-poetry','','[]','綠蠟一株才吐焰，紅綃半卷漸抽花。',32,'全唐诗/poet.song.220000.json','["綠蠟一株才吐焰，紅綃半卷漸抽花。", "窗前映月人無寐，疑是銀燈透碧紗。"]'),
('08e61906-19f2-4486-9b7c-79a5fb645399','竹閣','胡仲弓','宋','宋诗','song-poetry','','[]','萬竿叢裏立嶆峨，葉葉清風受用多。',32,'全唐诗/poet.song.220000.json','["萬竿叢裏立嶆峨，葉葉清風受用多。", "見說香山老居士，夜深猶唱竹枝歌。"]'),
('78dd4c05-1692-428f-bad2-4e5c5760e75e','鳳凰臺','胡仲弓','宋','宋诗','song-poetry','','[]','臺上梧桐失舊栽，荒丘寂寂掩蒿萊。',32,'全唐诗/poet.song.220000.json','["臺上梧桐失舊栽，荒丘寂寂掩蒿萊。", "鳳凰一去不復返，引得鴟鴞向此來。"]'),
('01ce0abd-16be-4fcc-a256-0b67c7fd378e','題劉氏東陵圖','胡仲弓','宋','宋诗','song-poetry','','[]','昔日青門喜種瓜，尚遺種子在天涯。',32,'全唐诗/poet.song.220000.json','["昔日青門喜種瓜，尚遺種子在天涯。", "如今落在劉郎手，劉邵原來自一家。"]'),
('0d7fa87e-bb85-4f8c-bb14-6418a091dece','秣陵','胡仲弓','宋','宋诗','song-poetry','','[]','山自青青水自流，五雲猶繞帝王州。',32,'全唐诗/poet.song.220000.json','["山自青青水自流，五雲猶繞帝王州。", "誰將千幅鵝溪絹，畫出東南一片秋。"]'),
('614c0280-8280-4cc3-929a-c0e92bd321bf','夢中','胡仲弓','宋','宋诗','song-poetry','','[]','忽思十數年前事，只似今朝昨日間。',32,'全唐诗/poet.song.220000.json','["忽思十數年前事，只似今朝昨日間。", "堪歎夢中猶有夢，浮生能得幾時閒。"]'),
('760ee44a-c2e1-4ace-a043-35d41629d4a4','衆芳所','胡仲弓','宋','宋诗','song-poetry','','[]','接䍦倒著醉花傍，染得衣巾一味芳。',32,'全唐诗/poet.song.220000.json','["接䍦倒著醉花傍，染得衣巾一味芳。", "說與園丁嚴鎖鑰，免教韓壽去偷香。"]'),
('55450206-61fc-4b78-83dd-73e6a62bb8c2','端午','胡仲弓','宋','宋诗','song-poetry','','[]','畫舸縱橫湖水濱，綵絲角黍鬥時新。',32,'全唐诗/poet.song.220000.json','["畫舸縱橫湖水濱，綵絲角黍鬥時新。", "年年此日人皆醉，能弔醒魂有幾人。"]'),
('cb1d448d-e936-4484-b633-94d51bc100b8','竹塢','胡仲弓','宋','宋诗','song-poetry','','[]','洗竹可留三數竿，清風葉葉掃詩壇。',32,'全唐诗/poet.song.220000.json','["洗竹可留三數竿，清風葉葉掃詩壇。", "莫言此是藏春塢，也有虛心管歲寒。"]'),
('01a8ec4d-6d98-4726-8594-77f5b625c7d7','題楊妃上馬嬌圖','胡仲弓','宋','宋诗','song-poetry','','[]','並轡行春沉醉歸，侍兒扶上繡鞍來。',32,'全唐诗/poet.song.220000.json','["並轡行春沉醉歸，侍兒扶上繡鞍來。", "君王微笑回眸看，肯信嵬坡掩面時。"]'),
('bf15b660-3934-4e67-b3ff-d8fa26243905','曹娥廟','胡仲弓','宋','宋诗','song-poetry','','[]','黄絹碑殘香草生，當時淚眼不曾晴。',32,'全唐诗/poet.song.220000.json','["黄絹碑殘香草生，當時淚眼不曾晴。", "至今流水聲嗚咽，猶是曹娥哀怨聲。"]'),
('bc7cc152-1a81-47c8-936e-295d4b60825c','雨中看花','胡仲弓','宋','宋诗','song-poetry','','[]','頑雲癡雨霸春寒，李白桃紅總失歡。',32,'全唐诗/poet.song.220000.json','["頑雲癡雨霸春寒，李白桃紅總失歡。", "試問東君因底事，却來花上作艱難。"]'),
('925e1756-37e7-4eaa-a903-f68ccadcf511','瓊花','胡仲弓','宋','宋诗','song-poetry','','[]','潔白全無一點瑕，玉皇敕賜上皇家。',32,'全唐诗/poet.song.220000.json','["潔白全無一點瑕，玉皇敕賜上皇家。", "花神不敢輕分拆，天下應無第二花。"]'),
('3ad151f0-dc80-4242-8c0e-065bc6e88ecd','碁詩','胡仲弓','宋','宋诗','song-poetry','','[]','局面年來竟未安，一番下著一番難。',32,'全唐诗/poet.song.220000.json','["局面年來竟未安，一番下著一番難。", "祇今黑白無分別，輸與傍人袖手觀。"]'),
('f0ce47b0-e5c9-4e9b-980f-5d6daf37c020','寄意三絕  其一','胡仲弓','宋','宋诗','song-poetry','','[]','燕樓猶在月明中，還却明珠淚掩紅。',32,'全唐诗/poet.song.220000.json','["燕樓猶在月明中，還却明珠淚掩紅。", "青鳥不來雲路隔，碧桃無復舊春風。"]'),
('f60f8d30-81ce-418b-9ad3-9571352a5552','寄意三絕  其二','胡仲弓','宋','宋诗','song-poetry','','[]','塵滿胡床淚滿衣，深閨寂寂鎖相思。',32,'全唐诗/poet.song.220000.json','["塵滿胡床淚滿衣，深閨寂寂鎖相思。", "一春幽恨無人共，手撚梨花腸斷時。"]'),
('3121dee5-84ad-4995-adb0-bc93221b1607','寄意三絕  其三','胡仲弓','宋','宋诗','song-poetry','','[]','井底銀瓶事已非，鴛鴦打散鴨驚飛。',32,'全唐诗/poet.song.220000.json','["井底銀瓶事已非，鴛鴦打散鴨驚飛。", "千金莫試秋胡婦，持向青樓買笑歸。"]'),
('a42f3853-010e-4407-a4b2-117303427e1a','走筆次月夜頤齋見寄','胡仲弓','宋','宋诗','song-poetry','','[]','抱琴時作醉翁吟，吟罷霞觴對月斟。',32,'全唐诗/poet.song.220000.json','["抱琴時作醉翁吟，吟罷霞觴對月斟。", "客有可人期不至，相思隔斷暮雲深。"]'),
('91e470c8-6a78-4556-83ae-a6b0715e00f9','倚樓','胡仲弓','宋','宋诗','song-poetry','','[]','月明獨倚異鄉樓，北望天涯幾許愁。',32,'全唐诗/poet.song.220000.json','["月明獨倚異鄉樓，北望天涯幾許愁。", "故國不歸人意老，無情汴水自東流。"]'),
('de310957-580b-4381-8bd8-7372041e271b','聽竇圭琴','胡仲弓','宋','宋诗','song-poetry','','[]','指按金徽星斗寒，試聽一曲話悲歡。',32,'全唐诗/poet.song.220000.json','["指按金徽星斗寒，試聽一曲話悲歡。", "妙音怕入時人耳，携入白雲深處彈。"]'),
('c03f86cc-6721-46fc-85e5-f4c74a880039','元宵','胡仲弓','宋','宋诗','song-poetry','','[]','緩轡歸來看夜城，千門燈火照街明。',32,'全唐诗/poet.song.220000.json','["緩轡歸來看夜城，千門燈火照街明。", "自疑不是乘槎客，却傍銀河星斗行。"]'),
('b3365cd8-e6d6-4388-afbf-752816876289','太真卧病圖','胡仲弓','宋','宋诗','song-poetry','','[]','鬢蟬彫落柳眉顰，慚愧三郎不見嗔。',32,'全唐诗/poet.song.220000.json','["鬢蟬彫落柳眉顰，慚愧三郎不見嗔。", "一病早知尸解去，定無羅襪墮邊塵。"]'),
('fb610eb9-e9ef-4db6-ae4c-d706b0142d26','次枯崖問病韻','胡仲弓','宋','宋诗','song-poetry','','[]','病餘已覺二毛侵，湖海詩盟亦懶尋。',32,'全唐诗/poet.song.220000.json','["病餘已覺二毛侵，湖海詩盟亦懶尋。", "無奈壯懷生萬感，黄昏枕上聽蛩吟。"]'),
('bce82eb8-11ca-41f8-a99a-308f67dd2513','元日  其一','胡仲弓','宋','宋诗','song-poetry','','[]','大書春帖當桃符，吟對窗前梅一株。',32,'全唐诗/poet.song.220000.json','["大書春帖當桃符，吟對窗前梅一株。", "湖海相逢無老少，莫分先後飲屠蘇。"]'),
('1a8276c6-af12-48f2-88e9-e345e365f7de','元日  其二','胡仲弓','宋','宋诗','song-poetry','','[]','綠蠟紅紗滿路新，翠眉蟬鬢往來人。',32,'全唐诗/poet.song.220000.json','["綠蠟紅紗滿路新，翠眉蟬鬢往來人。", "榕陰門戶香如霧，十二天街無此春。"]'),
('ae469498-9f54-49d5-968c-a3dd8f9a6723','征人婦  其一','胡仲弓','宋','宋诗','song-poetry','','[]','候蟲唧唧話人愁，鎮日思君懶下樓。',32,'全唐诗/poet.song.220000.json','["候蟲唧唧話人愁，鎮日思君懶下樓。", "鴻鴈不來邊信隔，時憑乾鵲噪簷頭。"]'),
('358d2d3a-9114-4d83-bef5-3ace19964bd1','征人婦  其二','胡仲弓','宋','宋诗','song-poetry','','[]','西風吹老碧桐秋，因念征夫事遠遊。',32,'全唐诗/poet.song.220000.json','["西風吹老碧桐秋，因念征夫事遠遊。", "獨倚小樓重回首，飛來一葉是何舟。"]'),
('a4b8e639-7cc0-4bc9-86dd-cd4675f6228a','夜坐冥搜聞吟聲','胡仲弓','宋','宋诗','song-poetry','','[]','青燈耿耿透窗明，一字推敲睡不成。',32,'全唐诗/poet.song.220000.json','["青燈耿耿透窗明，一字推敲睡不成。", "只道衰翁自迂闊，隔樓亦有苦吟聲。"]'),
('aa84b5fa-b051-44cf-9007-9c9d71c3799e','南雪','胡仲弓','宋','宋诗','song-poetry','','[]','半生道路困風沙，冰雪駸駸到海涯。',32,'全唐诗/poet.song.220000.json','["半生道路困風沙，冰雪駸駸到海涯。", "鉏却舊時桃與李，滿園多種木綿花。"]'),
('1295a8d8-5c0e-4ff1-88ae-b733d950f842','觀西淙千丈瀑布  其一','胡仲弓','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','泉聲一派迫人寒，疑有癡龍在此間。',32,'全唐诗/poet.song.220000.json','["泉聲一派迫人寒，疑有癡龍在此間。", "聽了西淙三日雨，不知天下有廬山。"]'),
('537a35b4-d6b1-4069-92d3-4322cf886bfb','觀西淙千丈瀑布  其二','胡仲弓','宋','宋诗','song-poetry','','[]','萬斛明珠萬疊雷，分明激破白雲堆。',32,'全唐诗/poet.song.220000.json','["萬斛明珠萬疊雷，分明激破白雲堆。", "何因捲上銀河去，莫放瀨溪橋下來。"]'),
('a507f20a-8e98-4429-9933-29c6d9e74432','錢塘潮圖','胡仲弓','宋','宋诗','song-poetry','','[]','吳縑半幅浪如堆，開卷晴窗殷地雷。',32,'全唐诗/poet.song.220000.json','["吳縑半幅浪如堆，開卷晴窗殷地雷。", "一見野人心目爽，中秋曾看夜潮來。"]'),
('24e48603-efbd-496c-959b-81e9de8c8781','烏衣巷','胡仲弓','宋','宋诗','song-poetry','','[]','飛雲當日未停驂，巷在秦淮水以南。',32,'全唐诗/poet.song.220000.json','["飛雲當日未停驂，巷在秦淮水以南。", "可笑異聞唐小說，餘風猶襲晉清談。"]'),
('efedb362-3716-47f9-bb04-9c34e66c9dcc','翡翠','胡仲弓','宋','宋诗','song-poetry','','[]','毛羽生來便屬人，悔將體段鬭精神。',32,'全唐诗/poet.song.220000.json','["毛羽生來便屬人，悔將體段鬭精神。", "寄言翡翠休驚訝，但是文章盡累身。"]'),
('b415312c-aaa0-4498-b618-882b04a2b2c0','晚靜','胡仲弓','宋','宋诗','song-poetry','','[]','當日濂翁此讀書，自編小說愛芙蕖。',32,'全唐诗/poet.song.220000.json','["當日濂翁此讀書，自編小說愛芙蕖。", "方池靜植香清遠，便擬蓬萊小石渠。"]'),
('63b889da-128d-41fd-ae58-8150a7c5702a','芭蕉','胡仲弓','宋','宋诗','song-poetry','','[]','爲愛芭蕉綠葉濃，栽時傍竹引清風。',32,'全唐诗/poet.song.220000.json','["爲愛芭蕉綠葉濃，栽時傍竹引清風。", "近來怕聽愁人雨，斫盡簷前三四叢。"]'),
('0c827d37-9e44-40e7-9fbd-42eff1eb7cd9','翠凉','胡仲弓','宋','宋诗','song-poetry','','[]','千章古木影蕭森，未必山林如許深。',32,'全唐诗/poet.song.220000.json','["千章古木影蕭森，未必山林如許深。", "纔見眼前成綠暗，一年又負種花心。"]'),
('1ca09151-fb33-4431-b662-04960718f065','題壽星寺盃泉','胡仲弓','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','勺水原來亦自多，便盈科後要如何。',32,'全唐诗/poet.song.220000.json','["勺水原來亦自多，便盈科後要如何。", "老龍豈是盃中物，放出長江與大河。"]'),
('333c2382-e61e-4801-bcbb-82ed82ecd251','遊九日山','胡仲弓','宋','宋诗','song-poetry','','[]','散策來遊九日山，松風細細襲人寒。',32,'全唐诗/poet.song.220000.json','["散策來遊九日山，松風細細襲人寒。", "菊花過了重陽節，自是登高興未闌。"]'),
('82f3a04c-415a-45d5-bea0-e1971c4cd835','夜泊朋溪釣隠','胡仲弓','宋','宋诗','song-poetry','','[]','借得溪亭暫解鞍，溪亭擬作釣船看。',32,'全唐诗/poet.song.220000.json','["借得溪亭暫解鞍，溪亭擬作釣船看。", "不應隠處近城郭，未必終身把釣竿。"]'),
('89937141-7705-4037-b020-f0c777433e6d','呼猿','胡仲弓','宋','宋诗','song-poetry','','[]','前度寒林去不回，洞門今爲小猿開。',32,'全唐诗/poet.song.220000.json','["前度寒林去不回，洞門今爲小猿開。", "不因擲果爲香餌，未必人呼肯下來。"]'),
('17ec14bb-c6f3-43c7-9446-a14ae309fd55','天竺呼猿','胡仲弓','宋','宋诗','song-poetry','','[]','眠雲嘯月走枯藤，不是園丁叫不譍。',32,'全唐诗/poet.song.220000.json','["眠雲嘯月走枯藤，不是園丁叫不譍。", "自戀香林不歸去，前生恐是住山僧。"]'),
('9800948f-f47b-4142-b052-4f8dc15e7c90','睡貓','胡仲弓','宋','宋诗','song-poetry','','[]','瓶中斗粟鼠竊盡，床上狸奴睡不知。',32,'全唐诗/poet.song.220000.json','["瓶中斗粟鼠竊盡，床上狸奴睡不知。", "無奈家人猶愛護，買魚和飯養如兒。"]'),
('0c6fde8a-ed67-43f0-8026-5e197bf25e5b','桃源圖','胡仲弓','宋','宋诗','song-poetry','','[]','誤入仙源不記春，花間一見喜津津。',32,'全唐诗/poet.song.220000.json','["誤入仙源不記春，花間一見喜津津。", "可憐塵迹空遺恨，一樹桃花經幾秦。"]'),
('344ee57b-7a10-42d8-adf5-28ee188cd959','山行逢樵者','胡仲弓','宋','宋诗','song-poetry','','[]','鶴髮童顔歌負薪，衣襟不染一凡塵。',32,'全唐诗/poet.song.220000.json','["鶴髮童顔歌負薪，衣襟不染一凡塵。", "擔頭幾點桃花片，恐是當年避世人。"]'),
('1bf53311-7671-4ef9-a9d3-c5e4f7a1c107','次適安感古二首  其一','胡仲弓','宋','宋诗','song-poetry','','[]','少陵合與古詩班，不是詩家持論寬。',32,'全唐诗/poet.song.220000.json','["少陵合與古詩班，不是詩家持論寬。", "風雅近來隨世變，詩無可採不須官。"]'),
('ed84034e-d83a-4961-823c-0786ee7c0059','次適安感古二首  其二','胡仲弓','宋','宋诗','song-poetry','','[]','二南風化盛行時，里詠塗歌總是詩。',32,'全唐诗/poet.song.220000.json','["二南風化盛行時，里詠塗歌總是詩。", "採到春秋無可採，獲麟以後更堪悲。"]'),
('f5b0d0ba-8701-4d09-8516-950b941caefc','次黄瑞玉石鏡韻','胡仲弓','宋','宋诗','song-poetry','','[]','鑿出巉巖似鏡形，年深剝盡蘚痕青。',32,'全唐诗/poet.song.220000.json','["鑿出巉巖似鏡形，年深剝盡蘚痕青。", "世間更有磨塼者，欲借鉗鎚與五丁。"]'),
('2677b493-d4fd-47ac-a8db-8e6913afc00e','送友人','胡仲弓','宋','宋诗','song-poetry','','[]','纔到離亭淚滿衣，雲山千里夢相隨。',32,'全唐诗/poet.song.220000.json','["纔到離亭淚滿衣，雲山千里夢相隨。", "石州一曲陽關酒，窨約歸來是幾時。"]'),
('0a01e8bd-eb64-4ba7-9e06-f222d55f848e','和宮怨','胡仲弓','宋','宋诗','song-poetry','','[]','斜日倒穿龍尾道，楊柳半枯秋色老。',32,'全唐诗/poet.song.220000.json','["斜日倒穿龍尾道，楊柳半枯秋色老。", "翠華西幸華清宮，長門落葉無人掃。"]'),
('f36280a1-5181-49e7-a438-f5f28aa8eed1','宮詞  其一','胡仲弓','宋','宋诗','song-poetry','','[]','漢宮春色傍黄昏，曾謁金門奉至尊。',32,'全唐诗/poet.song.220000.json','["漢宮春色傍黄昏，曾謁金門奉至尊。", "月上海棠人寂寂，焚香百拜感皇恩。"]'),
('088a3b6c-d704-4688-a359-ba7b8b78631e','宮詞  其二','胡仲弓','宋','宋诗','song-poetry','','[]','垂楊枝上喜遷鶑，梅子黄時雨乍晴。',32,'全唐诗/poet.song.220000.json','["垂楊枝上喜遷鶑，梅子黄時雨乍晴。", "幾陣薰風穿玉殿，真珠簾內有歡聲。"]'),
('afb7358d-484a-4d4b-afdd-5a4a0b51bf68','宮詞  其三','胡仲弓','宋','宋诗','song-poetry','','[]','錫宴山亭車馬回，三千宮女醉蓬萊。',32,'全唐诗/poet.song.220000.json','["錫宴山亭車馬回，三千宮女醉蓬萊。", "遶池遊唱逍遥樂，自折紅蓮一朶來。"]'),
('1556517c-001d-44cf-853a-3f2f36fd087d','宮詞  其四','胡仲弓','宋','宋诗','song-poetry','','[]','深夜遊宮玉漏遲，侵晨鶑囀上林時。',32,'全唐诗/poet.song.220000.json','["深夜遊宮玉漏遲，侵晨鶑囀上林時。", "無端蝶戀花心動，摇落東風第一枝。"]'),
('e10be0de-0fe3-4ee4-a618-3e5f99440045','宮詞  其五','胡仲弓','宋','宋诗','song-poetry','','[]','夜合花開笑語聲，敢將薄倖訴衷情。',32,'全唐诗/poet.song.220000.json','["夜合花開笑語聲，敢將薄倖訴衷情。", "祝君聖壽千秋歲，妾願年年引駕行。"]'),
('f0ee1a2b-1b1b-484c-9cb4-e7de0e4f384d','宮詞  其六','胡仲弓','宋','宋诗','song-poetry','','[]','美人戚氏出椒房，金縷衣成八寶粧。',32,'全唐诗/poet.song.220000.json','["美人戚氏出椒房，金縷衣成八寶粧。", "夜靜綺羅香度處，瑶臺月下滿庭芳。"]'),
('7aa0d429-bae0-41db-bfcf-e154e14fd4c8','宮詞  其七','胡仲弓','宋','宋诗','song-poetry','','[]','瑶花飛處憶瑶姬，一日傾杯十二時。',32,'全唐诗/poet.song.220000.json','["瑶花飛處憶瑶姬，一日傾杯十二時。", "青玉案前呵凍手，推窗自塑雪獅兒。"]'),
('ed9f7f3e-bbac-4621-aca8-4aaead328a56','宮詞  其八','胡仲弓','宋','宋诗','song-poetry','','[]','通宵銀燭影摇紅，坐對孤鸞伴守宮。',32,'全唐诗/poet.song.220000.json','["通宵銀燭影摇紅，坐對孤鸞伴守宮。", "空有婦人嬌態在，眼兒薄媚怨春風。"]'),
('bd36e627-b209-4bd7-9e95-7b4123694a60','宮詞  其九','胡仲弓','宋','宋诗','song-poetry','','[]','桂枝香裏立多時，忽見傳言玉女來。',32,'全唐诗/poet.song.220000.json','["桂枝香裏立多時，忽見傳言玉女來。", "報道太清歌未徹，何妨愛月夜眠遲。"]'),
('fd6c2fcd-29b8-4353-81cf-d05ab11a9ad9','宮詞  其一○','胡仲弓','宋','宋诗','song-poetry','','[]','一自長門芳草生，六宮怕見柳梢青。',32,'全唐诗/poet.song.220000.json','["一自長門芳草生，六宮怕見柳梢青。", "玉樓春盡君王懶，大小梁州不忍聽。"]'),
('9c97843d-8a71-4666-82fe-496dc933f8d9','玉泉觀魚','胡仲弓','宋','宋诗','song-poetry','','[]','一潭秋水凈無塵，付與羣魚樂性真。',32,'全唐诗/poet.song.220000.json','["一潭秋水凈無塵，付與羣魚樂性真。", "鎮日倚欄看未足，豈知滄海有修鱗。"]'),
('fbdb1c5d-a10f-4709-a563-0887a9288389','秋聲','胡仲弓','宋','宋诗','song-poetry','','[]','秋本無言那有聲，不然風過物飄零。',32,'全唐诗/poet.song.220000.json','["秋本無言那有聲，不然風過物飄零。", "此心祇在人心做，說與行人莫誤聽。"]'),
('2d9025d3-e2a1-46a3-a6de-7f1efd8d03b9','飛來峰','胡仲弓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','山染西湖水漾青，孤高長對冷泉亭。',32,'全唐诗/poet.song.220000.json','["山染西湖水漾青，孤高長對冷泉亭。", "飛來何不飛將去，空與山僧作畫屏。"]'),
('4de2bc44-05d2-457b-86e3-fe9e92804a4a','快倚亭','胡仲弓','宋','宋诗','song-poetry','','[]','築得危亭倚太空，品題曾屬考亭翁。',32,'全唐诗/poet.song.220000.json','["築得危亭倚太空，品題曾屬考亭翁。", "著身高處不知快，多少池臺在下風。"]'),
('1e0e7fb3-a7f1-4e6b-b713-57b2cc2060d0','恭和皇帝宸翰四絕句  其一','胡仲弓','宋','宋诗','song-poetry','','[]','凭高望殺舊山川，萬里雲迷不盡天。',32,'全唐诗/poet.song.220000.json','["凭高望殺舊山川，萬里雲迷不盡天。", "汴水流經淮泗去，更無人買北歸船。"]'),
('fdf71e22-24b8-4d6c-ab4c-5102600ab938','恭和皇帝宸翰四絕句  其二','胡仲弓','宋','宋诗','song-poetry','','[]','中興盛事記磨崖，上有千年苔蘚花。',32,'全唐诗/poet.song.220000.json','["中興盛事記磨崖，上有千年苔蘚花。", "世變幾經流水去，山邊猶有漫郎家。"]'),
('8101afbf-763c-4bfe-8434-51e60f9116f4','恭和皇帝宸翰四絕句  其三','胡仲弓','宋','宋诗','song-poetry','','[]','放鶴山中訪野梅，南枝開了北枝開。',32,'全唐诗/poet.song.220000.json','["放鶴山中訪野梅，南枝開了北枝開。", "花神不作趨時態，也待鸞輿親幸來。"]'),
('d196f7d5-40fe-4b1d-a0d7-0171d3b4073f','恭和皇帝宸翰四絕句  其四','胡仲弓','宋','宋诗','song-poetry','','[]','御溝鎮日水潺潺，安得流紅到世間。',32,'全唐诗/poet.song.220000.json','["御溝鎮日水潺潺，安得流紅到世間。", "三十六宮新雨露，春風長繞八盤山。"]'),
('f21644b4-839c-4ca7-9f9e-578920ac40f3','次芸居無題韻','胡仲弓','宋','宋诗','song-poetry','','[]','身似浮雲不定棲，倚欄覓句聽鴉啼。',32,'全唐诗/poet.song.220000.json','["身似浮雲不定棲，倚欄覓句聽鴉啼。", "洛陽紙價新來貴，吟得詩成就壁題。"]'),
('3a6fec09-ffab-4e1a-a3bb-c87ba6133fa3','寄方南湖','胡仲弓','宋','宋诗','song-poetry','','[]','風雨中間奔客程，征衣濕盡尚慳晴。',32,'全唐诗/poet.song.220000.json','["風雨中間奔客程，征衣濕盡尚慳晴。", "可人不見空惆悵，拍拍一湖春水平。"]'),
('cbe004c0-92aa-46e9-b452-9cbd9a83acc3','次韻順適遣寄','胡仲弓','宋','宋诗','song-poetry','','[]','擬折芳馨遺所思，要將心事共謀惟。',32,'全唐诗/poet.song.220000.json','["擬折芳馨遺所思，要將心事共謀惟。", "暮雲遮斷松江路，重讀夫君別後詩。"]'),
('e192f708-5bb7-429f-9d86-c6c18b6c2528','遊小身巖','胡仲弓','宋','宋诗','song-poetry','','[]','千古巖隈迹未塵，幾多斧鑿幻全身。',32,'全唐诗/poet.song.220000.json','["千古巖隈迹未塵，幾多斧鑿幻全身。", "金身丈六猶言小，絕倒侏儒世上人。"]'),
('33f975ec-234e-4782-81e0-a56d568999f6','瑞香花','胡仲弓','宋','宋诗','song-poetry','','[]','生處多應散紫芝，清香端的與梅期。',32,'全唐诗/poet.song.220000.json','["生處多應散紫芝，清香端的與梅期。", "梅花剛被人描畫，却是清香人不知。"]'),
('5a4b1504-79ed-40c2-9a13-e91623b646db','劉項祠','胡仲弓','宋','宋诗','song-poetry','','[]','二祠相望幾春秋，祀了龍顔祀沐猴。',32,'全唐诗/poet.song.220000.json','["二祠相望幾春秋，祀了龍顔祀沐猴。", "章戴溪南梨嶺北，不知何處是鴻溝。"]'),
('ceb2df7d-fcb5-44a1-9539-8eb5176e1df1','客裏','胡仲弓','宋','宋诗','song-poetry','','[]','客裏吟詩幾歲寒，歸來依舊客衣單。',32,'全唐诗/poet.song.220000.json','["客裏吟詩幾歲寒，歸來依舊客衣單。", "一冬不見孤山面，只買梅花带雪看。"]'),
('98b4ca9b-6df2-4fce-8c1f-81b57e4f809f','水樂洞','胡仲弓','宋','宋诗','song-poetry','','[]','媧皇昔日奏鈞天，一派清音知幾年。',32,'全唐诗/poet.song.220000.json','["媧皇昔日奏鈞天，一派清音知幾年。", "寄語山靈好收拾，不須留與世人傳。"]'),
('14958bb0-3cd4-47f0-80e0-d286c17edc42','遊水樂煙霞二洞三絕  其一','胡仲弓','宋','宋诗','song-poetry','','[]','此是遊山第二回，天風吹斷洞雲開。',32,'全唐诗/poet.song.220000.json','["此是遊山第二回，天風吹斷洞雲開。", "人生到處須行樂，不爲尋梅亦自來。"]'),
('200289b3-2dd6-4162-9cd1-7979687cb765','遊水樂煙霞二洞三絕  其二','胡仲弓','宋','宋诗','song-poetry','','[]','愛山分席坐松陰，草草盃盤慰賞心。',32,'全唐诗/poet.song.220000.json','["愛山分席坐松陰，草草盃盤慰賞心。", "水樂不鳴天籟寂，數聲幽鳥和清吟。"]'),
('59725e37-1186-4481-a5a1-1d6c4d59f947','遊水樂煙霞二洞三絕  其三','胡仲弓','宋','宋诗','song-poetry','','[]','象鼻峰前得少留，煙霞風景記來遊。',32,'全唐诗/poet.song.220000.json','["象鼻峰前得少留，煙霞風景記來遊。", "等閒拂石題名姓，惹得青雲上筆頭。"]'),
('218b6226-18af-453c-87af-23dbef5e240a','景陽宮井','胡仲弓','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','隋師已迫長江滸，玉樹庭花曲未終。',32,'全唐诗/poet.song.220000.json','["隋師已迫長江滸，玉樹庭花曲未終。", "千古龍鸞有遺恨，胭脂井上至今紅。"]'),
('cf09e52a-d10c-4e57-a235-1ec9ea0d6819','過桐江三絕  其一','胡仲弓','宋','宋诗','song-poetry','','[]','解纜移舟淛水濱，晚潮初落岸痕新。',32,'全唐诗/poet.song.220000.json','["解纜移舟淛水濱，晚潮初落岸痕新。", "酒酣卧唱江南曲，月在篷窗冷照人。"]'),
('8e750b08-fe5b-4910-91fd-f94ecc092048','過桐江三絕  其二','胡仲弓','宋','宋诗','song-poetry','','[]','客星何預漢中興，枉把虛名累子陵。',32,'全唐诗/poet.song.220000.json','["客星何預漢中興，枉把虛名累子陵。", "千古釣壇如壁立，先生去後少人登。"]'),
('f122322f-4bf7-475e-85c7-61a050c24d98','過桐江三絕  其三','胡仲弓','宋','宋诗','song-poetry','','[]','流水高山得趣時，好音政不要人知。',32,'全唐诗/poet.song.220000.json','["流水高山得趣時，好音政不要人知。", "絕絃此意誰能會，未必盡因鍾子期。"]'),
('b8045260-c356-4494-9b98-22e24a3ac4a0','用韻送馿與源谷','胡仲弓','宋','宋诗','song-poetry','','[]','長耳追風走似流，黔人空使載馿舟。',32,'全唐诗/poet.song.220000.json','["長耳追風走似流，黔人空使載馿舟。", "巾箱欲置無容處，來與騷人款段游。"]'),
('dcda241d-35d2-4a51-953b-aa0526057536','十二月十五夜雪','胡仲弓','宋','宋诗','song-poetry','','[]','聽得窗前雪打聲，起來眼界甚分明。',32,'全唐诗/poet.song.220000.json','["聽得窗前雪打聲，起來眼界甚分明。", "從前浪說豐年瑞，三白如今始作成。"]'),
('c9ec0691-f7cb-44aa-972a-e8c37801531e','元宵雪','胡仲弓','宋','宋诗','song-poetry','','[]','燈火樓臺白玉鋪，這般祥瑞不如無。',32,'全唐诗/poet.song.220000.json','["燈火樓臺白玉鋪，這般祥瑞不如無。", "誰能斷取維摩手，畫出元宵踏雪圖。"]'),
('56b8dcf3-52f0-4678-a475-ef4b7fc7f556','次卓仁夫元宵雪中三絕  其一','胡仲弓','宋','宋诗','song-poetry','','[]','姑射神人雉扇開，三千玉女擁瑶臺。',32,'全唐诗/poet.song.220000.json','["姑射神人雉扇開，三千玉女擁瑶臺。", "十分散布猶嫌少，萬斛明珠抖下來。"]'),
('09a5f263-205d-4ecc-89a3-194fb5ff0ba3','次卓仁夫元宵雪中三絕  其二','胡仲弓','宋','宋诗','song-poetry','','[]','風急梅花片片飛，遊人星散市聲稀。',32,'全唐诗/poet.song.220000.json','["風急梅花片片飛，遊人星散市聲稀。", "翻思往日西樓約，不至天明不肯歸。"]'),
('6e2c5799-9513-4f82-8c0b-f88b287a2d39','次卓仁夫元宵雪中三絕  其三','胡仲弓','宋','宋诗','song-poetry','','[]','繡簾直下整雲鬟，歌舞叢中强自懽。',32,'全唐诗/poet.song.220000.json','["繡簾直下整雲鬟，歌舞叢中强自懽。", "興盡歸來太多事，不如高卧學袁安。"]'),
('9d933f8b-48c0-475e-8036-2a2077584e2b','古意','胡仲弓','宋','宋诗','song-poetry','','[]','流水滔滔去不回，好花能得幾時開。',32,'全唐诗/poet.song.220000.json','["流水滔滔去不回，好花能得幾時開。", "丁寧莫剪門前竹，留兩三竿待鳳來。"]'),
('b89240fe-1d38-46eb-86cc-cd58855a52bf','秋意','胡仲弓','宋','宋诗','song-poetry','','[]','淅淅西風響敗欄，椶櫚一夜戰聲乾。',32,'全唐诗/poet.song.220000.json','["淅淅西風響敗欄，椶櫚一夜戰聲乾。", "壯心肯逐悲秋老，自剔青燈把劍看。"]'),
('a53ce853-8c92-476e-946a-fbff5de82ef2','吳潘二臺官以直言左遷董夕郎亦以薦賢之故相繼翩然而去公論惜之三學叩閽來歸劉聲伯感而賦詩因次其韻  其一','胡仲弓','宋','宋诗','song-poetry','','[]','三鳳高飛挽不留，轅駒仗馬轉堪羞。',32,'全唐诗/poet.song.220000.json','["三鳳高飛挽不留，轅駒仗馬轉堪羞。", "明朝封事排閶闔，公論從來在士流。"]'),
('d671a61f-f161-4e90-beb5-89b196bd570b','吳潘二臺官以直言左遷董夕郎亦以薦賢之故相繼翩然而去公論惜之三學叩閽來歸劉聲伯感而賦詩因次其韻  其二','胡仲弓','宋','宋诗','song-poetry','','[]','風采纔看聳柏臺，如何又遣賦歸來。',32,'全唐诗/poet.song.220000.json','["風采纔看聳柏臺，如何又遣賦歸來。", "晚年造物多顛倒，雷發原來是禍胎。"]'),
('5014353b-f8d4-47a0-98d0-f9e6547a5e35','觀道君御書','胡仲弓','宋','宋诗','song-poetry','','[]','带草行書十數行，也隨匹馬到錢塘。',32,'全唐诗/poet.song.220000.json','["带草行書十數行，也隨匹馬到錢塘。", "傷心一幅槐黄紙，猶染宣和御墨香。"]'),
('1e5ce80b-b88d-4356-aa94-de0c83f9c683','鄰雪','胡仲弓','宋','宋诗','song-poetry','','[]','萬玉叢中願卜鄰，世無和靖莫相親。',32,'全唐诗/poet.song.220000.json','["萬玉叢中願卜鄰，世無和靖莫相親。", "石橋春澗留衣鉢，端的先生是後人。"]'),
('49eaa44c-255e-4011-b7ee-14dcbc99f914','含章殿','胡仲弓','宋','宋诗','song-poetry','','[]','千古風流說壽陽，梅花飄落粉猶香。',32,'全唐诗/poet.song.220000.json','["千古風流說壽陽，梅花飄落粉猶香。", "寄言長信宮中女，莫學當時亡國粧。"]'),
('d60fcc03-6390-4360-a2b7-e8deff9ea669','靈和殿','胡仲弓','宋','宋诗','song-poetry','','[]','靈和殿下三眠柳，舞盡春風入畫圖。',32,'全唐诗/poet.song.220000.json','["靈和殿下三眠柳，舞盡春風入畫圖。", "記得風流年少事，青青還似舊時無。"]'),
('ea92e22b-2ef5-4aac-bb2f-a8af85b2483e','晚梅次韻  其一','胡仲弓','宋','宋诗','song-poetry','','[]','準擬和羹滋味成，如何尚带隔年英。',32,'全唐诗/poet.song.220000.json','["準擬和羹滋味成，如何尚带隔年英。", "春風可是無分別，遣放夭桃相並生。"]'),
('e764cdb4-8afc-4ea7-9758-49c242569579','晚梅次韻  其二','胡仲弓','宋','宋诗','song-poetry','','[]','年少叢中最老成，春風一點尚留情。',32,'全唐诗/poet.song.220000.json','["年少叢中最老成，春風一點尚留情。", "先生早晚調羹去，說與羣兒莫浪爭。"]'),
('159395a6-bd81-442c-9649-5f56053a889a','懷林梅臞','胡仲弓','宋','宋诗','song-poetry','','[]','梅花寂寂幾黄昏，見說青氈屬耳孫。',32,'全唐诗/poet.song.220000.json','["梅花寂寂幾黄昏，見說青氈屬耳孫。", "欲訪咸平舊香影，無僮無鶴暗銷魂。"]'),
('8e7e3110-ea7a-4bb0-bc80-c1f8b6ee9580','落梅  其一','胡仲弓','宋','宋诗','song-poetry','','[]','花本無情却有情，誰將開落擬浮生。',32,'全唐诗/poet.song.220000.json','["花本無情却有情，誰將開落擬浮生。", "盈虛自是天機事，錯認樓前羌笛聲。"]'),
('9f8e301a-718f-40a3-9140-2d3a97bbdc2b','落梅  其二','胡仲弓','宋','宋诗','song-poetry','','[]','南枝不與北枝同，及早開時及早空。',32,'全唐诗/poet.song.220000.json','["南枝不與北枝同，及早開時及早空。", "莫笑北枝開較晚，前頭畢竟有春風。"]'),
('c79d4d68-51cf-4058-9070-6e543f16f846','尋梅','胡仲弓','宋','宋诗','song-poetry','','[]','因探梅花踏曉雲，隔牆時有暗香聞。',32,'全唐诗/poet.song.220000.json','["因探梅花踏曉雲，隔牆時有暗香聞。", "枝頭纔漏春消息，便带春愁一二分。"]'),
('11a9aad3-ed46-41e8-8ad7-a79aa2cbae02','題高伯壽墨梅  其一','胡仲弓','宋','宋诗','song-poetry','','[]','纔見梅花喜溢眉，無聲詩索有聲詩。',32,'全唐诗/poet.song.220000.json','["纔見梅花喜溢眉，無聲詩索有聲詩。", "自從即墨移來種，莫辨南枝與北枝。"]'),
('29b226d8-0550-45db-b864-c6aae0686ece','題高伯壽墨梅  其二','胡仲弓','宋','宋诗','song-poetry','','[]','生來潔白本無瑕，翦雪裁冰擅一家。',32,'全唐诗/poet.song.220000.json','["生來潔白本無瑕，翦雪裁冰擅一家。", "堪歎俗流剛點涴，故將水墨寫梅花。"]'),
('8785731a-b0eb-4ce7-82eb-e7a41ed61e0a','閨情','胡仲弓','宋','宋诗','song-poetry','','[]','寶鏡愁看淚臉紅，銀瓶冷落若爲容。',32,'全唐诗/poet.song.220000.json','["寶鏡愁看淚臉紅，銀瓶冷落若爲容。", "夢魂不怕關山險，飛過巫山十二峰。"]'),
('7e3c5b8c-d17e-4d7b-81d7-5496ca2c59b1','閨怨  其一','胡仲弓','宋','宋诗','song-poetry','','[]','君居楚尾妾吳頭，咫尺天涯作許愁。',32,'全唐诗/poet.song.220000.json','["君居楚尾妾吳頭，咫尺天涯作許愁。", "多謝有情江上月，夜深分照兩家樓。"]'),
('3327bdd8-6b73-4433-90be-264433e4ab38','閨怨  其二','胡仲弓','宋','宋诗','song-poetry','','[]','別後粧臺鏡懶開，倚門日日望書來。',32,'全唐诗/poet.song.220000.json','["別後粧臺鏡懶開，倚門日日望書來。", "西風吹過衡陽雁，雁已歸回郎未回。"]'),
('b17ace34-8793-4fb7-90ef-16e9912d5070','雨中有懷','胡仲弓','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','幾度懷人風雨中，篝燈坐待鼓三通。',32,'全唐诗/poet.song.220000.json','["幾度懷人風雨中，篝燈坐待鼓三通。", "寸心同指長江水，君向西流我向東。"]'),
('e64ff6ec-6e7c-4490-9192-06df7f64bcbd','豆粥','胡仲弓','宋','宋诗','song-poetry','','[]','豆白宜烹玉糝糜，絕勝雲子雪翻匙。',32,'全唐诗/poet.song.220000.json','["豆白宜烹玉糝糜，絕勝雲子雪翻匙。", "蕪蔞亭上冰霜裏，曾與君王療一饑。"]'),
('5b85cf48-f898-43db-9e18-3789d497ebcc','祕書省墨竹','胡仲弓','宋','宋诗','song-poetry','','[]','寫出此君真面目，筆端造化少人知。',32,'全唐诗/poet.song.220000.json','["寫出此君真面目，筆端造化少人知。", "我疑與可今猶在，安得東坡共賦詩。"]'),
('6b5b0dd7-75f7-4c4d-b023-b2316ea2fb2c','聞西事有感','胡仲弓','宋','宋诗','song-poetry','','[]','春水方生秋又殘，上流無處避風寒。',32,'全唐诗/poet.song.220000.json','["春水方生秋又殘，上流無處避風寒。", "杜鵑飛向東南去，怕見如今蜀道難。"]'),
('c74945a2-6c84-4d58-8854-8b75c58d7e57','桐廬縣','胡仲弓','宋','宋诗','song-poetry','','[]','富春山下桐廬縣，江水縈迴千萬峰。',32,'全唐诗/poet.song.220000.json','["富春山下桐廬縣，江水縈迴千萬峰。", "縣宰何人真解事，做官來向畫圖中。"]'),
('d2063671-7cfe-455b-a644-2729cab31398','徘徊花','胡仲弓','宋','宋诗','song-poetry','','[]','獨擅春花掩衆芳，薔薇水洗內家粧。',32,'全唐诗/poet.song.220000.json','["獨擅春花掩衆芳，薔薇水洗內家粧。", "可憐清氣無收拾，惹得閒人衣袖香。"]'),
('272367b2-a587-422b-a8b4-ce3a106a2943','秀野','胡仲弓','宋','宋诗','song-poetry','','[]','世路荆榛日日深，山居抱膝且長吟。',32,'全唐诗/poet.song.220000.json','["世路荆榛日日深，山居抱膝且長吟。", "便教定亶無公論，不到風聞松竹林。"]'),
('a5d7ccaf-1780-4201-9383-d0c658027ab2','贈張南金談星','胡仲弓','宋','宋诗','song-poetry','','[]','迺祖乘槎去復還，君平饒舌世人傅。',32,'全唐诗/poet.song.220000.json','["迺祖乘槎去復還，君平饒舌世人傅。", "天機不道因渠泄，更遣雲仍學算天。"]'),
('0b7754ac-16c1-4a4e-8bd0-da6d42edf5db','談星陳炎發求詩','胡仲弓','宋','宋诗','song-poetry','','[]','從來此物最瞞人，術好多爲造物嗔。',32,'全唐诗/poet.song.220000.json','["從來此物最瞞人，術好多爲造物嗔。", "若把天機全泄漏，罰教甘石一生貧。"]'),
('dfac508e-fd61-4ac6-b1bd-79a7093ce93d','讀後村梅花百詠','胡仲弓','宋','宋诗','song-poetry','','[]','曾被梅花累十春，孤山踪跡斷知聞。',32,'全唐诗/poet.song.220000.json','["曾被梅花累十春，孤山踪跡斷知聞。", "百篇依舊相嘲弄，却恐梅花又怕君。"]'),
('05f227e6-93ee-4a8d-8b1e-bb56468130be','不如歸去','胡仲弓','宋','宋诗','song-poetry','','[]','禽言自是不分明，誰信西川帝子靈。',32,'全唐诗/poet.song.220000.json','["禽言自是不分明，誰信西川帝子靈。", "千古傳訛無訂正，至今春晚誤人聽。"]'),
('59f0c040-7da6-4eb6-8262-0c183008e7eb','江郎山  其一','胡仲弓','宋','宋诗','song-poetry','','[]','巫山有石稱神女，何事江山亦號郎。',32,'全唐诗/poet.song.220000.json','["巫山有石稱神女，何事江山亦號郎。", "豈是世情强分別，從來造化有陰陽。"]'),
('865feb5d-e7e6-490d-83f3-6579e213daf0','江郎山  其二','胡仲弓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','觀盡千山與萬山，幾曾得似此峰巒。',32,'全唐诗/poet.song.220000.json','["觀盡千山與萬山，幾曾得似此峰巒。", "誰能移向西湖上，併與西湖一樣看。"]'),
('7a37c912-5119-47cc-9803-db4e617bcccb','雪中有感','胡仲弓','宋','宋诗','song-poetry','','[]','閭閻愁歎不堪聞，風雪如何更作嗔。',32,'全唐诗/poet.song.220000.json','["閭閻愁歎不堪聞，風雪如何更作嗔。", "白玉樓臺銀步障，只宜富貴不宜貧。"]'),
('82fbe9f3-23da-450f-90ae-3599aa8eaa16','雜興  其一','胡仲弓','宋','宋诗','song-poetry','','[]','百年一瞬息，萬事皆塵埃。',72,'全唐诗/poet.song.220000.json','["百年一瞬息，萬事皆塵埃。", "所以身後名，不如掌中杯。", "山園足花草，雨露相先開。", "獨有崖下松，春風不曾來。", "青林曉霜重，百卉顔如灰。", "蒼髯五大夫，鬰鬰何佳哉。"]'),
('d4c92be5-9e97-4835-982a-18ff803470cc','雜興  其二','胡仲弓','宋','宋诗','song-poetry','','[]','佳花費事治，十無二三本。',60,'全唐诗/poet.song.220000.json','["佳花費事治，十無二三本。", "惡草時掃除，已復相苯䔿。", "試嘗問園丁，否泰乃爾反。", "渠方倚鋤笑，謂我見事晚。", "老天亦何心，生花日衮衮。"]'),
('c6099eaa-db16-43c3-b285-d09d13b155a0','雜興  其三','胡仲弓','宋','宋诗','song-poetry','','[]','梁武欲爲佛，秦皇欲爲仙。',72,'全唐诗/poet.song.220000.json','["梁武欲爲佛，秦皇欲爲仙。", "萬乘猶不足，要與天齊年。", "人生幾兩屐，過眼如風烟。", "此心苦無已，憂患常烹煎。", "不見客斯逐，力詆爭秦權。", "寧知咸陽市，父子更相憐。"]'),
('b286fa90-d049-4c3d-acfd-b80733d940bd','海月堂觀濤','胡仲弓','宋','宋诗','song-poetry','','[]','青天與海連，羲娥代吞吐。',156,'全唐诗/poet.song.220000.json','["青天與海連，羲娥代吞吐。", "封姨助餘威，陽侯倏起舞。", "或奔千丈龍，或轟萬疊鼓。", "蓬弱此路通，祇界一斥鹵。", "浩浩無津涯，尾閭闢地戶。", "嬴女驅鮫人，獻怪扶桑府。", "琛球來百蠻，玭珠還合浦。", "獨立象岡外，身世等一羽。", "宇宙納溟渤，萬山齊傴僂。", "清風與明月，造物不禁取。", "臨流喜得句，玉欄失笑拊。", "眺望此一時，澒洞注千古。", "安得捲上天，霈作天下雨。"]'),
('b5095578-252a-442e-91b5-264510183ed6','過駝巘嶺','胡仲弓','宋','宋诗','song-poetry','','[]','中興諸將士，殺身報明主。',72,'全唐诗/poet.song.220000.json','["中興諸將士，殺身報明主。", "生前七十創，死後一丘土。", "嶺上生愁雲，紛紛不可數。", "平生憂國心，氣結不能吐。", "肝膽常輪囷，未知死何所。", "杯酒酹夕陽，臨風淚如雨。"]'),
('8e6debd7-7392-4e3c-b98e-ac782a1ef73d','醜婦謠','胡仲弓','宋','宋诗','song-poetry','','[]','人知醜婦醜，不知醜婦妍。',144,'全唐诗/poet.song.220000.json','["人知醜婦醜，不知醜婦妍。", "醜婦安乎醜，婦德或可全。", "荆釵與布裙，常坐紡織邊。", "妍婦巧於人，玉貌長娟娟。", "嫵媚及依阿，萬態隨方圓。", "醜者妍之實，妍者醜之端。", "醜者妍之德，妍者醜之賊。", "人皆惡其醜，我以醜爲則。", "人皆愛其妍，我以妍爲惑。", "丁寧醜婦人，莫效妍婦顰。", "欲保醜婦德，莫學妍婦色。", "人鑑不可欺，妍醜自明白。"]'),
('c7ca1f57-a4b1-4658-abcf-a10eac73d274','題金粟洞','胡仲弓','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','名山洞府三十六，若擬帽峰猶未足。',224,'全唐诗/poet.song.220000.json','["名山洞府三十六，若擬帽峰猶未足。", "有人曾此坐丹爐，有人曾此安碁局。", "一朝悟道歸去來，依舊紫雲鎖林屋。", "武榮賈客來洛陽，手携尺書叩巖谷。", "覿面親逢呂洞賓，有眼不辨鄭文叔。", "功成行滿欲度人，酬之遺以半升粟。", "豈知粒粒皆金砂，一服可但能辟穀。", "先嗔後喜來重尋，癡心纔動隔山谷。", "故老相傳金粟仙，凌霄有塔蒼標玉。", "乾坤外物號無塵，凡夫到此懶著脚。", "我來稽首問先生，若爲乞得壺中藥。", "刀圭分與醫國人，却入深山抱幽獨。", "先生道我亦不塵，且走千巖并萬壑。", "它時相過岳陽樓，定把奇書與君讀。"]'),
('d8610f73-e638-44cc-ba1d-957cbf90265b','過新蓬二嶺','胡仲弓','宋','宋诗','song-poetry','','[]','新嶺高，蓬嶺高，兩山前後爭嶆峨。',64,'全唐诗/poet.song.220000.json','["新嶺高，蓬嶺高，兩山前後爭嶆峨。", "世途平處多風波，何如嶺嶠肩相摩。", "脚踏實地無偏頗，著身高處不爲勞。", "新嶺高，蓬嶺高，勿令此地生蓬蒿。"]'),
('cdf81287-39b5-4d1d-b03e-7e3059748dcf','芳庭爲作希聖二字以詩謝之','胡仲弓','宋','宋诗','song-poetry','','["\u897f\u6e56"]','貫休鐵畫天下奇，芳庭心法今似之。',144,'全唐诗/poet.song.220000.json','["貫休鐵畫天下奇，芳庭心法今似之。", "偃波垂露久不作，雲煙灑灑光陸離。", "北山塔穎健筆卓，西湖倒瀉爲研池。", "長空萬里紙一幅，等閑揮翰摇坤維。", "大書姓氏牋金闕，書仙驚問子爲誰。", "安定後人希聖父，曾披骨鯁干龍墀。", "公權筆諫粗有志，未知所遇何如時。", "書仙聞言發一笑，風雲際會須有期。", "何當濃墨寫竹帛，千古萬古長昭垂。"]'),
('96c01dc3-803f-4575-b4b4-80f31eb5a52a','試劍石','胡仲弓','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','青蛇生膽氣，袖過洞庭湖。',48,'全唐诗/poet.song.220000.json','["青蛇生膽氣，袖過洞庭湖。", "既有虎堪刺，豈無龍可屠。", "鐵山何用碎，崖石至今枯。", "欲斷樓蘭首，能安砥礪歟。"]'),
('4660bde1-df6e-4c7b-86a0-c1728951d650','法山寺','胡仲弓','宋','宋诗','song-poetry','','[]','距城無數里，乃有此名山。',48,'全唐诗/poet.song.220000.json','["距城無數里，乃有此名山。", "海近雲常漫，林深風易寒。", "齋餘飛鳥下，定後野僧閒。", "一宿何曾覺，翩然又起單。"]'),
('358bb6c8-abde-49a1-b262-0b1c804d9ba8','次法石寺即事韻','胡仲弓','宋','宋诗','song-poetry','','[]','近郊來往熟，馴犬向人迎。',48,'全唐诗/poet.song.220000.json','["近郊來往熟，馴犬向人迎。", "半是吟將老，何時隠得成。", "月明山景合，潮落海痕生。", "歸路霜鐘外，微聞三數聲。"]'),
('a1948304-75bc-493c-b46e-2df59f99048d','清吟寺','胡仲弓','宋','宋诗','song-poetry','','[]','高僧曾住此，長對佛爐吟。',48,'全唐诗/poet.song.220000.json','["高僧曾住此，長對佛爐吟。", "蕭寺有興廢，清名無古今。", "禪心秋水瑩，燈影石壇深。", "不見鬼神泣，空聞鐘磬音。"]'),
('29069708-34dc-419d-8771-aa437e824ce6','廢寺','胡仲弓','宋','宋诗','song-poetry','','[]','鐘鼓蕭條久，誰從此地來。',48,'全唐诗/poet.song.220000.json','["鐘鼓蕭條久，誰從此地來。", "僧房無戶牖，佛面有塵埃。", "碑斷眠荒草，廊空長綠苔。", "鵂鶹并蝙蝠，時或此徘徊。"]'),
('cc92b20e-2ca7-4251-8a6b-4ab9cb7e9e43','得闕越州冷掾','胡仲弓','宋','宋诗','song-poetry','','[]','寒氈纔入手，便動帝鄉心。',48,'全唐诗/poet.song.220000.json','["寒氈纔入手，便動帝鄉心。", "千古蘭亭在，三年芹水深。", "文排崑體作，詩對越人吟。", "自得高山趣，何當遇賞音。"]'),
('43b59932-230d-49d7-93f2-8271afbf913b','頤齋聯日有事於琛亭賦詩聊爲解嘲','胡仲弓','宋','宋诗','song-poetry','','[]','詩人有公事，日日走琛亭。',48,'全唐诗/poet.song.220000.json','["詩人有公事，日日走琛亭。", "紫翠和衣重，香塵滿面生。", "蚌還江月濕，龍起浪雲腥。", "薏苡亦何有，奚囊澈底清。"]'),
('6e11e373-2bbf-401f-988c-e62e912bebf6','次雲心韻贈臞仙','胡仲弓','宋','宋诗','song-poetry','','[]','清修如野鶴，心性在雲間。',48,'全唐诗/poet.song.220000.json','["清修如野鶴，心性在雲間。", "蔬食從來瘦，林居耐得閒。", "爐分真造化，夢繞舊鄉關。", "汩汩塵樊者，聞風想厚顔。"]'),
('5c731a3c-e009-4000-bad8-3c0c9a6dfe6d','送季同歸龍泉','胡仲弓','宋','宋诗','song-poetry','','[]','天寒猶客路，行李况擔書。',48,'全唐诗/poet.song.220000.json','["天寒猶客路，行李况擔書。", "喚醒江湖夢，歸尋水竹居。", "詞華須近古，劍氣欲凌虛。", "好趁功名會，言詩特緒餘。"]'),
('cf316deb-c27d-4e31-a2b4-471cd6b4ab3f','明發','胡仲弓','宋','宋诗','song-poetry','','[]','明發占鷄唱，停驂數暝鴉。',48,'全唐诗/poet.song.220000.json','["明發占鷄唱，停驂數暝鴉。", "半生多在路，十日九懷家。", "照水芙蓉色，滿園蕎麥花。", "歸田何日是，對客話桑麻。"]'),
('2a739115-eb07-435b-ab49-d418e9ad68a1','題黄耑玉寒瘦藁','胡仲弓','宋','宋诗','song-poetry','','[]','幾回吟傑句，破硯幾遭焚。',48,'全唐诗/poet.song.220000.json','["幾回吟傑句，破硯幾遭焚。", "古道不復作，唐風猶可聞。", "寒於梅傲雪，瘦似竹侵雲。", "近世無郊島，詩人數到君。"]'),
('36ede697-c13c-43cd-b850-244ddd02bcac','山行觀紫雲洞','胡仲弓','宋','宋诗','song-poetry','','[]','浪遊知幾載，久不到山巔。',48,'全唐诗/poet.song.220000.json','["浪遊知幾載，久不到山巔。", "泉石曾留意，煙霞未有緣。", "松陰長匝地，塔穎欲鑽天。", "待洗塵埃脚，重來訪紫仙。"]'),
('104faeaf-424e-4d52-aac8-f882e2cbf5da','嘲赴緣僧道','胡仲弓','宋','宋诗','song-poetry','','[]','身在塵緣外，如何更趁緣。',48,'全唐诗/poet.song.220000.json','["身在塵緣外，如何更趁緣。", "僧堂清富貴，道院小神仙。", "飯飽休持鉢，丹成莫賣錢。", "但能了生死，何必問蒼天。"]'),
('14efcc8d-0b07-4841-b7f6-5788fe8b97cd','山庵','胡仲弓','宋','宋诗','song-poetry','','[]','蒲團清夜話，吟鬢任鬅鬙。',48,'全唐诗/poet.song.220000.json','["蒲團清夜話，吟鬢任鬅鬙。", "瀹茗遲留客，焚香靜對僧。", "嵐蒸侵硯版，月冷逼禪燈。", "萬籟俱岑寂，呼童亦不譍。"]'),
('2ca4662c-3184-4c2f-b051-c089f9235602','送傅明府之南安','胡仲弓','宋','宋诗','song-poetry','','[]','撫字及催科，三年鬢已皤。',48,'全唐诗/poet.song.220000.json','["撫字及催科，三年鬢已皤。", "公心如日月，浮議任風波。", "父老顰眉說，兒童拍掌歌。", "歸裝無一物，空有綠旗多。"]'),
('f7359b94-f11e-4992-b9d1-3beb23cc29d6','車中遥觀五峰','胡仲弓','宋','宋诗','song-poetry','','[]','五峰天外立，馿脚慣經過。',48,'全唐诗/poet.song.220000.json','["五峰天外立，馿脚慣經過。", "十載身萍梗，今朝面薜蘿。", "雲低山色暗，風急樹聲多。", "蠟屐何時辦，來聽樵子歌。"]'),
('565dd99e-c611-4fb0-a2c6-8c096480c6d5','送趙明叔分教潮陽','胡仲弓','宋','宋诗','song-poetry','','[]','昌黎遺俗在，興教更煩君。',48,'全唐诗/poet.song.220000.json','["昌黎遺俗在，興教更煩君。", "地産無名木，春生半水芹。", "詩歌麟趾化，筆補鰐魚文。", "莫厭官氈冷，相期粉省芸。"]'),
('877c1b79-7571-4e49-8c1f-132b5048d8c0','送梅臞三山','胡仲弓','宋','宋诗','song-poetry','','[]','曾共梅花約，論心到歲寒。',48,'全唐诗/poet.song.220000.json','["曾共梅花約，論心到歲寒。", "如何傾別酒，獨自上吟鞍。", "藥裹留餘劑，詩囊有近刊。", "懷人眇雲際，頻展墨龍看。"]'),
('c2b254b6-38c4-4b5c-803f-c97ac813ff58','自笑','胡仲弓','宋','宋诗','song-poetry','','[]','自笑謀生拙，多應涉世疎。',48,'全唐诗/poet.song.220000.json','["自笑謀生拙，多應涉世疎。", "爲貧趨斗祿，因病試方書。", "榕葉寒侵戶，梅花深結廬。", "焚香坐清夜，吟到曉鐘初。"]'),
('dd471e8c-59d1-499a-81ba-218a004b514b','倚欄','胡仲弓','宋','宋诗','song-poetry','','[]','倚欄商好句，雲散海山青。',48,'全唐诗/poet.song.220000.json','["倚欄商好句，雲散海山青。", "風急天無恙，人驚心地靈。", "潮頭迎日月，帆片落滄溟。", "夜靜濤聲息，龍吟得細聽。"]'),
('5c96b494-0ead-4e3d-9723-1e18d7db060e','薄遊','胡仲弓','宋','宋诗','song-poetry','','[]','薄遊歸較晚，清氣滿丘園。',48,'全唐诗/poet.song.220000.json','["薄遊歸較晚，清氣滿丘園。", "鴉噪盤林影，蛩聲咽草根。", "吟腸思茗碗，醉眼迫冰盆。", "心迹兩忘處，難同俗子論。"]'),
('97376a0b-75dc-4ca8-85db-bef21e550f84','哀黄鳥','胡仲弓','宋','宋诗','song-poetry','','[]','憐君金縷衣，失脚蹈危機。',48,'全唐诗/poet.song.220000.json','["憐君金縷衣，失脚蹈危機。", "自是我心惻，非關物命微。", "引雛誰共食，求友便忘歸。", "送汝入幽谷，驚魂何處飛。"]'),
('0364dcf9-f6fc-4beb-9ac8-1ea2e04e2029','題崇福寺青山閣','胡仲弓','宋','宋诗','song-poetry','','[]','禪餘無一事，冷面看青山。',48,'全唐诗/poet.song.220000.json','["禪餘無一事，冷面看青山。", "明月幾時有，白雲終日閒。", "地虛塵不到，天遠手難攀。", "直下看人境，紛紛醉夢間。"]'),
('e95ebe11-b5d2-4e7f-b4e8-09b88d829c25','爲源上人題寶葉','胡仲弓','宋','宋诗','song-poetry','','[]','寶蓮千萬葉，葉葉是如來。',48,'全唐诗/poet.song.220000.json','["寶蓮千萬葉，葉葉是如來。", "浄土社中得，無波水上栽。", "根頭藏舍利，香氣避塵埃。", "移向松灣去，山花不敢開。"]'),
('77fbd065-ad13-4b18-b1fb-83ffe14fcedb','寒食','胡仲弓','宋','宋诗','song-poetry','','[]','初過一百五，園林正好看。',48,'全唐诗/poet.song.220000.json','["初過一百五，園林正好看。", "梨花未全禿，梅子带微酸。", "近世煙初禁，何人食肯寒。", "東風猶作惡，誰念客衣單。"]'),
('bb9de1b3-1bb6-4ee9-ab0f-237facaddb9a','不飲','胡仲弓','宋','宋诗','song-poetry','','[]','之子青州裔，生來契分疎。',48,'全唐诗/poet.song.220000.json','["之子青州裔，生來契分疎。", "難從將進酒，屢下絕交書。", "甕面空浮螘，樽前但取魚。", "任他賢與聖，清濁不關渠。"]'),
('1720f7a6-ba1f-4256-bb2b-1641fee53008','春晚山茶花數朵艷甚','胡仲弓','宋','宋诗','song-poetry','','[]','萬紅彫落盡，留住隔年花。',48,'全唐诗/poet.song.220000.json','["萬紅彫落盡，留住隔年花。", "獨艷迎人笑，殘粧带雨斜。", "物情無老少，春意自繁華。", "顔色休相妬，風流別一家。"]'),
('51c0d31d-82e9-42a4-9173-1a9b74699061','題清泉院','胡仲弓','宋','宋诗','song-poetry','','[]','孤僧如槁木，住處遠人煙。',48,'全唐诗/poet.song.220000.json','["孤僧如槁木，住處遠人煙。", "山有千年寺，名因一派泉。", "堂虛遺像暗，壁敗野藤穿。", "法座空塵積，無人來叩禪。"]'),
('a9b3c2b6-52e4-4503-a1f6-67e41c10f7ce','題通妙亭柱','胡仲弓','宋','宋诗','song-poetry','','[]','小亭存古意，雅稱道家風。',48,'全唐诗/poet.song.220000.json','["小亭存古意，雅稱道家風。", "池水鴨頭綠，山茶鶴頂紅。", "內丹還九轉，法鼓叩三通。", "若問希夷事，簷鈴語未終。"]'),
('9cd8f50d-a2ef-4699-8d2c-1cc0909440e0','遊紫澤觀','胡仲弓','宋','宋诗','song-poetry','','[]','地偏塵不到，俗客可曾來。',48,'全唐诗/poet.song.220000.json','["地偏塵不到，俗客可曾來。", "寫帖雲侵硯，朝真風滿臺。", "蘭荒根有蠹，梅古樹生苔。", "莫論還丹訣，金爐久已灰。"]'),
('cbe4c9d9-f221-4fdd-bb3f-e5b3b0160820','虹橋','胡仲弓','宋','宋诗','song-poetry','','[]','纔過虹橋渡，漫山皆紫泥。',48,'全唐诗/poet.song.220000.json','["纔過虹橋渡，漫山皆紫泥。", "鷗邊秋水落，牛背夕陽低。", "酒向汙樽飲，詩從板壁題。", "江郎在何許，靈石與天齊。"]'),
('c1d717d3-842b-45db-a700-c6e321b028ad','山中','胡仲弓','宋','宋诗','song-poetry','','[]','世情紛醉夢，抱獨入山林。',48,'全唐诗/poet.song.220000.json','["世情紛醉夢，抱獨入山林。", "有竹堪醫俗，無絃誰賞音。", "松蘿青嶂合，鷄犬白雲深。", "未必幽居者，能賡梁甫吟。"]'),
('6c52b6e1-ef5e-42d6-af99-6341cbfe28e6','尤溪山中','胡仲弓','宋','宋诗','song-poetry','','[]','山中寒意足，自笑索裘遲。',48,'全唐诗/poet.song.220000.json','["山中寒意足，自笑索裘遲。", "野店鷄聲飯，頹垣鴉字詩。", "雨餘松徑滑，溪漲板橋危。", "問訊恬軒老，鄉鄰總不知。"]'),
('d9af2b5c-b74a-466b-9e5b-08737f8cd454','柬蕭芸莊','胡仲弓','宋','宋诗','song-poetry','','[]','十載江湖夢，鴻飛不到君。',48,'全唐诗/poet.song.220000.json','["十載江湖夢，鴻飛不到君。", "近聞吟思苦，半爲宦情分。", "往事隨流水，懷人看暮雲。", "相逢又相別，安得細論文。"]'),
('caa845a9-ab4d-40fe-9a8e-1ec0029c7f98','舟中即事','胡仲弓','宋','宋诗','song-poetry','','[]','携家驅宦牒，短棹泛桃源。',48,'全唐诗/poet.song.220000.json','["携家驅宦牒，短棹泛桃源。", "人語聯篷屋，漁歌隔水村。", "雲歸千嶂合，雨過一江渾。", "爲愛招提近，纜船楊柳根。"]'),
('8831ebfa-04b6-43ed-bb03-0e2f78ce2602','舟中歸興','胡仲弓','宋','宋诗','song-poetry','','[]','舟膠回短棹，岸曲抱溪斜。',48,'全唐诗/poet.song.220000.json','["舟膠回短棹，岸曲抱溪斜。", "香篆迷煙草，燈光閃浪花。", "歸心隨舴艋，遺響託琵琶。", "明月如留客，猶籠淺渡沙。"]'),
('7aabe65d-6891-4f5f-9b80-ead954c504fd','寄舟中諸吟友','胡仲弓','宋','宋诗','song-poetry','','[]','溪流何太急，畫槳去如飛。',48,'全唐诗/poet.song.220000.json','["溪流何太急，畫槳去如飛。", "詩壘才無敵，愁城醉解圍。", "日斜帆影亞，風細樂聲微。", "誤入桃源去，月明猶未歸。"]'),
('624909a9-a658-4bfb-9ebc-67dc8b67bcd4','觀江郎石','胡仲弓','宋','宋诗','song-poetry','','[]','江郎何日化，千古鎮長青。',48,'全唐诗/poet.song.220000.json','["江郎何日化，千古鎮長青。", "乍見人疑怪，多應地有靈。", "世間無此石，天上應何星。", "海外蓬萊島，猶疑在杳冥。"]'),
('da24ad9f-b04f-452b-8c6d-5ef21b8c8399','桐江舟中','胡仲弓','宋','宋诗','song-poetry','','[]','推篷納山色，愁坐對黄昏。',48,'全唐诗/poet.song.220000.json','["推篷納山色，愁坐對黄昏。", "雨過天無翳，舟行水有痕。", "鐘聲來遠寺，犬吠隔煙村。", "柳下漁人屋，收罾早閉門。"]'),
('daf7d36a-ea28-419d-aa4d-7bf6f0f3c8ef','延平舟中','胡仲弓','宋','宋诗','song-poetry','','[]','雙槳去夷猶，延平津上州。',48,'全唐诗/poet.song.220000.json','["雙槳去夷猶，延平津上州。", "英雄三尺劍，今古一潭秋。", "市近人爭渡，山迴水急流。", "前頭風浪惡，莫放釣魚舟。"]'),
('ec21b463-e204-421b-bd99-5fa56c5894c3','送羅去華','胡仲弓','宋','宋诗','song-poetry','','[]','江湖如許闊，無地著詩流。',48,'全唐诗/poet.song.220000.json','["江湖如許闊，無地著詩流。", "難覓青精飯，空回明月舟。", "分甘貧國士，莫謁富民侯。", "隨處風波惡，無魚可上鈎。"]'),
('6cd023f1-711b-43cb-8c25-21d1ddc8e6d7','夜飲頤齋以燈前細雨簷花落爲韻分得前字又得花字賦二首  其一','胡仲弓','宋','宋诗','song-poetry','','[]','春去如惜別，淚雨滴簷前。',48,'全唐诗/poet.song.220000.json','["春去如惜別，淚雨滴簷前。", "酒病思盧橘，吟魂逐杜鵑。", "堂虛香穗直，風定燭花圓。", "萬籟沈清夜，瓦溝聞落泉。"]'),
('17e01829-f461-4574-9663-b19a74fcd54d','夜飲頤齋以燈前細雨簷花落爲韻分得前字又得花字賦二首  其二','胡仲弓','宋','宋诗','song-poetry','','[]','萬仞騷臺立海涯，堂堂筆陣走龍蛇。',64,'全唐诗/poet.song.220000.json','["萬仞騷臺立海涯，堂堂筆陣走龍蛇。", "喚回蝴蝶三更夢，吟落荼䕷一架花。", "座上風流追靖節，酒邊豪放逼劉叉。", "幅巾危坐清源□，小待山陰漸熟瓜。"]'),
('b4552c83-ef52-42ec-8fd9-d64108befa0e','贈神籟談天','胡仲弓','宋','宋诗','song-poetry','','[]','曾將甲子問羣生，來向人間說五行。',64,'全唐诗/poet.song.220000.json','["曾將甲子問羣生，來向人間說五行。", "眼底精神雖晦昧，胸中造化却分明。", "指推寶曆八千數，時弄玉簫三四聲。", "袖裏百篇題品盡，何曾識得一公卿。"]'),
('26716501-fe5a-4541-a493-fad6a2b830ee','次韻賦海棠','胡仲弓','宋','宋诗','song-poetry','','[]','萬樹嫣紅壓錦城，此花宜雨又宜晴。',64,'全唐诗/poet.song.220000.json','["萬樹嫣紅壓錦城，此花宜雨又宜晴。", "睡中銀燭層層照，醉後朱唇暈暈輕。", "携酒獨來蘇學士，逸詩笑殺杜先生。", "雪兒檀板休教唱，見說嬌羞不耐驚。"]'),
('c5e76cdf-481e-4779-b4e8-d9c55acbce07','次麓湖韻送王用和歸省侍','胡仲弓','宋','宋诗','song-poetry','','[]','因訪詩宗特特來，子猷興盡轉船回。',64,'全唐诗/poet.song.220000.json','["因訪詩宗特特來，子猷興盡轉船回。", "故園松竹元無恙，新本芝蘭更欠栽。", "傑句多於貧後出，好懷長是醉時開。", "白雲只在青山外，歸去堂前學老萊。"]'),
('5b1f0a01-73e4-49c9-afaf-23e74601a703','次林明府清源洞壁間韻','胡仲弓','宋','宋诗','song-poetry','','[]','解带臨風卧看山，夢魂飛不到人間。',64,'全唐诗/poet.song.220000.json','["解带臨風卧看山，夢魂飛不到人間。", "雲蒸空翠和衣濕，石潄泉聲透骨寒。", "解語靈禽如有訴，倦飛野鶴自知還。", "吟詩盡道隠居好，能幾人來肯棄官。"]'),
('8a796026-b141-424c-8502-e1a20271403a','再和抱拙清源洞韻','胡仲弓','宋','宋诗','song-poetry','','[]','泉聲一路和吟聲，可是山雲未放晴。',64,'全唐诗/poet.song.220000.json','["泉聲一路和吟聲，可是山雲未放晴。", "倦客難攀千丈壁，遊仙空負十年盟。", "草廬不信無龍卧，松徑微聞有鶴鳴。", "此舉羨君高著脚，山肴野䔩薦杯羹。"]'),
('00b0a0d4-c83f-4fef-9a0e-5aeb6ea09e89','和杜友遊清源洞韻','胡仲弓','宋','宋诗','song-poetry','','[]','涉險何如過虎牢，白雲堆裏著身高。',64,'全唐诗/poet.song.220000.json','["涉險何如過虎牢，白雲堆裏著身高。", "登臨我欲招元亮，談笑時能接李翺。", "人境下看猶粟粒，洞天西去有蟠桃。", "學仙恐是虛無說，且向峰頭跨六鼇。"]'),
('732e4afb-98e6-42ce-a40a-1bb6a29968df','己酉上元詩同日立春','胡仲弓','宋','宋诗','song-poetry','','[]','又是京華見上元，一番燈火奪春寒。',64,'全唐诗/poet.song.220000.json','["又是京華見上元，一番燈火奪春寒。", "花蛾巧剪禁風撲，綵燕新裁带月看。", "客裏無家愁對酒，吟邊索句夜凭欄。", "寄言雲雨休相妬，天下人人欲縱觀。"]'),
('d6e5de07-3f60-4fba-bbe8-c99e22e65541','和李希膺春日醉吟','胡仲弓','宋','宋诗','song-poetry','','[]','節物催人白髮新，放懷不減少年春。',64,'全唐诗/poet.song.220000.json','["節物催人白髮新，放懷不減少年春。", "叵羅酌酒猶堪醉，古錦爲囊未是貧。", "清坐相看情不惡，淡交至久味方真。", "妓圍笑指紅樓去，寂寞窮吟胡楚賓。"]'),
('8ba54b0b-b4df-4328-a7aa-b57191556383','和壁間韻','胡仲弓','宋','宋诗','song-poetry','','[]','萬仞岡邊去路長，道人採藥試丹方。',64,'全唐诗/poet.song.220000.json','["萬仞岡邊去路長，道人採藥試丹方。", "弈枰誰解爭高著，仙樂時聞按大涼。", "日落塔頭雲氣紫，雨餘山脚蘚痕蒼。", "年深洞古無塵迹，惟有先皇御墨香。"]'),
('326233eb-7a6e-4c08-8fcb-4763361da75f','寄鱸鄉主人','胡仲弓','宋','宋诗','song-poetry','','[]','天北天南獨鴈飛，別君動是隔年期。',64,'全唐诗/poet.song.220000.json','["天北天南獨鴈飛，別君動是隔年期。", "尺書久欠鱸鄉便，寸步難邀馬足馳。", "池草驚回春夢句，梅花開到歲寒枝。", "江湖諸老凋零盡，從此逢人懶說詩。"]'),
('658f905f-37d4-4644-b622-9472a5bd4159','送趙汝楫分教建安','胡仲弓','宋','宋诗','song-poetry','','[]','又領臯比走建安，青衿喜色上眉端。',64,'全唐诗/poet.song.220000.json','["又領臯比走建安，青衿喜色上眉端。", "詩因老去難言別，氈到春來不覺寒。", "當日紫陽傳授學，他年粉省校讎官。", "聖門豈必肯私淑，莫把規隨一例看。"]'),
('582a1610-45d8-48f4-9314-ef75b780238e','春日雜興  其一','胡仲弓','宋','宋诗','song-poetry','','[]','漁翁樵叟自行藏，裹飯過從樂未央。',64,'全唐诗/poet.song.220000.json','["漁翁樵叟自行藏，裹飯過從樂未央。", "撲滿自緣錢作祟，鴟夷聊以酒爲鄉。", "老來願棄人間世，病去欲荒牆下桑。", "黄犢不嫌人日雨，村村苗長綠微茫。"]'),
('44a8dc93-b106-4313-8981-5809cd00ab0b','春日雜興  其二','胡仲弓','宋','宋诗','song-poetry','','[]','殘雪初消月正明，茅簷自雨竹窗晴。',64,'全唐诗/poet.song.220000.json','["殘雪初消月正明，茅簷自雨竹窗晴。", "肩寒聳聳吟詩骨，肺渴泠泠醒酒羹。", "少有梅方成野趣，不多松亦作江聲。", "高人合著山巖裏，縱有窮愁澈底清。"]'),
('ed77e781-93f6-4977-8200-b3ef0015ab11','春日雜興  其三','胡仲弓','宋','宋诗','song-poetry','','[]','野性最於魚鶴親，自知不是世間人。',64,'全唐诗/poet.song.220000.json','["野性最於魚鶴親，自知不是世間人。", "生成雪壑冰崖面，收得煙蓑雨笠身。", "楊柳春來青眼舊，山林老去白頭新。", "毋多感慨令君瘦，獨立斜陽一欠伸。"]'),
('e2371110-5a18-468b-82a4-98323f48fc01','春日雜興  其四','胡仲弓','宋','宋诗','song-poetry','','[]','吾生身事信天緣，一死何須較後先。',64,'全唐诗/poet.song.220000.json','["吾生身事信天緣，一死何須較後先。", "未怕時逢真太歲，或言壽過古稀年。", "窮餘祿料齏百甕，醉負生涯囊一錢。", "又見山林春意思，辦隨芳草落花眠。"]'),
('c1e28458-4b2e-44c2-a23a-7292e09157de','春日雜興  其五','胡仲弓','宋','宋诗','song-poetry','','[]','天與之愚竟不移，經年兀兀槿花籬。',64,'全唐诗/poet.song.220000.json','["天與之愚竟不移，經年兀兀槿花籬。", "拙於生事可無粥，工乃窮人頼有詩。", "只恁麽休身是客，知何以故鬢成絲。", "寒欺雪屋青燈夜，六十猶癡始是癡。"]'),
('8b42ba4b-5b3c-4b1b-928e-d2ab1a685fcd','春日雜興  其六','胡仲弓','宋','宋诗','song-poetry','','[]','綠繞西疇小作勞，溪村寒入舊綈袍。',64,'全唐诗/poet.song.220000.json','["綠繞西疇小作勞，溪村寒入舊綈袍。", "五窮政坐沒梁斗，百舌不如無口匏。", "穫稻條桑豳雅頌，紉蘭餐菊楚離騷。", "客來更話唐虞上，盍且卑之毋甚高。"]'),
('6249161e-4f21-4db8-9246-5a9755dd5f0f','春日雜興  其七','胡仲弓','宋','宋诗','song-poetry','','[]','鶴骨嶄嶄疾未瘳，怯行山亦倦登樓。',64,'全唐诗/poet.song.220000.json','["鶴骨嶄嶄疾未瘳，怯行山亦倦登樓。", "久知老去自當爾，自入春來雨不休。", "虛器甚慙居士屩，實封難覓醉鄉侯。", "小遲須有佳晴日，待試山翁已健不。"]'),
('288ed7d3-2c64-4981-b2e6-583af8109d41','春日雜興  其八','胡仲弓','宋','宋诗','song-poetry','','[]','春來多病感頹齡，草藥泥瓶不暫停。',64,'全唐诗/poet.song.220000.json','["春來多病感頹齡，草藥泥瓶不暫停。", "身似漏船難補貼，齒如敗屐久凋零。", "炎黄豈解留年壽，莊老聊堪悅性靈。", "長劍拄頤兒戲耳，底須麟閣更圖形。"]'),
('ab713af5-c999-4f6b-8e92-4ab957ce6c7d','春日雜興  其九','胡仲弓','宋','宋诗','song-poetry','','[]','花柳村村奈老何，一春門巷斷經過。',64,'全唐诗/poet.song.220000.json','["花柳村村奈老何，一春門巷斷經過。", "無繩可繫西沈日，有水皆隨東逝波。", "妄想已空騎鶴夢，勞生亦厭飯牛歌。", "正須秉燭遊清夜，轉眼蘭亭舊永和。"]'),
('964e692e-120b-4bd9-ab76-7731804af694','春日雜興  其一○','胡仲弓','宋','宋诗','song-poetry','','[]','幽溪幾日不曾來，半是紅香半綠苔。',64,'全唐诗/poet.song.220000.json','["幽溪幾日不曾來，半是紅香半綠苔。", "樂事每從忙裏過，好花偏向雨中開。", "慣貧可使居無竹，高隠共忻山有萊。", "投老田廬今日倦，不才多病兩悠哉。"]'),
('56387702-1284-4e6c-8237-32c7843f4ac6','春日雜興  其一一','胡仲弓','宋','宋诗','song-poetry','','[]','高下雲藏野老家，縱橫水潄竹籬斜。',64,'全唐诗/poet.song.220000.json','["高下雲藏野老家，縱橫水潄竹籬斜。", "勒將春去許多雨，流出山來都是花。", "白首風煙三徑草，清時鼓吹一池蛙。", "身閒不耐閒雙手，洗甑吹香夜作茶。"]'),
('490e0c12-94e7-4108-8887-e007b9333f15','春日雜興  其一二','胡仲弓','宋','宋诗','song-poetry','','[]','南岡北嶺對窗扉，看盡朝嵐與夕暉。',64,'全唐诗/poet.song.220000.json','["南岡北嶺對窗扉，看盡朝嵐與夕暉。", "社後未曾聞燕語，雨中誰不惜花飛。", "山醅約莫幾日熟，沙笋輪囷一尺圍。", "莫怨風光損桃李，荼䕷芍藥又芳菲。"]'),
('dd661b29-6ab9-4d0b-ac41-96b3dbf12a5e','春日雜興  其一三','胡仲弓','宋','宋诗','song-poetry','','[]','衝雨衝泥處處行，物情殊不可詩情。',64,'全唐诗/poet.song.220000.json','["衝雨衝泥處處行，物情殊不可詩情。", "牡丹又是一年過，春事略無三日晴。", "先後笋爭滕薛長，東西鷗背晉齊盟。", "山居寂寞誰堪共，杞葉菊苗俱可耕。"]'),
('3941442b-81f9-4023-a8a8-6c1a0cd701c7','春日雜興  其一四','胡仲弓','宋','宋诗','song-poetry','','[]','綠陰芳草鳥啼春，與客相携發興新。',64,'全唐诗/poet.song.220000.json','["綠陰芳草鳥啼春，與客相携發興新。", "半落杏花初過雨，微酸梅子已生仁。", "每尋詩去必遷坐，穩跨牛歸不問津。", "筋力尚堪蓑笠在，莫欺老子髮如銀。"]'),
('79727bbc-2317-45d0-8527-679ddf3291ac','春日雜興  其一五','胡仲弓','宋','宋诗','song-poetry','','[]','浄掃山房不似貧，旋炊野飯喚比鄰。',64,'全唐诗/poet.song.220000.json','["浄掃山房不似貧，旋炊野飯喚比鄰。", "子規啼處一村雨，芍藥開時三逕春。", "丘壑自成安樂國，漁樵尚有老成人。", "茅簷相對坐終日，只說桑麻語自真。"]'),
('569545ef-073e-456f-9d7d-3823336bb427','題金粟洞','胡仲弓','宋','宋诗','song-poetry','','[]','誰信東南有此山，幾回蠟屐只空還。',64,'全唐诗/poet.song.220000.json','["誰信東南有此山，幾回蠟屐只空還。", "乾坤超出浮塵外，世界深藏粒粟間。", "鶴不歸來華表在，犀從飛去紫雲閒。", "捫蘿直上凌霄塔，見說微垣手可攀。"]'),
('bd50a47d-62fc-48e4-a3dc-b86ad62130e3','和瞻甫韻','胡仲弓','宋','宋诗','song-poetry','','[]','住在壺中小有天，故山猿鶴作忘年。',64,'全唐诗/poet.song.220000.json','["住在壺中小有天，故山猿鶴作忘年。", "雲歸每失碁盤石，人去不生丹竈烟。", "肯信玉華空有洞，自貪黄粟便無仙。", "我來立盡斜陽暮，猶撚吟髭風月邊。"]'),
('0be4a87d-a68f-48be-90f6-1dbac4346dc9','過嶺作','胡仲弓','宋','宋诗','song-poetry','','[]','崇岡峻嶺欲凌霄，鳥道行邊去路遥。',64,'全唐诗/poet.song.220000.json','["崇岡峻嶺欲凌霄，鳥道行邊去路遥。", "客裏恰逢三伏暑，程頭方到九秋橋。", "不堪流水鳴嗚咽，頼有詩篇慰寂寥。", "但得此身强健在，任渠皤鬢自蕭蕭。"]'),
('1d0322a1-9405-401d-9c7b-1d011f97bf32','舊題寶勝寺壁','胡仲弓','宋','宋诗','song-poetry','','[]','十里湖光鏡樣平，銀潢一带向東傾。',64,'全唐诗/poet.song.220000.json','["十里湖光鏡樣平，銀潢一带向東傾。", "寺從楊柳陰中出，僧在蓮花會上行。", "佛地也容擔板漢，梵音莫近採菱聲。", "我來借榻醒塵夢，歸去吟詩韻更清。"]'),
('2c233d86-a32a-43de-baf0-46a33dc964e7','早過毫光嶺','胡仲弓','宋','宋诗','song-poetry','','[]','輕烟護日曉霞明，身在毫光嶺上行。',64,'全唐诗/poet.song.220000.json','["輕烟護日曉霞明，身在毫光嶺上行。", "虎過新蹄看未了，犬逢舊客喜相迎。", "摘來山栗連蓬買，采得溪芹带葉羹。", "一字推敲猶未穩，奚奴知我有詩成。"]'),
('491386f3-ce03-4bbb-bc24-f2d0624e6bb9','郊行同張宰','胡仲弓','宋','宋诗','song-poetry','','[]','雨晴郊外共尋芳，細水交流注野塘。',64,'全唐诗/poet.song.220000.json','["雨晴郊外共尋芳，細水交流注野塘。", "花欲戀枝風不肯，柳纔舞影日還藏。", "轉添老態難於健，看得閒時少似忙。", "擬訪一僧共茶話，禪房扃鎖出遊方。"]'),
('9db2ee6b-31c8-4dd7-86cb-e84ce8a54eff','和劉後村雜興  其一','胡仲弓','宋','宋诗','song-poetry','','[]','冬深差喜病根除，藥裹猶親酒盞疎。',64,'全唐诗/poet.song.220000.json','["冬深差喜病根除，藥裹猶親酒盞疎。", "門對好山純種竹，園通活水可澆蔬。", "簷牙带濕霜晴後，簾額移陰日出初。", "時有郵筒遞詩至，吟餘便擬借牛車。"]'),
('8acaa8f3-18ed-457b-bba5-af6a21677102','和劉後村雜興  其二','胡仲弓','宋','宋诗','song-poetry','','[]','幾年待漏趣朝班，乞得閒身返故山。',64,'全唐诗/poet.song.220000.json','["幾年待漏趣朝班，乞得閒身返故山。", "公論盡歸恩怨外，清談不落是非間。", "屠龍肯信無高手，畫虎雖成亦强顔。", "馬革裹尸徒自壯，爭如投老得生還。"]'),
('759ff326-fab9-4e51-85e2-8508996aad06','和劉後村雜興  其三','胡仲弓','宋','宋诗','song-poetry','','[]','出處難爲卜筮謀，植鰭無復轉巖求。',64,'全唐诗/poet.song.220000.json','["出處難爲卜筮謀，植鰭無復轉巖求。", "清風不度麒麟閣，明月空沈鸚鵡洲。", "采石僅埋吟骨在，新亭猶带淚痕羞。", "書生慷慨談時事，未必膺門肯見留。"]'),
('3af36a63-1855-4940-a2c7-7eea5a5701fa','和劉後村雜興  其四','胡仲弓','宋','宋诗','song-poetry','','[]','避俗常關白板扉，北山泉石尚堪嬉。',64,'全唐诗/poet.song.220000.json','["避俗常關白板扉，北山泉石尚堪嬉。", "臨流且賦觀魚樂，憂國何消捋虎危。", "自許丹心長戀闕，獨憐萬戶未逢時。", "割雞爲黍尋常事，客至休言子爲誰。"]'),
('946f4ae8-2dd1-4b77-b1ed-1c13fe824fc6','和劉後村雜興  其五','胡仲弓','宋','宋诗','song-poetry','','[]','邇來筆硯亦相疎，野服焚香讀異書。',64,'全唐诗/poet.song.220000.json','["邇來筆硯亦相疎，野服焚香讀異書。", "築室不須臨孔道，閉門只合造輕車。", "有梅花處猶堪酒，無竹人家不可居。", "涉世直消誡口過，是非榮辱不關渠。"]'),
('d967a755-9979-4b16-8752-7685b303f6bd','和劉後村雜興  其六','胡仲弓','宋','宋诗','song-poetry','','[]','誦讀未多才思慳，數編遺醜落人間。',64,'全唐诗/poet.song.220000.json','["誦讀未多才思慳，數編遺醜落人間。", "洪音互雜蛙蟬奏，封事宜投虎豹關。", "楊震有知金忍受，相如未死璧終還。", "且須靜守心齋坐，學取簞瓢陋巷顔。"]'),
('d46252d0-5a80-42cf-ba20-4a412339806b','和劉後村雜興  其七','胡仲弓','宋','宋诗','song-poetry','','[]','累疏殷勤奏榻前，憂時急似救頭然。',64,'全唐诗/poet.song.220000.json','["累疏殷勤奏榻前，憂時急似救頭然。", "功名常是中年立，忠孝當於晚節全。", "投祓歸來泉石上，班荆坐向竹梅邊。", "烏臺無復詩公案，弄月嘲風亦偶然。"]'),
('28e17c7a-795b-4627-bd92-8a3c8b4e5b4f','和劉後村雜興  其八','胡仲弓','宋','宋诗','song-poetry','','[]','近學時粧越樣新，空遺畎畝處忠臣。',64,'全唐诗/poet.song.220000.json','["近學時粧越樣新，空遺畎畝處忠臣。", "燭之武老未爲老，劉伯龍貧可是貧。", "造物不應推若輩，江山亦合助詩人。", "挂冠神武當年事，明哲從來要保身。"]'),
('b1365891-473e-4098-b61f-af1629e3ade7','和劉後村雜興  其九','胡仲弓','宋','宋诗','song-poetry','','[]','宦海風波亦足驚，得閒聊爾慰平生。',64,'全唐诗/poet.song.220000.json','["宦海風波亦足驚，得閒聊爾慰平生。", "雖無塞上雪堪卧，幸有山中田可耕。", "一老拂衣何太勇，羣兒撼樹漫相輕。", "絕憐千丈西涼瀑，偏與人間訴不平。"]'),
('7d40bd39-fa39-4281-a97c-b159e89560cb','和劉後村雜興  其一○','胡仲弓','宋','宋诗','song-poetry','','[]','當日曾彈貢禹冠，懸知出處獨今難。',64,'全唐诗/poet.song.220000.json','["當日曾彈貢禹冠，懸知出處獨今難。", "寧將退翮翔千仞，誰肯模棱持兩端。", "風雨筆頭猶老健，江湖吟鬢未凋殘。", "十篇話破平生事，留與時人作樣看。"]'),
('f08c47ad-1533-4808-bc0d-613bd2b1e902','遊承天寺偶成','胡仲弓','宋','宋诗','song-poetry','','[]','人間熱惱正匆匆，纔入山門便不同。',64,'全唐诗/poet.song.220000.json','["人間熱惱正匆匆，纔入山門便不同。", "雲板聲中僧出定，月臺影裏佛觀空。", "堂陰岑寂常如夜，殿角清涼不見風。", "纔得浮雲閒半日，明朝馬跡又西東。"]'),
('6bb4534f-0f24-4efd-86a0-c8cdc22e9fa6','春晴','胡仲弓','宋','宋诗','song-poetry','','[]','寒齋淺酌喜新晴，絕倒湘累賦獨醒。',64,'全唐诗/poet.song.220000.json','["寒齋淺酌喜新晴，絕倒湘累賦獨醒。", "清坐苦無佳客話，朗吟生怕俗人聽。", "五湖四海雙塵屐，萬壑千巖一畫屏。", "雲雨從來翻覆手，黄昏更看照泥星。"]'),
('6e30334b-d6c1-4c88-b258-0328d378c1a7','次洪陽巖太卿韻爲方蒙仲書監賦西清風月','胡仲弓','宋','宋诗','song-poetry','','[]','莫聽豳人歌楚茨，鬻書空笑未多貲。',64,'全唐诗/poet.song.220000.json','["莫聽豳人歌楚茨，鬻書空笑未多貲。", "治中盡說裴懷古，館下曾宗韓退之。", "西望前山誰拄笏，南來別駕例能詩。", "昔賢自有清標在，添在桐城一段奇。"]'),
('988c645b-8fef-4f18-a3f5-f3aa12c56deb','寄朱靜佳明府','胡仲弓','宋','宋诗','song-poetry','','[]','十載江湖嘆不遭，識君歲月漫蹉跎。',64,'全唐诗/poet.song.220000.json','["十載江湖嘆不遭，識君歲月漫蹉跎。", "文書南去靜邊省，山水西來佳處多。", "琴調本高緣撫字，詩逋未了欠催科。", "騷人標致清如許，製錦機中製芰荷。"]'),
('a55e8113-8fb9-44c4-b3ac-4e40be0b7707','寒食雨中用李希膺韻','胡仲弓','宋','宋诗','song-poetry','','[]','平明風雨釀春寒，試把餳和杏酪餐。',64,'全唐诗/poet.song.220000.json','["平明風雨釀春寒，試把餳和杏酪餐。", "野祭人來悲冷節，郊行誰肯共吟鞍。", "煮茶有約泉堪品，禁火無條燧莫鑽。", "一百五朝全戒酒，定知夢不到邯鄲。"]'),
('420266be-7462-49c8-a3ef-26ada57c89ca','夜飲趙明府歸來偶成','胡仲弓','宋','宋诗','song-poetry','','[]','睡思濃時酒已醺，主人猶自倒金樽。',64,'全唐诗/poet.song.220000.json','["睡思濃時酒已醺，主人猶自倒金樽。", "綺筵散盡月初上，畫燭泣殘宵正分。", "榕葉聲中清醉夢，梅花影裏返吟魂。", "歸來小立樓西角，紫帽峰頭生白雲。"]'),
('8f8583da-fde0-4bd3-b563-a24e559ea1d7','清泉院用柱間韻','胡仲弓','宋','宋诗','song-poetry','','[]','僧居一路曲通村，日落層巔生暮雲。',64,'全唐诗/poet.song.220000.json','["僧居一路曲通村，日落層巔生暮雲。", "白石巧於山背出，清泉時向澗邊聞。", "鉢盂未信承龍化，錫杖曾經解虎紛。", "歸去鶴猿應笑我，稚圭何必更移文。"]'),
('90e3a2e2-19f6-4333-8598-a3c3954d7e67','耕田','胡仲弓','宋','宋诗','song-poetry','','[]','田可耕兮圃可蔬，幾年夢不到亨衢。',64,'全唐诗/poet.song.220000.json','["田可耕兮圃可蔬，幾年夢不到亨衢。", "山林受用琴書鶴，天地交遊風月吾。", "事變無涯人老矣，死生有命汝知乎。", "客來時復一盃酒，盡作鱸鄉醉隠圖。"]'),
('b7c21ff7-b09d-426b-86df-1f0468f84420','代壽圓嶠顔文昌','胡仲弓','宋','宋诗','song-poetry','','[]','長命新詩恰剪裁，瓣香南望祝蓬萊。',64,'全唐诗/poet.song.220000.json','["長命新詩恰剪裁，瓣香南望祝蓬萊。", "千齡椿算從天與，九節蒲根著地栽。", "范不待年甘引去，文雖告老召還來。", "肉芝幸有丹書在，留取他年薦壽杯。"]'),
('838f0a57-3da3-4608-89d8-202fb15e2182','壽趙默庵','胡仲弓','宋','宋诗','song-poetry','','[]','九十風光老益强，一生長得對東皇。',64,'全唐诗/poet.song.220000.json','["九十風光老益强，一生長得對東皇。", "結成梅子味初實，開盡荼䕷晚更香。", "堯曆不隨春脚去，周天從此日頭長。", "年年常記今時節，花滿朝冠酒滿觴。"]'),
('769fce01-0605-42bf-81ce-33976a028989','和趙同叔送桂花韻','胡仲弓','宋','宋诗','song-poetry','','[]','少年折桂已心灰，纔臭清芬鼻觀開。',64,'全唐诗/poet.song.220000.json','["少年折桂已心灰，纔臭清芬鼻觀開。", "喜見月宮和影落，傳聞天女散花來。", "黄金枝上留仙粟，白玉臺前絕世埃。", "聚遠樓空成感慨，不堪時節苦相催。"]'),
('8d5301a3-6b3c-4fff-8bc9-88f98661b68c','包家山看桃花','胡仲弓','宋','宋诗','song-poetry','','[]','春風吹到小桃根，便覺仙凡有路分。',64,'全唐诗/poet.song.220000.json','["春風吹到小桃根，便覺仙凡有路分。", "紫氣直衝文德殿，綵霞隔斷武陵源。", "錦官城向山頭出，玉蹕聲從天上聞。", "一見圜丘懷故土，令人寂寞暗銷魂。"]'),
('4fc9e8a0-d4d8-4c5b-8d84-b388f1958ac3','次韻柬李希膺','胡仲弓','宋','宋诗','song-poetry','','[]','相逢一笑便忘懷，鼠量難當三百盃。',64,'全唐诗/poet.song.220000.json','["相逢一笑便忘懷，鼠量難當三百盃。", "幕府清閒無檄至，郵筒絡繹有詩來。", "分朋盡屏牛僧孺，取女親逢羊角哀。", "滿眼鶑花良不惡，春風吹上越王臺。"]'),
('11bd1a9b-cf12-4c86-a4d6-455bd95f614f','柬倪梅村','胡仲弓','宋','宋诗','song-poetry','','[]','蕭寺相逢喜溢眉，未言心事我先知。',64,'全唐诗/poet.song.220000.json','["蕭寺相逢喜溢眉，未言心事我先知。", "半生風月樽中酒，十載江湖社裏詩。", "滿眼秋容關客况，背時春色到南枝。", "翻思舊日長安市，醉拍欄干歌楚辭。"]'),
('a82b6d78-bee4-4cfd-9ff5-73155ae20762','用後村韻送陳先輩','胡仲弓','宋','宋诗','song-poetry','','[]','休將心事問西鄰，原憲長貧豈是貧。',64,'全唐诗/poet.song.220000.json','["休將心事問西鄰，原憲長貧豈是貧。", "黄葉落邊迷去路，白雲飛處倍思親。", "世間那得埋金者，原上空慙負土人。", "苦語只堪吾與汝，倚廬抱恨此情均。"]'),
('33a97c0a-c3f7-433c-be1a-d9c74798956e','南地','胡仲弓','宋','宋诗','song-poetry','','[]','數點青來海上山，山根斷處水漫漫。',64,'全唐诗/poet.song.220000.json','["數點青來海上山，山根斷處水漫漫。", "爲無南雪地偏暖，纔有北風天便寒。", "生理盡歸蠻賈去，宦遊直作瘴鄉看。", "塵迷鉅野家何在，縱有雲梯見亦難。"]'),
('a35a7e55-99c9-4b93-9b47-f7d7e88806ec','回文體二首  其一','胡仲弓','宋','宋诗','song-poetry','','[]','紅花濯錦織前山，日暖啼鶑春晝閒。',64,'全唐诗/poet.song.220000.json','["紅花濯錦織前山，日暖啼鶑春晝閒。", "空院古廊風寂寂，僻居幽谷水潺潺。", "宮移舊曲新翻譜，酒暈濃愁淺带顔。", "同調賦詩吟思苦，匆匆急遞走囊慳。"]'),
('3a0d2a22-0720-4c3e-a461-7f9e4677f382','回文體二首  其二','胡仲弓','宋','宋诗','song-poetry','','[]','灣前過渡小舟虛，好景粧成天畫圖。',64,'全唐诗/poet.song.220000.json','["灣前過渡小舟虛，好景粧成天畫圖。", "山列翠屏開戶牖，麥翻黄浪滾田圩。", "閒鷗樂處晴波細，暮鳥歸邊殘日晡。", "攀柳共人人恨別，綿綿落絮有情無。"]'),
('22cc22d9-6c9b-4385-b2a4-522f920d66d9','存方寸地','胡仲弓','宋','宋诗','song-poetry','','[]','此心僅方寸，去天唯咫尺。',24,'全唐诗/poet.song.220000.json','["此心僅方寸，去天唯咫尺。", "欲付子孫耕，先自竭吾力。"]'),
('c8ee11c8-eee0-404e-96a1-98381440b0dc','失題  其一','胡仲弓','宋','宋诗','song-poetry','','[]','成蹊雖無言，嫵媚隨東風。',24,'全唐诗/poet.song.220000.json','["成蹊雖無言，嫵媚隨東風。", "挺挺冰雪姿，所稟自不同。"]'),
('8d1477b9-fa39-4644-90e8-823604701d23','失題  其二','胡仲弓','宋','宋诗','song-poetry','','[]','篇篇剔蠹魚，字字編科斗。',24,'全唐诗/poet.song.220000.json','["篇篇剔蠹魚，字字編科斗。", "螢小無晶光，明月入我牖。"]'),
('68f4cba1-8ae1-49ef-ba8b-e6a4aee1ee37','光風霽月','胡仲弓','宋','宋诗','song-poetry','','[]','胸懷自灑落，風月特寓形。',24,'全唐诗/poet.song.220000.json','["胸懷自灑落，風月特寓形。", "造物無盡藏，何假乎丹青。"]'),
('7ca3cab4-4b23-4af5-9cff-a15c8c54d616','一志','胡仲弓','宋','宋诗','song-poetry','','[]','念頭纔起處，此一常分明。',24,'全唐诗/poet.song.220000.json','["念頭纔起處，此一常分明。", "其中有主帥，談笑驅五兵。"]'),
('5f5e1f36-7faa-4b56-bda8-e27938b309d2','汲清','胡仲弓','宋','宋诗','song-poetry','','[]','慾波如濁流，心源如古井。',24,'全唐诗/poet.song.220000.json','["慾波如濁流，心源如古井。", "不患無清泉，祇惡無修綆。"]');
